  'builtin__iter_funcs.py':
      "# === sum() ===\n# Basic sum operations\nassert sum([1, 2, 3]) == 6, 'sum of list'\nassert sum([1, 2, 3], 10) == 16, 'sum with start value'\nassert sum(()) == 0, 'sum of empty tuple'\nassert sum([], 5) == 5, 'sum of empty list with start'\nassert sum(range(5)) == 10, 'sum of range'\nassert sum([1.5, 2.5, 3.0], 0.0) == 7.0, 'sum of floats with float start'\n# Note: sum of floats without start requires py_add to support int+float\n\n# sum with different iterables\nassert sum({1, 2, 3}) == 6, 'sum of set'\nassert sum({1: 'a', 2: 'b', 3: 'c'}) == 6, 'sum of dict keys'\n\n# === any() ===\n# Basic any operations\nassert any([True, False, False]) == True, 'any with one True'\nassert any([False, False, False]) == False, 'any with all False'\nassert any([]) == False, 'any of empty list'\nassert any([0, 0, 1]) == True, 'any with truthy int'\nassert any([0, '', None]) == False, 'any with all falsy'\nassert any(['', 'hello']) == True, 'any with non-empty string'\nassert any(range(0, 5)) == True, 'any of range (has non-zero)'\nassert any(range(0, 1)) == False, 'any of range(0,1) is False (only 0)'\n\n# === all() ===\n# Basic all operations\nassert all([True, True, True]) == True, 'all with all True'\nassert all([True, False, True]) == False, 'all with one False'\nassert all([]) == True, 'all of empty list'\nassert all([1, 2, 3]) == True, 'all with truthy ints'\nassert all([1, 0, 3]) == False, 'all with zero'\nassert all(['a', 'b', 'c']) == True, 'all with non-empty strings'\nassert all(['a', '', 'c']) == False, 'all with empty string'\n\n# More edge cases with nested structures\nassert any([[1], [], [3]]) == True, 'any with nested lists (some non-empty)'\nassert all([[1], [2], [3]]) == True, 'all with non-empty nested lists'\n\n# sum with lists (list + list is supported)\nassert sum([[1], [2], [3]], []) == [1, 2, 3], 'sum lists with empty start'\n# Note: sum with tuples requires Tuple py_add which is not implemented\n",
  'builtin__iter_next.py':
      "# === iter() on various iterables ===\n# iter() creates an iterator from an iterable\n\n# iter() on list\nit = iter([1, 2, 3])\nassert next(it) == 1, 'iter list: first element should be 1'\nassert next(it) == 2, 'iter list: second element should be 2'\nassert next(it) == 3, 'iter list: third element should be 3'\n\n# iter() on tuple\nit = iter((10, 20))\nassert next(it) == 10, 'iter tuple: first element should be 10'\nassert next(it) == 20, 'iter tuple: second element should be 20'\n\n# iter() on string\nit = iter('ab')\nassert next(it) == 'a', 'iter string: first element should be a'\nassert next(it) == 'b', 'iter string: second element should be b'\n\n# iter() on range\nit = iter(range(3))\nassert next(it) == 0, 'iter range: first element should be 0'\nassert next(it) == 1, 'iter range: second element should be 1'\nassert next(it) == 2, 'iter range: third element should be 2'\n\n# iter() on dict iterates over keys\nd = {'x': 1, 'y': 2}\nit = iter(d)\nkeys = [next(it), next(it)]\nassert 'x' in keys, 'iter dict: x should be in keys'\nassert 'y' in keys, 'iter dict: y should be in keys'\n\n# === next() with default value ===\n# next() returns default when iterator is exhausted\n\nit = iter([42])\nassert next(it) == 42, 'next: first element should be 42'\nassert next(it, 'done') == 'done', 'next with default: should return default when exhausted'\n\n# Check default with various types\nit = iter([])\nassert next(it, None) is None, 'next with None default: should return None'\nassert next(it, 0) == 0, 'next with 0 default: should return 0'\nassert next(it, []) == [], 'next with empty list default: should return empty list'\n\n# === iter() on iterator returns itself ===\n# Calling iter() on an iterator should return the same iterator\n\noriginal = iter([1, 2, 3])\nsame = iter(original)\n# They should iterate over the same values\nassert next(original) == 1, 'iter on iterator: original first should be 1'\nassert next(same) == 2, 'iter on iterator: same should continue from 2'\nassert next(original) == 3, 'iter on iterator: original should continue to 3'\n\n# === Multiple independent iterators ===\n# Creating multiple iterators over the same iterable should be independent\n\ndata = [1, 2, 3]\nit1 = iter(data)\nit2 = iter(data)\nassert next(it1) == 1, 'independent iterators: it1 first should be 1'\nassert next(it1) == 2, 'independent iterators: it1 second should be 2'\nassert next(it2) == 1, 'independent iterators: it2 first should be 1 (independent)'\nassert next(it1) == 3, 'independent iterators: it1 third should be 3'\nassert next(it2) == 2, 'independent iterators: it2 second should be 2'\n",
  'builtin__map.py':
      "assert list(map(abs, [-1, 0, 1, -2])) == [1, 0, 1, 2], 'map with abs'\nassert list(map(abs, [0, 0, 0])) == [0, 0, 0], 'map with abs all zeros'\n\nassert list(map(str, [1, 2, 3])) == ['1', '2', '3'], 'map with str on ints'\nassert list(map(str, [True, False])) == ['True', 'False'], 'map with str on bools'\n\nassert list(map(int, ['1', '2', '3'])) == [1, 2, 3], 'map with int on strings'\nassert list(map(int, [1.1, 2.9, 3.5])) == [1, 2, 3], 'map with int on floats'\nassert list(map(int, [True, False, True])) == [1, 0, 1], 'map with int on bools'\n\nassert list(map(bool, [0, 1, '', 'x'])) == [False, True, False, True], 'map with bool'\nassert list(map(bool, [[], [1], (), (2,)])) == [False, True, False, True], 'map with bool on containers'\n\nassert list(map(len, ['', 'a', 'ab', 'abc'])) == [0, 1, 2, 3], 'map with len on strings'\nassert list(map(len, [[], [1], [1, 2], [1, 2, 3]])) == [0, 1, 2, 3], 'map with len on lists'\n\nassert list(map(float, [1, 2, 3])) == [1.0, 2.0, 3.0], 'map with float on ints'\nassert list(map(float, ['1.5', '2.5'])) == [1.5, 2.5], 'map with float on strings'\n\nassert list(map(abs, [1, -2, 3])) == [1, 2, 3], 'map on list'\n\nassert list(map(abs, (1, -2, 3))) == [1, 2, 3], 'map on tuple'\n\nassert list(map(ord, 'abc')) == [97, 98, 99], 'map ord on string'\n\nassert list(map(abs, range(-3, 3))) == [3, 2, 1, 0, 1, 2], 'map on range'\n\nresult = list(map(abs, {-1, 0, 1}))\nassert sorted(result) == [0, 1, 1], 'map on set'\n\nassert list(map(abs, [])) == [], 'map on empty list'\nassert list(map(abs, ())) == [], 'map on empty tuple'\nassert list(map(abs, '')) == [], 'map on empty string'\nassert list(map(abs, range(0))) == [], 'map on empty range'\n\nassert list(map(list, [(1, 2), (3, 4)])) == [[1, 2], [3, 4]], 'map with list constructor'\nassert list(map(tuple, [[1, 2], [3, 4]])) == [(1, 2), (3, 4)], 'map with tuple constructor'\n\nassert list(map(pow, [2, 3, 4], [3, 2, 2])) == [8, 9, 16], 'map with pow and 2 iterables'\n\nassert list(map(divmod, [10, 20, 30], [3, 6, 7])) == [(3, 1), (3, 2), (4, 2)], 'map with divmod and 2 iterables'\n\nassert list(map(pow, [2, 3, 4, 5], [3, 2])) == [8, 9], 'map stops at shortest iterable'\nassert list(map(pow, [2, 3], [3, 2, 1, 0])) == [8, 9], 'map stops at shortest iterable (first shorter)'\n\nassert list(map(pow, [2], [3, 4, 5])) == [8], 'map with single item in shortest'\n\n\ndef f(x):\n    return x * 2\n\n\nassert list(map(f, [1, 2, 3])) == [2, 4, 6], 'map with custom function'\n\n\ndef raise_exception(x):\n    raise ValueError('Intentional error')\n\n\ntry:\n    list(map(raise_exception, [1, 2, 3]))\n    assert False, 'should have failed with exception'\nexcept ValueError as e:\n    assert str(e) == 'Intentional error', 'map with function that raises exception'\n\ntry:\n    map()\nexcept TypeError as e:\n    assert str(e) == 'map() must have at least two arguments.', 'map with no arguments'\n\ntry:\n    map(None)\nexcept TypeError as e:\n    assert str(e) == 'map() must have at least two arguments.', 'map with only function argument'\n",
