  'chain_comparison__all.py':
      "# === Basic chain comparisons ===\nassert (1 < 2 < 3) == True, 'ascending chain'\nassert (1 < 3 < 2) == False, 'fails at second comparison'\nassert (3 < 2 < 1) == False, 'fails at first comparison'\nassert (1 <= 2 <= 2) == True, 'with equality'\nassert 1 <= 2 <= 2, 'with equality'\nassert 1 <= 2 <= 2 <= 3, 'chained with equality'\n\n# === Mixed operators ===\nassert (1 < 2 <= 2 < 3) == True, 'mixed lt and le'\nassert (1 == 1 == 1) == True, 'triple equality'\nassert (1 != 2 != 1) == True, 'not-equal chain (not transitive)'\n\n# === Longer chains ===\nassert (1 < 2 < 3 < 4 < 5) == True, '5-way ascending'\nassert (1 < 2 < 3 < 2 < 5) == False, 'fails in middle'\n\n# === With variables and expressions ===\nx = 5\nassert (1 < x < 10) == True, 'variable in chain'\nassert (0 < x - 3 < x < x + 1) == True, 'expressions'\n\n\n# === Short-circuit evaluation ===\ndef test_short_circuit():\n    calls = []\n\n    def a():\n        calls.append('a')\n        return 1\n\n    def b():\n        calls.append('b')\n        return 0  # This will make first comparison fail\n\n    def c():\n        calls.append('c')\n        return 2\n\n    # Test: first comparison fails, c() should not be called\n    result = a() < b() < c()  # 1 < 0 is False, c() should not be called\n    assert result == False, 'short circuit result'\n    assert calls == ['a', 'b'], 'c not called due to short circuit'\n\n\ntest_short_circuit()\n\n\n# === Single evaluation of intermediate values ===\ndef test_single_eval():\n    count = 0\n\n    def middle():\n        nonlocal count\n        count += 1\n        return 5\n\n    result = 1 < middle() < 10\n    assert result == True, 'chain result'\n    assert count == 1, 'middle() called exactly once'\n\n\ntest_single_eval()\n\n# === Identity comparisons ===\na = [1]\nb = a\nc = a\nassert (a is b is c) == True, 'is chain same object'\n\n# === Containment checks ===\nassert (1 in [1, 2] in [[1, 2], [3]]) == True, 'in chain'\n\n\n# === Verify no namespace pollution ===\n# Note: The old implementation used _chain_cmp_N variables which would leak.\n# The new stack-based implementation doesn't create any intermediate variables.\n# We can't easily test for namespace pollution without dir(), so we just verify\n# that chain comparisons work correctly (covered by tests above).\n",
  'closure__param_shadows_outer.py':
      "# === Parameter shadows outer local (basic) ===\ndef outer_basic():\n    x = 42\n\n    def inner(x):\n        return x + 1\n\n    return inner(10)\n\n\nassert outer_basic() == 11, 'inner param should shadow outer local'\n\n\n# === Parameter shadows outer local (multiple params) ===\ndef outer_multi():\n    a = 100\n    b = 200\n\n    def inner(a, b):\n        return a + b\n\n    return inner(1, 2)\n\n\nassert outer_multi() == 3, 'both params should shadow outer locals'\n\n\n# === Mixed: one param shadows, one captures ===\ndef outer_mixed():\n    x = 10\n    y = 20\n\n    def inner(x):\n        return x + y\n\n    return inner(5)\n\n\nassert outer_mixed() == 25, 'x should be param (5), y should be captured (20)'\n\n\n# === Parameter shadows with default value ===\ndef outer_default():\n    x = 99\n\n    def inner(x=7):\n        return x\n\n    return inner()\n\n\nassert outer_default() == 7, 'default param should shadow outer local'\n\n\n# === Deeply nested: param shadows grandparent local ===\ndef outer_deep():\n    x = 1000\n\n    def middle():\n        def inner(x):\n            return x * 2\n\n        return inner(3)\n\n    return middle()\n\n\nassert outer_deep() == 6, 'inner param should shadow grandparent local'\n\n\n# === Parameter used in complex expression ===\ndef outer_expr():\n    scale = 100\n\n    def inner(n, scale):\n        return n * scale + 1\n\n    return inner(5, 10)\n\n\nassert outer_expr() == 51, 'scale param should shadow outer scale'\n",
  'closure__pep448.py':
      "# Tests for PEP 448 unpacking inside closures.\n# These exercise the collect_*_from_expr helpers in prepare.rs which walk\n# expressions to find walrus-operator assignments, cell variables, and\n# referenced names in nested functions. Closures that reference variables\n# used in PEP 448 positions (dict unpack, list/tuple/set literal, call args)\n# are the only way to reach these code paths.\n\n# === Closure capturing variable used in dict unpack ===\ndef outer_dict():\n    d1 = {'a': 1, 'b': 2}\n    d2 = {'c': 3}\n\n    def inner():\n        return {**d1, **d2}\n\n    return inner()\n\n\nassert outer_dict() == {'a': 1, 'b': 2, 'c': 3}, 'closure: dict unpack'\n\n\n# === Closure capturing variable used in list unpack ===\ndef outer_list():\n    items = [1, 2, 3]\n    extra = [4, 5]\n\n    def inner():\n        return [*items, *extra]\n\n    return inner()\n\n\nassert outer_list() == [1, 2, 3, 4, 5], 'closure: list unpack'\n\n\n# === Closure capturing variable used in tuple unpack ===\ndef outer_tuple():\n    a = (1, 2)\n    b = (3, 4)\n\n    def inner():\n        return (*a, *b)\n\n    return inner()\n\n\nassert outer_tuple() == (1, 2, 3, 4), 'closure: tuple unpack'\n\n\n# === Closure capturing variable used in set unpack ===\ndef outer_set():\n    items = [1, 2, 3]\n\n    def inner():\n        return {*items}\n\n    return inner()\n\n\nassert outer_set() == {1, 2, 3}, 'closure: set unpack'\n\n\n# === Closure using PEP 448 in a function call (single * and **) ===\ndef outer_call_star():\n    def f(*args, **kwargs):\n        return (args, kwargs)\n\n    args = [1, 2, 3]\n    kw = {'x': 10}\n\n    def inner():\n        return f(*args, **kw)\n\n    return inner()\n\n\nassert outer_call_star() == ((1, 2, 3), {'x': 10}), 'closure: call *args **kw'\n\n\n# === Closure using multiple * and ** in a call ===\ndef outer_multi():\n    def f(*args, **kwargs):\n        return (args, kwargs)\n\n    a = [1, 2]\n    b = [3, 4]\n    kw1 = {'x': 10}\n    kw2 = {'y': 20}\n\n    def inner():\n        return f(*a, *b, **kw1, **kw2)\n\n    return inner()\n\n\nassert outer_multi() == ((1, 2, 3, 4), {'x': 10, 'y': 20}), 'closure: multi-star call'\n\n\n# === Closure calling with keyword-only args (ArgExprs::Kwargs) ===\n# The outer-function assignment `_precomp = f(a=val_a, b=val_b)` exercises\n# collect_assigned_names_from_args for the Kwargs arm.  The inner body exercises\n# collect_cell_vars_from_args and collect_referenced_names_from_args for Kwargs.\ndef outer_kwargs_call():\n    def f(**kwargs):\n        return kwargs\n\n    val_a = 10\n    val_b = 20\n    # Assignment RHS is a Kwargs call → triggers collect_assigned_names_from_args Kwargs arm\n    _precomp = f(a=val_a, b=val_b)\n\n    def inner():\n        # Kwargs call in inner body → collect_cell/referenced_names Kwargs arm\n        return f(a=val_a, b=val_b)\n\n    return inner()\n\n\nassert outer_kwargs_call() == {'a': 10, 'b': 20}, 'closure: keyword-only call'\n\n\n# === Closure calling with positional + *star (ArgsKargs with args=Some) ===\n# Exercises ArgsKargs branch where the positional-args field is non-None.\ndef outer_argsstar():\n    def f(*args):\n        return list(args)\n\n    pos_val = 1\n    items = [2, 3]\n    # Assignment RHS has positional arg + star → ArgsKargs with args=Some([pos_val])\n    _precomp = f(pos_val, *items)\n\n    def inner():\n        return f(pos_val, *items)\n\n    return inner()\n\n\nassert outer_argsstar() == [1, 2, 3], 'closure: positional + *args'\n\n\n# === Closure calling with named kwarg + **kw (ArgsKargs with kwargs=Some) ===\n# Exercises ArgsKargs branch where the named-kwargs field is non-None.\ndef outer_kwargsstar():\n    def f(**kwargs):\n        return kwargs\n\n    val = 1\n    extra = {'b': 2}\n    # Assignment RHS has named kwarg + double-star → ArgsKargs with kwargs=Some\n    _precomp = f(a=val, **extra)\n\n    def inner():\n        return f(a=val, **extra)\n\n    return inner()\n\n\nassert outer_kwargsstar() == {'a': 1, 'b': 2}, 'closure: named kwarg + **kw'\n\n\n# === Closure with GeneralizedCall and Named kwarg ===\n# Exercises the CallKwarg::Named arm in all three collect_*_names_from_args functions.\ndef outer_generalized_named():\n    def f(*args, **kwargs):\n        return (args, kwargs)\n\n    a = [1, 2]\n    b = [3]\n    key_val = 99\n    # Assignment RHS has GeneralizedCall with Named kwarg → collect_assigned_names Named arm\n    _precomp = f(*a, *b, key=key_val)\n\n    def inner():\n        # Named kwarg in GeneralizedCall → collect_cell/referenced_names Named arm\n        return f(*a, *b, key=key_val)\n\n    return inner()\n\n\nassert outer_generalized_named() == ((1, 2, 3), {'key': 99}), 'closure: generalized call with named kwarg'\n\n\n# === Closure with GeneralizedCall and plain Value arg ===\n# Exercises the CallArg::Value path of the GeneralizedCall args loop,\n# covering the Value branch of the `CallArg::Value | CallArg::Unpack` OR-pattern.\ndef outer_generalized_mixed():\n    def f(*args):\n        return list(args)\n\n    const = 0\n    items1 = [1, 2]\n    items2 = [3, 4]\n    # GeneralizedCall with Value(const) + Unpack(items1) + Unpack(items2)\n    _precomp = f(const, *items1, *items2)\n\n    def inner():\n        return f(const, *items1, *items2)\n\n    return inner()\n\n\nassert outer_generalized_mixed() == [0, 1, 2, 3, 4], 'closure: generalized call with value + unpack args'\n",
