  'compare__mixed_types.py':
      "# === Bool == Int equality ===\nassert True == 1, 'True == 1'\nassert False == 0, 'False == 0'\nassert 1 == True, '1 == True'\nassert 0 == False, '0 == False'\nassert True != 2, 'True != 2'\nassert False != 1, 'False != 1'\n\n# === Bool == Float equality ===\nassert True == 1.0, 'True == 1.0'\nassert False == 0.0, 'False == 0.0'\nassert 1.0 == True, '1.0 == True'\nassert 0.0 == False, '0.0 == False'\nassert True != 2.0, 'True != 2.0'\nassert 0.5 != False, '0.5 != False'\n\n# === Int == Float equality ===\nassert 5 == 5.0, '5 == 5.0'\nassert 5.0 == 5, '5.0 == 5'\nassert 5 != 5.5, '5 != 5.5'\nassert 0 == 0.0, '0 == 0.0'\nassert -3 == -3.0, '-3 == -3.0'\n\n# === Int/Float ordering ===\nassert 5 < 5.5, '5 < 5.5'\nassert 5.5 > 5, '5.5 > 5'\nassert 5 <= 5.0, '5 <= 5.0'\nassert 5.0 >= 5, '5.0 >= 5'\nassert 5 > 4.9, '5 > 4.9'\nassert 4.9 < 5, '4.9 < 5'\n\n# === Bool ordering (promotes to int) ===\nassert True > False, 'True > False'\nassert False < True, 'False < True'\nassert True >= 1, 'True >= 1'\nassert False <= 0, 'False <= 0'\nassert True > 0, 'True > 0'\nassert True < 2, 'True < 2'\nassert True > 0.5, 'True > 0.5'\nassert True < 1.5, 'True < 1.5'\nassert False < 0.5, 'False < 0.5'\nassert False >= -1, 'False >= -1'\n\n# === Cross-type non-equality ===\nassert 'hello' != 42, 'str != int'\nassert 42 != 'hello', 'int != str'\nassert b'hello' != 'hello', 'bytes != str'\nassert 'hello' != b'hello', 'str != bytes'\nassert None != 0, 'None != 0'\nassert 0 != None, '0 != None'\nassert [] != 'list', 'list != str'\nassert {} != 0, 'dict != int'\n\n# === LongInt cross-type comparisons ===\nbig = 2**100\nbig2 = 2**100\nassert big == big2, 'LongInt == LongInt'\nassert big != 5, 'LongInt != int'\nassert big > 5, 'LongInt > int'\nassert 5 < big, 'int < LongInt'\nassert big >= 5, 'LongInt >= int'\nassert 5 <= big, 'int <= LongInt'\nsmall_big = 2**100\nlarge_big = 2**101\nassert small_big < large_big, 'LongInt < LongInt'\nassert large_big > small_big, 'LongInt > LongInt'\nassert big != 'hello', 'LongInt != str'\n\n# === Bytes ordering ===\nassert b'abc' < b'abd', 'bytes lt'\nassert b'abc' <= b'abc', 'bytes le'\nassert b'abd' > b'abc', 'bytes gt'\nassert b'abc' >= b'abc', 'bytes ge'\nassert b'a' < b'b', 'single byte lt'\nassert b'' < b'a', 'empty bytes lt non-empty'\n\n# === String ordering ===\nassert 'abc' < 'abd', 'str lt'\nassert 'abc' <= 'abc', 'str le'\nassert 'abd' > 'abc', 'str gt'\nassert 'abc' >= 'abc', 'str ge'\nassert 'a' < 'b', 'single char lt'\n\n# === Heap-allocated string ordering (from split) ===\nparts = 'banana,apple'.split(',')\nassert parts[1] < parts[0], 'heap str lt'\nassert parts[0] > parts[1], 'heap str gt'\nassert parts[0] >= parts[0], 'heap str ge self'\nassert parts[0] <= parts[0], 'heap str le self'\n\n# === Cross-type string ordering (interned vs heap) ===\nheap_str = 'banana,apple'.split(',')[0]\nassert heap_str > 'apple', 'heap str gt interned'\nassert 'cherry' > heap_str, 'interned gt heap str'\nassert heap_str >= 'banana', 'heap str ge interned eq'\nassert 'banana' <= heap_str, 'interned le heap str eq'\n\n# === Containment: not in list ===\nassert 999 not in [1, 2, 3], 'not in list'\nassert 0 not in [1, 2, 3], 'zero not in list'\n\n# === Containment: not in tuple ===\nassert 'z' not in ('a', 'b', 'c'), 'not in tuple'\nassert 0 not in (1, 2, 3), 'zero not in tuple'\n\n# === Containment: in/not in set ===\nassert 2 in {1, 2, 3}, 'in set'\nassert 99 not in {1, 2, 3}, 'not in set'\n\n# === Containment: in/not in frozenset ===\nassert 2 in frozenset({1, 2, 3}), 'in frozenset'\nassert 99 not in frozenset({1, 2, 3}), 'not in frozenset'\n\n# === Containment: in/not in list (found) ===\nassert 2 in [1, 2, 3], 'in list'\nassert 'b' in ['a', 'b', 'c'], 'str in list'\n\n# === Containment: in/not in tuple (found) ===\nassert 'b' in ('a', 'b', 'c'), 'str in tuple'\nassert 2 in (1, 2, 3), 'int in tuple'\n",
  'comprehension__all.py':
      "# === Basic list comprehension ===\nassert [x for x in [1, 2, 3]] == [1, 2, 3], 'identity'\nassert [x * 2 for x in [1, 2, 3]] == [2, 4, 6], 'transform'\nassert [x + 1 for x in range(5)] == [1, 2, 3, 4, 5], 'range'\n\n# === With filter ===\nassert [x for x in [1, 2, 3, 4] if x > 2] == [3, 4], 'filter'\nassert [x for x in [1, 2, 3, 4, 5] if x % 2 == 0] == [2, 4], 'even filter'\nassert [x for x in range(20) if x % 2 == 0 if x % 3 == 0] == [0, 6, 12, 18], 'multi-filter'\nassert [x * 2 for x in [1, 2, 3, 4] if x > 1 if x < 4] == [4, 6], 'transform with multi-filter'\n\n# === Nested for ===\nassert [x + y for x in [1, 2] for y in [10, 20]] == [11, 21, 12, 22], 'nested'\nassert [(x, y) for x in [1, 2] for y in ['a', 'b']] == [(1, 'a'), (1, 'b'), (2, 'a'), (2, 'b')], 'nested tuple'\nassert [x * y for x in [1, 2, 3] for y in [10, 100]] == [10, 100, 20, 200, 30, 300], 'nested multiply'\n\n# === Nested with filter ===\nassert [x + y for x in [1, 2, 3] if x > 1 for y in [10, 20] if y > 10] == [22, 23], 'nested with filters'\n\n# === Set comprehension ===\nassert {x for x in [1, 2, 2, 3]} == {1, 2, 3}, 'set dedup'\nassert {x for x in [1, 2, 3] if x > 1} == {2, 3}, 'set filter'\nassert {x * 2 for x in [1, 2, 3]} == {2, 4, 6}, 'set transform'\nassert {x % 3 for x in range(10)} == {0, 1, 2}, 'set modulo'\n\n# === Dict comprehension ===\nassert {x: x * 2 for x in [1, 2, 3]} == {1: 2, 2: 4, 3: 6}, 'dict'\nassert {x: x for x in [1, 2, 3] if x > 1} == {2: 2, 3: 3}, 'dict filter'\nassert {str(x): x for x in [1, 2, 3]} == {'1': 1, '2': 2, '3': 3}, 'dict str keys'\nassert {x: y for x in [1, 2] for y in [10, 20]} == {1: 20, 2: 20}, 'dict nested overwrites'\n\n# === Scope isolation ===\nx = 'outer'\nresult = [x for x in [1, 2, 3]]\nassert x == 'outer', 'loop var does not leak'\n\ny = 'before'\nresult2 = [y * 2 for y in [1, 2]]\nassert y == 'before', 'loop var y does not leak'\n\n# === Access enclosing scope ===\nmultiplier = 10\nassert [x * multiplier for x in [1, 2]] == [10, 20], 'closure'\n\nprefix = 'item_'\nassert [prefix + str(x) for x in [1, 2, 3]] == ['item_1', 'item_2', 'item_3'], 'closure string'\n\nbase = [1, 2, 3]\nassert [x + 10 for x in base] == [11, 12, 13], 'closure list'\n\n\n# === Capture when iter uses same name as target ===\ndef outer_capture_same_name():\n    x = [1, 2, 3]\n\n    def inner():\n        return [x for x in x]\n\n    return inner()\n\n\nassert outer_capture_same_name() == [1, 2, 3], 'iter uses outer x'\n\n# === Empty iterables ===\nassert [x for x in []] == [], 'empty list'\nassert {x for x in []} == set(), 'empty set'\nassert {x: x for x in []} == {}, 'empty dict'\n\n# === Filter removes all ===\nassert [x for x in [1, 2, 3] if x > 10] == [], 'filter all'\nassert {x for x in [1, 2, 3] if x > 10} == set(), 'set filter all'\nassert {x: x for x in [1, 2, 3] if x > 10} == {}, 'dict filter all'\n\n# === Complex expressions ===\nassert [x**2 for x in [1, 2, 3, 4]] == [1, 4, 9, 16], 'square'\nassert [len(s) for s in ['a', 'bb', 'ccc']] == [1, 2, 3], 'len'\nassert [[y for y in range(x)] for x in [1, 2, 3]] == [[0], [0, 1], [0, 1, 2]], 'nested comprehension'\n\n# === Nested generator referencing prior loop var ===\n# Second generator's iter references first generator's loop variable\nassert [y for x in [[1, 2], [3, 4]] for y in x] == [1, 2, 3, 4], 'flatten nested lists'\nassert [(x, y) for x in [1, 2] for y in range(x)] == [(1, 0), (2, 0), (2, 1)], 'second iter uses first var'\n\n\ndef outer_nested_comp():\n    xs = [[1, 2], [3, 4]]\n\n    def inner():\n        return [y for x in xs for y in x]\n\n    return inner()\n\n\nassert outer_nested_comp() == [1, 2, 3, 4], 'nested comp in closure'\n\n# === Tuple unpacking in comprehensions ===\npairs = [(1, 'a'), (2, 'b'), (3, 'c')]\nassert [x for x, y in pairs] == [1, 2, 3], 'unpack first element'\nassert [y for x, y in pairs] == ['a', 'b', 'c'], 'unpack second element'\nassert [str(x) + str(y) for x, y in [(1, 2), (3, 4)]] == ['12', '34'], 'unpack and use both'\nassert [(y, x) for x, y in pairs] == [('a', 1), ('b', 2), ('c', 3)], 'swap unpacked elements'\n\n# Tuple unpacking with filter\nassert [x for x, y in pairs if x > 1] == [2, 3], 'unpack with filter'\nassert [y for x, y in pairs if y != 'b'] == ['a', 'c'], 'unpack filter on second'\n\n# Triple unpacking\ntriples = [(1, 2, 3), (4, 5, 6)]\nassert [a + b + c for a, b, c in triples] == [6, 15], 'triple unpack sum'\nassert [b for a, b, c in triples] == [2, 5], 'triple unpack middle'\n\n# Dict comprehension with unpacking\nd = {k: v for k, v in pairs}\nassert d == {1: 'a', 2: 'b', 3: 'c'}, 'dict comp with unpack'\nassert {v: k for k, v in pairs} == {'a': 1, 'b': 2, 'c': 3}, 'dict comp swap key/value'\n\n# Set comprehension with unpacking\nassert {x for x, y in pairs} == {1, 2, 3}, 'set comp unpack first'\nassert {y for x, y in pairs} == {'a', 'b', 'c'}, 'set comp unpack second'\n\n# Unpacking with dict.items()\nd2 = {'x': 10, 'y': 20, 'z': 30}\nassert [k for k, v in d2.items()] == ['x', 'y', 'z'], 'unpack dict items keys'\nassert [v for k, v in d2.items()] == [10, 20, 30], 'unpack dict items values'\nassert {v: k for k, v in d2.items()} == {10: 'x', 20: 'y', 30: 'z'}, 'dict comp invert dict'\n\n# Nested comprehension with unpacking\nmatrix = [[(1, 2), (3, 4)], [(5, 6), (7, 8)]]\nassert [[a + b for a, b in row] for row in matrix] == [[3, 7], [11, 15]], 'nested comp unpack'\n\n# Scope isolation with unpacking (vars don't leak)\nx = 'outer_x'\ny = 'outer_y'\nresult = [x + y for x, y in [(1, 2)]]\nassert x == 'outer_x', 'x does not leak from unpack'\nassert y == 'outer_y', 'y does not leak from unpack'\n\n\n# Unpacking in closure\ndef outer_unpack():\n    items = [(1, 2), (3, 4)]\n\n    def inner():\n        return [a * b for a, b in items]\n\n    return inner()\n\n\nassert outer_unpack() == [2, 12], 'unpack in closure'\n\n\n# Capture variable used in unpacking pattern\ndef outer_shadow_unpack():\n    x = 100\n\n    def inner():\n        # x in unpacking shadows the outer x, but we can still reference outer x in expression\n        # Actually, the x in the comprehension shadows outer x, so this tests scope isolation\n        pairs = [(1, 2), (3, 4)]\n        return [x + y for x, y in pairs]\n\n    return inner()\n\n\nassert outer_shadow_unpack() == [3, 7], 'shadow unpack in closure'\n\n# === Generator expressions (temporary: treated as list comprehensions) ===\n# TODO: When proper generators are implemented, these should return generator objects\n# instead of lists. For now, generator expressions are parsed as list comprehensions.\n# See iter__generator_expr.py for tests, and iter__generator_expr_type.py for\n# a type check test (xfail=cpython since CPython has real generators).\n\n# Generator in list() call - works identically in both Monty and CPython\nassert list(x for x in [1, 2, 3]) == [1, 2, 3], 'generator in list()'\nassert tuple(x for x in [1, 2, 3]) == (1, 2, 3), 'generator in tuple()'\n\n# Generator with condition\nassert list(x for x in range(10) if x % 2 == 0) == [0, 2, 4, 6, 8], 'generator with condition'\n\n# Nested generators\nassert list(x + y for x in range(3) for y in range(2)) == [0, 1, 1, 2, 2, 3], 'nested generator'\n\n# Generator in sum()\nassert sum(x for x in range(5)) == 10, 'generator in sum()'\n\n# Generator with unpacking\npairs = [(1, 2), (3, 4)]\nassert list(a + b for a, b in pairs) == [3, 7], 'generator with unpacking'\n\n# list of strings join\nassert ''.join(str(x) for x in range(5)) == '01234', 'list of strings join'\na = '1', '2', '3'\nassert ''.join(a) == '123', 'tuple of strings join'\n\n# === Regression: Iterator panic with try/except inside loop ===\n# Issue: https://github.com/pydantic/monty/issues/177\n# Verifies that exception handling in a comprehension inside a loop doesn't\n# corrupt the outer loop's iterator (causing \"expected Iterator on heap\" panic).\n# A prior loop is needed to potentially trigger incorrect stack depth tracking.\nfor _ in range(1):\n    pass\n\nfor s in ['hello']:\n    try:\n        # Inner comprehension raises exception\n        [int(c) for c in s]\n    except ValueError:\n        pass\n",
  'comprehension__scope.py':
      "[x for x in range(10)]\n\ntry:\n    x\n    assert False, \"Expected NameError for 'x' after comprehension\"\nexcept NameError:\n    pass\n",
  'comprehension__unbound_local.py':
      "# Test that comprehension scoping raises UnboundLocalError when a generator's iter\n# references a later generator's loop variable (which is local but not yet assigned)\n\nz = ['outer']\n\nresult = [x for x in [1] for y in z for z in [[2], [3]]]\n\"\"\"\nTRACEBACK:\nTraceback (most recent call last):\n  File \"comprehension__unbound_local.py\", line 6, in <module>\n    result = [x for x in [1] for y in z for z in [[2], [3]]]\n                                      ~\nUnboundLocalError: cannot access local variable 'z' where it is not associated with a value\n\"\"\"\n",
  'dataclass__basic.py':
      "# call-external\n# === Basic dataclass tests ===\n\n# Get immutable dataclass from external function\npoint = make_point()\n\n# === repr and str ===\nassert repr(point) == 'Point(x=1, y=2)', f'point repr {point=!r}'\nassert str(point) == 'Point(x=1, y=2)', 'point str'\n\n# === Boolean truthiness ===\n# Dataclasses are always truthy (like Python class instances)\nassert bool(point), 'dataclass bool is True'\n\n# === Hash for immutable dataclass ===\n# Immutable (frozen) dataclasses are hashable\nh1 = hash(point)\nassert h1 != 0, 'hash is not zero'\n\n# Hash is consistent - same object hashes to same value\nh2 = hash(point)\nassert h1 == h2, 'hash is consistent'\n\n# Equal frozen dataclasses hash to same value\npoint2 = make_point()\nassert hash(point) == hash(point2), 'equal dataclasses have equal hash'\n\n# Frozen dataclass can be used as dict key\nd = {point: 'first'}\nassert d[point] == 'first', 'frozen dataclass as dict key'\nassert d[point2] == 'first', 'equal frozen dataclass looks up same value'\n\n# Frozen dataclass can be added to set\ns = {point, point2}\nassert len(s) == 1, 'equal frozen dataclasses deduplicated in set'\n\n# Different field values produce different hash\nalice = make_user('Alice')\nbob = make_user('Bob')\nassert hash(alice) != hash(bob), 'different field values have different hash'\n\n# === Mutable dataclass ===\nmut_point = make_mutable_point()\nassert repr(mut_point) == 'MutablePoint(x=1, y=2)', f'mutable point repr {mut_point=!r}'\n\n# === Dataclass with string argument ===\nalice = make_user('Alice')\nassert repr(alice) == \"User(name='Alice', active=True)\", f'user repr with string field {alice=!r}'\n\n# === Dataclass in list (using existing variables) ===\npoints = [point, mut_point, alice]\nassert len(points) == 3, 'dataclass list length'\n\n# === Attribute access (get) ===\n# Access fields on immutable dataclass\nassert point.x == 1, 'point.x is 1'\nassert point.y == 2, 'point.y is 2'\n\n# Access fields on mutable dataclass\nassert mut_point.x == 1, 'mut_point.x is 1'\nassert mut_point.y == 2, 'mut_point.y is 2'\n\n# Access fields on dataclass with string field\nassert alice.name == 'Alice', 'alice.name is Alice'\nassert alice.active == True, 'alice.active is True'\n\n# === Attribute assignment (set) ===\n# Modify mutable dataclass\nmut_point.x = 10\nassert mut_point.x == 10, 'mut_point.x updated to 10'\nmut_point.y = 20\nassert mut_point.y == 20, 'mut_point.y updated to 20'\nassert repr(mut_point) == 'MutablePoint(x=10, y=20)', f'repr after attribute update {mut_point=!r}'\n\n# === set other attributes\nmut_point.z = 30\nassert mut_point.z == 30, 'mut_point.z updated to 30'\nassert repr(mut_point) == 'MutablePoint(x=10, y=20)', 'repr after attribute update'\n\n# === Augmented attribute assignment (+=, -=, etc.) ===\naug_point = make_mutable_point()\naug_point.x += 5\nassert aug_point.x == 6, 'augmented attr assign +='\naug_point.y -= 1\nassert aug_point.y == 1, 'augmented attr assign -='\naug_point.x *= 3\nassert aug_point.x == 18, 'augmented attr assign *='\n\n# === Chained augmented attribute assignment ===\nouter_aug = make_mutable_point()\ninner_aug = make_mutable_point()\nouter_aug.x = inner_aug\nouter_aug.x.y += 100\nassert inner_aug.y == 102, 'chained augmented attr assign'\n\n# === Nested attribute access (chained get) ===\n# Create outer dataclass with inner dataclass as field\nouter = make_mutable_point()\ninner = make_mutable_point()\ninner.x = 100\ninner.y = 200\nouter.x = inner\n\n# Chained attribute get: outer.x.y\nassert outer.x.x == 100, 'outer.x.x is 100'\nassert outer.x.y == 200, 'outer.x.y is 200'\n\n# === Nested attribute assignment (chained set) ===\n# Modify nested field via chained access\nouter.x.x = 999\nassert outer.x.x == 999, 'outer.x.x updated to 999'\nouter.x.y = 888\nassert outer.x.y == 888, 'outer.x.y updated to 888'\n\n# Verify inner was modified (same object)\nassert inner.x == 999, 'inner.x also updated to 999'\nassert inner.y == 888, 'inner.y also updated to 888'\n\n# === Deeper nesting (3 levels) ===\nlevel1 = make_mutable_point()\nlevel2 = make_mutable_point()\nlevel3 = make_mutable_point()\nlevel3.x = 42\nlevel2.x = level3\nlevel1.x = level2\n\n# 3-level chained get\nassert level1.x.x.x == 42, 'level1.x.x.x is 42'\n\n# 3-level chained set\nlevel1.x.x.x = 7\nassert level1.x.x.x == 7, 'level1.x.x.x updated to 7'\nassert level3.x == 7, 'level3.x also updated to 7'\n\n# === Empty dataclass ===\nempty = make_empty()\nassert repr(empty) == 'Empty()', 'empty dataclass repr'\nassert str(empty) == 'Empty()', 'empty dataclass str'\n\n# === FrozenInstanceError is subclass of AttributeError ===\n# Catching AttributeError should also catch FrozenInstanceError\nfrozen_point = make_point()\ncaught = False\ntry:\n    frozen_point.x = 10\nexcept AttributeError:\n    caught = True\nassert caught, 'FrozenInstanceError caught by AttributeError'\n\n# === Error: accessing non-existent attribute ===\ntry:\n    point.nonexistent\n    assert False, 'should have raised AttributeError for missing attr'\nexcept AttributeError as e:\n    assert str(e) == \"'Point' object has no attribute 'nonexistent'\", f'wrong message: {e}'\n\n# === Error: accessing non-existent private attribute ===\ntry:\n    point._private\n    assert False, 'should have raised AttributeError for private attr'\nexcept AttributeError as e:\n    assert str(e) == \"'Point' object has no attribute '_private'\", f'wrong message: {e}'\n\n# === Error: calling a dunder that doesn't exist ===\ntry:\n    point.__nonexistent__()\n    assert False, 'should have raised AttributeError for dunder'\nexcept AttributeError as e:\n    assert str(e) == \"'Point' object has no attribute '__nonexistent__'\", f'wrong message: {e}'\n\n# === Error: calling a private method that doesn't exist ===\ntry:\n    point._private_method()\n    assert False, 'should have raised AttributeError for private method'\nexcept AttributeError as e:\n    assert str(e) == \"'Point' object has no attribute '_private_method'\", f'wrong message: {e}'\n\n# === Error: calling a field value (not callable) ===\ntry:\n    point.x()\n    assert False, 'should have raised TypeError for calling int field'\nexcept TypeError as e:\n    assert str(e) == \"'int' object is not callable\", f'wrong message: {e}'\n\n# === Error: calling a non-existent public method ===\ntry:\n    point.nonexistent_method()\n    assert False, 'should have raised AttributeError for missing method'\nexcept AttributeError as e:\n    assert str(e) == \"'Point' object has no attribute 'nonexistent_method'\", f'wrong message: {e}'\n\n# === Error: same errors on mutable dataclass ===\ntry:\n    mut_point.nonexistent\n    assert False, 'should have raised AttributeError on mutable dc'\nexcept AttributeError as e:\n    assert str(e) == \"'MutablePoint' object has no attribute 'nonexistent'\", f'wrong message: {e}'\n\ntry:\n    mut_point.x()\n    assert False, 'should have raised TypeError on mutable dc field call'\nexcept TypeError as e:\n    assert str(e) == \"'int' object is not callable\", f'wrong message: {e}'\n\n# === Method calls: no args (exercises ArgValues::prepend on Empty) ===\nresult = point.sum()\nassert result == 3, f'Point.sum() should be 3, got {result}'\n\n# === Method calls: two positional args (exercises ArgValues::prepend on Two) ===\nnew_point = point.add(10, 20)\nassert new_point.x == 11, f'Point.add x should be 11, got {new_point.x}'\nassert new_point.y == 22, f'Point.add y should be 22, got {new_point.y}'\n\n# === Method calls: one positional arg (exercises ArgValues::prepend on One) ===\nscaled = point.scale(3)\nassert scaled.x == 3, f'Point.scale x should be 3, got {scaled.x}'\nassert scaled.y == 6, f'Point.scale y should be 6, got {scaled.y}'\n\n# === Method calls: returning a string ===\ndesc = point.describe('pt')\nassert desc == 'pt(1, 2)', f'Point.describe should be pt(1, 2), got {desc}'\n\n# === Method calls on mutable dataclass ===\nmut_p2 = make_mutable_point()\nmut_sum = mut_p2.sum()\nassert mut_sum == 3, f'MutablePoint.sum() should be 3, got {mut_sum}'\n\n# === Method calls on User dataclass (string field) ===\nalice2 = make_user('Alice')\ngreeting = alice2.greeting()\nassert greeting == 'Hello, Alice!', f'User.greeting should be Hello, Alice!, got {greeting}'\n\n# === Method call returning dataclass - chained access ===\np3 = point.add(0, 0)\nassert p3.x == 1, f'chained method access: p3.x should be 1, got {p3.x}'\nassert p3.y == 2, f'chained method access: p3.y should be 2, got {p3.y}'\n\n# === Method calls with keyword-only args (exercises ArgValues::prepend on Kwargs) ===\ndesc_kw = point.describe(label='custom')\nassert desc_kw == 'custom(1, 2)', f'Point.describe(label=) should be custom(1, 2), got {desc_kw}'\n\n# === Error: calling non-existent method on mutable dataclass ===\ntry:\n    mut_p2.nonexistent_method()\n    assert False, 'should have raised AttributeError for missing method on mutable dc'\nexcept AttributeError as e:\n    assert str(e) == \"'MutablePoint' object has no attribute 'nonexistent_method'\", f'wrong message: {e}'\n\n# === Error: calling non-existent method on User ===\ntry:\n    alice2.missing()\n    assert False, 'should have raised AttributeError for missing method on User'\nexcept AttributeError as e:\n    assert str(e) == \"'User' object has no attribute 'missing'\", f'wrong message: {e}'\n",
