  'dict__methods.py':
      "# === dict.clear() ===\nd = {'a': 1, 'b': 2}\nd.clear()\nassert d == {}, 'clear empties the dict'\n\nd = {}\nd.clear()\nassert d == {}, 'clear on empty dict is no-op'\n\n# === dict.copy() ===\nd = {'a': 1, 'b': 2}\ncopy = d.copy()\nassert copy == {'a': 1, 'b': 2}, 'copy creates equal dict'\nassert copy is not d, 'copy creates new dict object'\nd['c'] = 3\nassert 'c' not in copy, 'copy is independent'\n\nd = {}\ncopy = d.copy()\nassert copy == {}, 'copy empty dict'\n\n# === dict.update() ===\nd = {'a': 1}\nd.update({'b': 2})\nassert d == {'a': 1, 'b': 2}, 'update with dict'\n\nd = {'a': 1}\nd.update({'a': 10})\nassert d == {'a': 10}, 'update overwrites existing key'\n\nd = {'a': 1}\nd.update()\nassert d == {'a': 1}, 'update with no args is no-op'\n\nd = {}\nd.update([('a', 1), ('b', 2)])\nassert d == {'a': 1, 'b': 2}, 'update with list of tuples'\n\n# === dict.setdefault() ===\nd = {'a': 1}\nresult = d.setdefault('a', 10)\nassert result == 1, 'setdefault returns existing value'\nassert d == {'a': 1}, 'setdefault does not overwrite'\n\nd = {'a': 1}\nresult = d.setdefault('b', 2)\nassert result == 2, 'setdefault returns default for new key'\nassert d == {'a': 1, 'b': 2}, 'setdefault inserts new key'\n\nd = {'a': 1}\nresult = d.setdefault('b')\nassert result is None, 'setdefault default is None'\nassert d == {'a': 1, 'b': None}, 'setdefault inserts None'\n\n# === dict.popitem() ===\nd = {'a': 1, 'b': 2}\nitem = d.popitem()\nassert item == ('b', 2), 'popitem returns last inserted item'\nassert d == {'a': 1}, 'popitem removes item'\n\nd = {'x': 10}\nitem = d.popitem()\nassert item == ('x', 10), 'popitem on single-item dict'\nassert d == {}, 'dict is now empty'\n\n# === dict.fromkeys() ===\nd = dict.fromkeys(['a', 'b', 'c'])\nassert d == {'a': None, 'b': None, 'c': None}, 'fromkeys with list, default None'\n\nd = dict.fromkeys(['a', 'b'], 0)\nassert d == {'a': 0, 'b': 0}, 'fromkeys with default value'\n\nd = dict.fromkeys([])\nassert d == {}, 'fromkeys with empty iterable'\n\nd = dict.fromkeys('abc')\nassert d == {'a': None, 'b': None, 'c': None}, 'fromkeys with string iterable'\n\nd = dict.fromkeys(range(3), 'x')\nassert d == {0: 'x', 1: 'x', 2: 'x'}, 'fromkeys with range iterable'\n\nd = dict.fromkeys((1, 2, 3), [])\nassert d[1] is d[2] and d[2] is d[3], 'fromkeys shares same value object for all keys'\n\n# Duplicate keys - later occurrence wins\nd = dict.fromkeys(['a', 'b', 'a'], 1)\nassert d == {'a': 1, 'b': 1}, 'fromkeys with duplicate keys'\nassert list(d.keys()) == ['a', 'b'], 'fromkeys preserves first occurrence order'\n\n# === dict.fromkeys() instance access ===\n# fromkeys is a classmethod but should also work on instances\nd = {}.fromkeys(['a', 'b'])\nassert d == {'a': None, 'b': None}, 'fromkeys on empty dict instance'\n\nd = {'x': 1}.fromkeys(['a', 'b'], 0)\nassert d == {'a': 0, 'b': 0}, 'fromkeys on non-empty dict instance (ignores original)'\n\n# === dict.update() with keyword arguments ===\nd = {'a': 1}\nd.update(b=2)\nassert d == {'a': 1, 'b': 2}, 'update with single kwarg'\n\nd = {'a': 1}\nd.update(b=2, c=3)\nassert d == {'a': 1, 'b': 2, 'c': 3}, 'update with multiple kwargs'\n\nd = {'a': 1}\nd.update(a=10)\nassert d == {'a': 10}, 'update kwarg overwrites existing key'\n\nd = {}\nd.update(a=1, b=2)\nassert d == {'a': 1, 'b': 2}, 'update empty dict with kwargs'\n\n# update with both positional dict and kwargs\nd = {'a': 1}\nd.update({'b': 2}, c=3)\nassert d == {'a': 1, 'b': 2, 'c': 3}, 'update with dict and kwargs'\n\n# kwargs overwrite positional dict values\nd = {'a': 1}\nd.update({'b': 2}, b=20)\nassert d == {'a': 1, 'b': 20}, 'update kwargs overwrite positional dict'\n\n# update with iterable and kwargs\nd = {}\nd.update([('a', 1)], b=2)\nassert d == {'a': 1, 'b': 2}, 'update with iterable and kwargs'\n\n# === Error message for unknown classmethod ===\n# Error message should say 'dict' not 'type'\ntry:\n    dict.nonexistent()\n    assert False, 'should raise AttributeError'\nexcept AttributeError as e:\n    msg = str(e)\n    assert 'dict' in msg, f'error should mention dict, got: {e}'\n    assert 'nonexistent' in msg, f'error should mention method name, got: {e}'\n\n# === dict.update() sequence element error ===\n# Invalid sequence elements should raise ValueError\ntry:\n    d = {}\n    d.update([('a', 1), 'x', ('c', 3)])  # 'x' at index 1 is not a 2-tuple\n    assert False, 'should raise ValueError'\nexcept (ValueError, TypeError) as e:\n    msg = str(e)\n    # Error message should mention 'length' requirement\n    assert 'length' in msg.lower(), f'error should mention length, got: {e}'\n    # TODO: CPython includes element index (#N) in error message\n    # assert '#1' in msg, 'error should mention element index'\n",
  'dict__ops.py':
      "# === Dict literals ===\nassert {} == {}, 'empty literal'\nassert {'a': 1} == {'a': 1}, 'single item literal'\nassert {'a': 1, 'b': 2} == {'a': 1, 'b': 2}, 'multiple items literal'\nassert {1: 'a', 2: 'b'} == {1: 'a', 2: 'b'}, 'int keys literal'\n\n# === Dict length ===\nassert len({}) == 0, 'len empty'\nassert len({'a': 1, 'b': 2, 'c': 3}) == 3, 'len multiple'\n\n# === Dict equality ===\nassert ({'a': 1, 'b': 2} == {'b': 2, 'a': 1}) == True, 'equality true (order independent)'\nassert ({'a': 1} == {'a': 2}) == False, 'equality false'\n\n# === Dict subscript get ===\nd = {'name': 'Alice', 'age': 30}\nassert d['name'] == 'Alice', 'subscript get str key'\nassert d['age'] == 30, 'subscript get value'\n\nd = {1: 'one', 2: 'two'}\nassert d[1] == 'one', 'subscript get int key'\n\n# === Dict subscript set ===\nd = {'a': 1}\nd['b'] = 2\nassert d == {'a': 1, 'b': 2}, 'subscript set new key'\n\nd = {'a': 1}\nd['a'] = 99\nassert d == {'a': 99}, 'subscript set existing key'\n\n# === Dict subscript augmented assignment ===\ntotals = {'photo': 1}\nrtype = 'photo'\nlikes = 2\ntotals[rtype] += likes\nassert totals == {'photo': 3}, 'subscript += updates existing dict item'\n\ncalls = 0\n\n\ndef key():\n    global calls\n    calls += 1\n    return 'photo'\n\n\ntotals = {'photo': 10}\ntotals[key()] += 5\nassert totals == {'photo': 15}, 'subscript += stores the computed result back'\nassert calls == 1, 'subscript += evaluates the index expression once'\n\ncaptured_total = {'photo': 1}\ncaptured_likes = 2\n\n\ndef apply_captured_increment():\n    captured_total['photo'] += captured_likes\n\n\napply_captured_increment()\nassert captured_total == {'photo': 3}, 'subscript += works with closure-captured names'\n\nwalrus_key = None\nwalrus_total = {'photo': 10}\nwalrus_total[(walrus_key := 'photo')] += 4\nassert walrus_key == 'photo', 'subscript += allows walrus in the index expression'\nassert walrus_total == {'photo': 14}, 'subscript += with walrus index updates the selected item'\n\ntry:\n    missing = {}\n    missing['photo'] += 1\n    assert False, 'subscript += on a missing dict key should raise KeyError'\nexcept KeyError as e:\n    assert e.args == ('photo',), 'subscript += missing key preserves the missing key in KeyError'\n\ntry:\n    existing = {'photo': 'a'}\n    existing['photo'] += 1\n    assert False, 'subscript += with incompatible operand types should raise TypeError'\nexcept TypeError as e:\n    assert e.args == ('can only concatenate str (not \"int\") to str',), 'subscript += type error matches CPython'\n    assert existing == {'photo': 'a'}, 'failed subscript += does not overwrite the original dict item'\n\n# === Dict.get() method ===\nd = {'a': 1, 'b': 2}\nassert d.get('a') == 1, 'get existing'\nassert d.get('missing') is None, 'get missing returns None'\nassert d.get('missing', 'default') == 'default', 'get missing with default'\n\n# === Dict.pop() method ===\nd = {'a': 1, 'b': 2}\nassert d.pop('a') == 1, 'pop existing'\nassert d == {'b': 2}, 'pop removes key'\n\nd = {'a': 1}\nassert d.pop('missing', 'default') == 'default', 'pop missing with default'\n\n# === Dict with tuple key ===\nd = {(1, 2): 'value'}\nassert d[(1, 2)] == 'value', 'tuple key'\n\n# === Dict repr ===\nassert repr({}) == '{}', 'empty repr'\nassert repr({'a': 1}) == \"{'a': 1}\", 'repr with items'\n\n# === Dict self-reference ===\nd = {}\nd['self'] = d\nassert d['self'] is d, 'getitem self'\n\nd = {}\nassert d.get('missing', d) is d, 'get default same dict'\n\n# === Dict unpacking (PEP 448) ===\na = {'x': 1, 'y': 2}\nb = {'y': 99, 'z': 3}\nassert {**a} == {'x': 1, 'y': 2}, 'single unpack'\nassert {**a, **b} == {'x': 1, 'y': 99, 'z': 3}, 'double unpack, later wins'\nassert {**a, 'y': 0} == {'x': 1, 'y': 0}, 'literal overrides unpacked key'\nassert {'y': 0, **a} == {'y': 2, 'x': 1}, 'unpack overrides earlier literal'\nassert {**a, 'z': 3} == {'x': 1, 'y': 2, 'z': 3}, 'unpack then new key'\nassert {**{}} == {}, 'unpack empty dict'\nassert {**a, **b, 'w': 4} == {'x': 1, 'y': 99, 'z': 3, 'w': 4}, 'complex mixed'\nassert list({**a, 'z': 3}.keys()) == ['x', 'y', 'z'], 'insertion order preserved'\n\n# === Dict unpack TypeError for non-mapping heap ref ===\n# Unpacking a Ref that is NOT a dict (e.g. a list) should raise TypeError\ntry:\n    x = {**[1, 2, 3]}\n    assert False, 'expected TypeError'\nexcept TypeError as e:\n    assert str(e) == \"'list' object is not a mapping\", f'wrong error: {e}'\n",
