  'ext_call__arg_side_effect_bug.py':
      "# call-external\n# BUG: Side effects in arguments are duplicated when external call suspends\n#\n# When an external call is in one argument position and there's a side effect\n# in another argument position, the side effect may be executed multiple times\n# because argument evaluation is repeated during resumption.\n\ncall_count = 0\n\n\ndef side_effect(val):\n    global call_count\n    call_count += 1\n    return val\n\n\n# Side effect before external call in args\n# Expected: side_effect runs once, result is 10 + 3 = 13\ncall_count = 0\nresult = add_ints(side_effect(10), add_ints(1, 2))\nassert result == 13, 'ext call after side effect'\nassert call_count == 1, 'side effect should happen only once (before ext)'\n",
  'ext_call__augmented.py':
      "# call-external\n# External calls in augmented assignment expressions\n\n# += with external call\nx = 10\nx += add_ints(5, 5)\nassert x == 20, 'ext call in augmented add'\n\n# -= with external call\nx = 100\nx -= add_ints(20, 30)\nassert x == 50, 'ext call in augmented sub'\n\n# *= with external call\nx = 5\nx *= add_ints(2, 1)\nassert x == 15, 'ext call in augmented mul'\n",
  'ext_call__augmented_refcount_bug.py':
      "# call-external\n# BUG: Reference counting bug with string augmented assignment and external calls\n\n# String += with external call causes reference counting error\ns = 'hello'\ns += concat_strings(' ', 'world')\nassert s == 'hello world', 'ext call in augmented string concat'\n",
  'ext_call__bare_raise_after_resume.py':
      "# call-external\n# Test bare raise after external call resumption in except handler\n# This tests that current_exception is properly restored after resuming\n# Note: bare raise after resumption only works when exception is bound (as e)\n\ncaught_reraised = False\ntry:\n    try:\n        raise ValueError('original error')\n    except ValueError as e:\n        # Make an external call, which will cause a suspend/resume\n        x = add_ints(1, 2)\n        # After resuming, bare raise should still work (exception restored from binding)\n        raise\nexcept ValueError as outer_e:\n    caught_reraised = repr(outer_e) == \"ValueError('original error')\"\n\nassert caught_reraised, 'bare raise after external call should re-raise original exception'\n\n# === Nested handler bare raise after resumption ===\nouter_nested_reraise = False\ntry:\n    try:\n        raise ValueError('outer error')\n    except ValueError:\n        try:\n            raise KeyError('inner error')\n        except KeyError:\n            _ = add_ints(1, 2)\n        raise\nexcept ValueError as reraised:\n    outer_nested_reraise = repr(reraised) == \"ValueError('outer error')\"\n\nassert outer_nested_reraise, 'bare raise in outer handler should re-raise original exception after nested resumption'\n",
  'ext_call__basic.py':
      "# call-external\n# === Basic external function tests ===\n\n# Simple calls\na = add_ints(10, 20)\nassert a == 30, 'add_ints basic'\n\nb = add_ints(-5, 15)\nassert b == 10, 'add_ints with negative'\n\ns = concat_strings('hello', ' world')\nassert s == 'hello world', 'concat_strings basic'\n\nx = return_value(42)\nassert x == 42, 'return_value with int'\n\ny = return_value('test')\nassert y == 'test', 'return_value with str'\n\n# === Assignment with external calls ===\nresult = add_ints(100, 200)\nassert result == 300, 'assignment from add_ints'\n\nname = concat_strings('foo', 'bar')\nassert name == 'foobar', 'assignment from concat_strings'\n\n# === Nested calls ===\nnested = add_ints(1, add_ints(2, 3))\nassert nested == 6, 'nested add_ints right'\n\nnested2 = add_ints(add_ints(1, 2), 3)\nassert nested2 == 6, 'nested add_ints left'\n\nnested3 = add_ints(add_ints(1, 2), add_ints(3, 4))\nassert nested3 == 10, 'nested add_ints both'\n\ndeep = add_ints(add_ints(add_ints(1, 2), 3), 4)\nassert deep == 10, 'deeply nested add_ints'\n\n# === Chained operations ===\nchained = add_ints(1, 2) + add_ints(3, 4)\nassert chained == 10, 'chained add_ints with +'\n\nchained2 = add_ints(10, 20) - add_ints(5, 10)\nassert chained2 == 15, 'chained add_ints with -'\n\nchained3 = add_ints(2, 3) * add_ints(4, 5)\nassert chained3 == 45, 'chained add_ints with *'\n\nstr_chain = concat_strings('a', 'b') + concat_strings('c', 'd')\nassert str_chain == 'abcd', 'chained concat_strings'\n\n# === External calls in assert statements ===\nassert add_ints(5, 5) == 10, 'ext call in assert condition'\nassert return_value(True), 'ext call returning truthy in assert'\nassert concat_strings('x', 'y') == 'xy', 'concat in assert'\nassert add_ints(1, add_ints(2, 3)) == 6, 'nested ext call in assert'\n\n# === Mixed with builtins ===\nlength = len(concat_strings('hello', 'world'))\nassert length == 10, 'len of concat result'\n\nitems = [add_ints(1, 2), add_ints(3, 4)]\nassert items[0] == 3, 'ext call in list literal first'\nassert items[1] == 7, 'ext call in list literal second'\n\n# === Multiple external calls in single expression ===\n\n# Two ext calls added together\nsum_result = add_ints(1, 2) + add_ints(3, 4)\nassert sum_result == 10, 'two ext calls in addition'\n\n# Three ext calls in one expression\ntriple = add_ints(1, 1) + add_ints(2, 2) + add_ints(3, 3)\nassert triple == 12, 'three ext calls in expression'\n\n# Ext calls in multiplication\nmul_result = add_ints(2, 3) * add_ints(1, 1)\nassert mul_result == 10, 'ext calls in multiplication'\n\n# Ext calls in subtraction\nsub_result = add_ints(10, 5) - add_ints(3, 2)\nassert sub_result == 10, 'ext calls in subtraction'\n\n# Complex expression with multiple ext calls\ncomplex_expr = (add_ints(1, 2) + add_ints(3, 4)) * add_ints(0, 2)\nassert complex_expr == 20, 'complex expr with ext calls'\n\n# String concatenation with multiple ext calls\nstr_result = concat_strings(return_value('a'), return_value('b')) + concat_strings('c', 'd')\nassert str_result == 'abcd', 'multiple ext calls for string concat'\n\n# Comparison with multiple ext calls\ncmp_result = add_ints(5, 5) == add_ints(3, 7)\nassert cmp_result == True, 'comparison of two ext call results'\n\n# Nested ext calls in expression\nnested_expr = add_ints(add_ints(1, 2), add_ints(3, 4))\nassert nested_expr == 10, 'nested ext calls in expression'\n",
  'ext_call__boolean.py':
      "# call-external\n# External calls in boolean short-circuit expressions\n\n# === Basic boolean operations ===\nresult = return_value(True) and return_value(42)\nassert result == 42, 'ext call in and (both run)'\n\nresult = return_value(False) and return_value(42)\nassert result == False, 'ext call in and (short circuit)'\n\nresult = return_value(0) or return_value(42)\nassert result == 42, 'ext call in or (both run)'\n\nresult = return_value(99) or return_value(42)\nassert result == 99, 'ext call in or (short circuit)'\n\n\n# === Chained boolean with external calls ===\nresult = return_value(True) and return_value(True) and return_value(42)\nassert result == 42, 'chained and all truthy'\n\nresult = return_value(True) and return_value(False) and return_value(42)\nassert result == False, 'chained and with false in middle'\n\nresult = return_value(0) or return_value(0) or return_value(42)\nassert result == 42, 'chained or all falsy except last'\n\nresult = return_value(0) or return_value(99) or return_value(42)\nassert result == 99, 'chained or with truthy in middle'\n\n\n# === Mixed and/or ===\nresult = return_value(True) and return_value(0) or return_value(42)\nassert result == 42, 'and then or'\n\nresult = return_value(0) or return_value(True) and return_value(42)\nassert result == 42, 'or then and'\n",
  'ext_call__boolean_side_effect_hang.py':
      "# call-external\n# BUG: This test hangs (infinite loop) - external calls in boolean expressions\n# with side effects cause incorrect behavior.\n\ncall_count = 0\n\n\ndef side_effect(val):\n    global call_count\n    call_count += 1\n    return val\n\n\n# This specific pattern causes a hang in Monty\nresult = return_value(True) and return_value(side_effect(42))\nassert result == 42, 'and: second runs when first truthy'\nassert call_count == 1, 'and: side effect runs when first is truthy'\n",
  'ext_call__closure_bug.py':
      "# call-external\n# BUG: External calls in closures cannot access captured variables\n# When an external call is inside a closure, it fails to access free variables\n# Error: \"cannot access free variable 'x' where it is not associated with a value\"\n\n\ndef make_adder(x):\n    def adder(y):\n        return add_ints(x, y)\n\n    return adder\n\n\nadd5 = make_adder(5)\nresult = add5(10)\nassert result == 15, 'ext call in closure accessing captured var'\n",
  'ext_call__comparison.py':
      "# call-external\n# External calls in comparison expressions\n\n# External call on left side of comparison\nresult = add_ints(1, 2) == 3\nassert result == True, 'ext call == literal'\n\n# External call on right side\nresult = 3 == add_ints(1, 2)\nassert result == True, 'literal == ext call'\n\n# Both sides external calls\nresult = add_ints(1, 2) == add_ints(2, 1)\nassert result == True, 'ext call == ext call'\n\n# Less than\nresult = add_ints(1, 1) < add_ints(2, 2)\nassert result == True, 'ext call < ext call'\n\n# Greater than\nresult = add_ints(5, 5) > add_ints(2, 2)\nassert result == True, 'ext call > ext call'\n\n# Not equal\nresult = add_ints(1, 2) != add_ints(3, 4)\nassert result == True, 'ext call != ext call'\n",
  'ext_call__deep_call_stack.py':
      "# call-external\n# External function calls in deep call stacks (function calling function).\n# Tests that the outer function receives the return value correctly when\n# the inner function makes an external call.\n\n\ndef depth1(n):\n    return add_ints(n, 1)\n\n\ndef depth2(n):\n    return depth1(n) + 10\n\n\nresult = depth2(5)\n# depth2(5) should be: depth1(5) + 10 = 6 + 10 = 16\n\nassert result == 16, f'ext call through 2 levels of functions {result=}'\n",
  'ext_call__elif.py':
      "# call-external\n# === External calls in elif conditions ===\n\n# External call in elif condition - true\nresult1 = 0\nif add_ints(1, 1) == 3:\n    result1 = 1\nelif add_ints(2, 2) == 4:\n    result1 = 2\nelse:\n    result1 = 3\nassert result1 == 2, f'elif condition with ext call should be evaluated, {result1=}'\n\n# External call in elif condition - falls through to else\nresult2 = 0\nif add_ints(1, 1) == 3:\n    result2 = 1\nelif add_ints(2, 2) == 5:\n    result2 = 2\nelse:\n    result2 = 3\nassert result2 == 3, 'else taken when all ext call conditions are false'\n\n# Multiple elif with external calls\nresult3 = 0\nif add_ints(1, 1) == 10:\n    result3 = 1\nelif add_ints(2, 2) == 10:\n    result3 = 2\nelif add_ints(3, 3) == 6:\n    result3 = 3\nelif add_ints(4, 4) == 10:\n    result3 = 4\nelse:\n    result3 = 5\nassert result3 == 3, 'third elif with ext call should match'\n\n# === External calls in elif bodies ===\n\n# Ext call in elif body\nval1 = 0\nif False:\n    val1 = 1\nelif True:\n    val1 = add_ints(10, 20)\nelse:\n    val1 = 3\nassert val1 == 30, 'ext call in elif body'\n\n# Ext call in else body after elif chain\nval2 = 0\nif False:\n    val2 = 1\nelif False:\n    val2 = 2\nelse:\n    val2 = add_ints(15, 25)\nassert val2 == 40, 'ext call in else body after elif'\n\n# Multiple ext calls in elif body\nval3 = 0\nif False:\n    val3 = 1\nelif True:\n    a = add_ints(5, 5)\n    b = add_ints(10, 10)\n    val3 = add_ints(a, b)\nelse:\n    val3 = 3\nassert val3 == 30, 'multiple ext calls in elif body'\n\n# === Nested ext calls ===\n\n# Nested ext calls in elif condition\nresult4 = 0\nif False:\n    result4 = 1\nelif add_ints(add_ints(1, 2), add_ints(3, 4)) == 10:\n    result4 = 2\nelse:\n    result4 = 3\nassert result4 == 2, 'nested ext calls in elif condition'\n\n# === Short-circuit with ext calls ===\n\n# Ext call should not be evaluated if earlier condition is true\ncall_count = 0\n\n\ndef counting_add(a, b):\n    global call_count\n    call_count = call_count + 1\n    return a + b\n\n\n# This uses a regular function, not ext call, to verify short-circuit\n# but the ext calls in bodies still test suspension\nx = 0\nif True:\n    x = add_ints(1, 1)\nelif False:\n    x = add_ints(2, 2)\nassert x == 2, 'if body ext call executed, elif skipped'\n\n# === Ext call in both condition and body ===\n\nresult5 = 0\nif add_ints(1, 1) == 3:\n    result5 = add_ints(100, 100)\nelif add_ints(2, 2) == 4:\n    result5 = add_ints(50, 50)\nelse:\n    result5 = add_ints(25, 25)\nassert result5 == 100, 'ext call in both elif condition and body'\n\n# === Ext call in if body when condition is true ===\n\nif_body_result = 0\nif add_ints(5, 5) == 10:\n    if_body_result = add_ints(100, 200)\nelif add_ints(1, 1) == 2:\n    if_body_result = add_ints(10, 20)\nelse:\n    if_body_result = add_ints(1, 2)\nassert if_body_result == 300, 'ext call in if body when if condition is true'\n\n# === Ext calls returning values used as conditions ===\n\n# return_value returns its argument, so we can use it to test boolean coercion\ncond_result = 0\nif return_value(0):\n    cond_result = 1\nelif return_value(1):\n    cond_result = 2\nelse:\n    cond_result = 3\nassert cond_result == 2, 'ext call return value used as boolean condition'\n\n# === Ext calls with string concatenation ===\n\nstr_result = ''\nif add_ints(1, 1) == 3:\n    str_result = concat_strings('a', 'b')\nelif add_ints(2, 2) == 4:\n    str_result = concat_strings('hello', ' world')\nelse:\n    str_result = concat_strings('x', 'y')\nassert str_result == 'hello world', 'ext call with string result in elif body'\n\n# === Multiple conditions with ext calls in same expression ===\n\nmulti_cond = 0\nif add_ints(1, 1) > 5:\n    multi_cond = 1\nelif add_ints(2, 2) < add_ints(3, 3):\n    multi_cond = 2\nelse:\n    multi_cond = 3\nassert multi_cond == 2, 'comparison between two ext call results in elif condition'\n\n# === Ext call in all three branches ===\n\nall_branches = 0\nval = add_ints(5, 5)\nif val < 5:\n    all_branches = add_ints(1, 0)\nelif val < 15:\n    all_branches = add_ints(2, 0)\nelse:\n    all_branches = add_ints(3, 0)\nassert all_branches == 2, 'ext call in elif body based on earlier ext call result'\n",
  'ext_call__exc.py':
      "# call-external\n# External call in raise statement\nraise ValueError(return_value('foobar'))\n# Raise=ValueError('foobar')\n",
  'ext_call__exc_deep_stack.py':
      "# call-external\ndef level4():\n    x = 1\n    raise_error('RuntimeError', 'deep error')\n\n\ndef level3():\n    level4()\n\n\ndef level2():\n    level3()\n\n\ndef level1():\n    level2()\n\n\nlevel1()\n\"\"\"\nTRACEBACK:\nTraceback (most recent call last):\n  File \"ext_call__exc_deep_stack.py\", line 19, in <module>\n    level1()\n    ~~~~~~~~\n  File \"ext_call__exc_deep_stack.py\", line 16, in level1\n    level2()\n    ~~~~~~~~\n  File \"ext_call__exc_deep_stack.py\", line 12, in level2\n    level3()\n    ~~~~~~~~\n  File \"ext_call__exc_deep_stack.py\", line 8, in level3\n    level4()\n    ~~~~~~~~\n  File \"ext_call__exc_deep_stack.py\", line 4, in level4\n    raise_error('RuntimeError', 'deep error')\n    ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\nRuntimeError: deep error\n\"\"\"\n",
  'ext_call__exc_in_function.py':
      "# call-external\ndef wrapper():\n    raise_error('ValueError', 'from external')\n\n\nwrapper()\n\"\"\"\nTRACEBACK:\nTraceback (most recent call last):\n  File \"ext_call__exc_in_function.py\", line 6, in <module>\n    wrapper()\n    ~~~~~~~~~\n  File \"ext_call__exc_in_function.py\", line 3, in wrapper\n    raise_error('ValueError', 'from external')\n    ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\nValueError: from external\n\"\"\"\n",
  'ext_call__exc_nested_functions.py':
      "# call-external\ndef inner():\n    raise_error('TypeError', 'nested error')\n\n\ndef middle():\n    inner()\n\n\ndef outer():\n    middle()\n\n\nouter()\n\"\"\"\nTRACEBACK:\nTraceback (most recent call last):\n  File \"ext_call__exc_nested_functions.py\", line 14, in <module>\n    outer()\n    ~~~~~~~\n  File \"ext_call__exc_nested_functions.py\", line 11, in outer\n    middle()\n    ~~~~~~~~\n  File \"ext_call__exc_nested_functions.py\", line 7, in middle\n    inner()\n    ~~~~~~~\n  File \"ext_call__exc_nested_functions.py\", line 3, in inner\n    raise_error('TypeError', 'nested error')\n    ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~\nTypeError: nested error\n\"\"\"\n",
  'ext_call__ext_exc.py':
      "# call-external\n# === External function exceptions ===\n# Tests for exceptions raised by external functions\n\n# === Basic exception propagation ===\n\n# External function raising ValueError\ncaught_value_error = False\ntry:\n    result = raise_error('ValueError', 'test error')\n    assert False, 'should not reach here'\nexcept ValueError:\n    caught_value_error = True\nassert caught_value_error, 'ValueError was caught'\n\n# External function raising TypeError\ncaught_type_error = False\ntry:\n    result = raise_error('TypeError', 'type error message')\n    assert False, 'should not reach here'\nexcept TypeError:\n    caught_type_error = True\nassert caught_type_error, 'TypeError was caught'\n\n# External function raising KeyError\ncaught_key_error = False\ntry:\n    result = raise_error('KeyError', 'missing key')\n    assert False, 'should not reach here'\nexcept KeyError:\n    caught_key_error = True\nassert caught_key_error, 'KeyError was caught'\n\n# External function raising RuntimeError\ncaught_runtime_error = False\ntry:\n    result = raise_error('RuntimeError', 'runtime error')\n    assert False, 'should not reach here'\nexcept RuntimeError:\n    caught_runtime_error = True\nassert caught_runtime_error, 'RuntimeError was caught'\n\n# === Exception not caught by wrong handler ===\n\n# ValueError not caught by TypeError handler\ncaught_outer = False\ntry:\n    try:\n        raise_error('ValueError', 'inner error')\n    except TypeError:\n        assert False, 'TypeError should not catch ValueError'\nexcept ValueError:\n    caught_outer = True\nassert caught_outer, 'ValueError caught by outer handler'\n\n# === Exception in expression with multiple ext calls ===\n\n# First ext call raises, second should not be called\ntry:\n    x = raise_error('ValueError', 'first') + add_ints(1, 2)\n    assert False, 'should not reach here'\nexcept ValueError:\n    pass  # Expected\n\n# === External exception in try body with finally ===\n\nfinally_ran = False\ntry:\n    raise_error('ValueError', 'in try')\nexcept ValueError:\n    pass  # Caught\nfinally:\n    finally_ran = True\nassert finally_ran, 'finally ran after external exception caught'\n\n# External exception propagating through finally\nouter_caught = False\nfinally_ran2 = False\ntry:\n    try:\n        raise_error('KeyError', 'will propagate')\n    except ValueError:\n        assert False, 'ValueError should not catch KeyError'\n    finally:\n        finally_ran2 = True\nexcept KeyError:\n    outer_caught = True\nassert finally_ran2, 'finally ran before exception propagated'\nassert outer_caught, 'exception propagated after finally'\n\n# === Mix of normal returns and exceptions ===\n\n# Normal return, then exception\nvalue1 = add_ints(10, 20)\nassert value1 == 30, 'first ext call returned normally'\ntry:\n    raise_error('ValueError', 'after success')\n    assert False, 'should not reach here'\nexcept ValueError:\n    pass  # Expected\n\n# Exception, then normal return (after catching)\ncaught_exc = False\ntry:\n    raise_error('TypeError', 'will be caught')\nexcept TypeError:\n    caught_exc = True\nvalue2 = add_ints(5, 5)\nassert caught_exc, 'exception was caught'\nassert value2 == 10, 'ext call after caught exception returned normally'\n\n# === Exception in except handler from external function ===\n\nouter_catch = False\ntry:\n    try:\n        raise ValueError('inner')\n    except ValueError:\n        raise_error('TypeError', 'from handler')\nexcept TypeError:\n    outer_catch = True\nassert outer_catch, 'exception from handler caught by outer'\n\n# === Exception in else block from external function ===\n\nelse_exc_caught = False\ntry:\n    try:\n        pass  # No exception\n    except:\n        assert False, 'should not reach except'\n    else:\n        raise_error('RuntimeError', 'from else')\nexcept RuntimeError:\n    else_exc_caught = True\nassert else_exc_caught, 'exception from else block caught'\n\n# === Exception in finally block ===\n\n# Note: exception in finally replaces any pending exception\nfinally_exc_caught = False\ntry:\n    try:\n        pass\n    finally:\n        raise_error('ValueError', 'from finally')\nexcept ValueError:\n    finally_exc_caught = True\nassert finally_exc_caught, 'exception from finally caught'\n\n# === Nested try blocks with external exceptions ===\n\ninner_handled = False\nouter_handled = False\nfinally_count = 0\ntry:\n    try:\n        raise_error('ValueError', 'inner error')\n    except ValueError:\n        inner_handled = True\n        raise_error('TypeError', 'from inner handler')\n    finally:\n        finally_count += 1\nexcept TypeError:\n    outer_handled = True\nfinally:\n    finally_count += 1\n\nassert inner_handled, 'inner exception was handled'\nassert outer_handled, 'exception from inner handler was caught by outer'\nassert finally_count == 2, 'both finally blocks ran'\n",
  'ext_call__for.py':
      "# call-external\n# === External calls in for loops ===\n\n# Ext call in loop body\ntotal = 0\nfor i in range(3):\n    total = add_ints(total, 1)\nassert total == 3, f'ext call accumulator in loop, {total=}'\n\n# Ext call with loop variable\nsum_val = 0\nfor i in range(4):\n    sum_val = add_ints(sum_val, i)\nassert sum_val == 6, 'ext call with loop var'\n\n# Multiple ext calls per iteration\nresult = 0\nfor i in range(3):\n    result = add_ints(result, add_ints(i, i))\nassert result == 6, 'nested ext calls in loop'\n\n# Building list with ext calls\nitems = []\nfor i in range(3):\n    items.append(add_ints(i, 10))\nassert items[0] == 10, 'ext call list build first'\nassert items[1] == 11, 'ext call list build second'\nassert items[2] == 12, 'ext call list build third'\n\n# Chained ext calls in loop\nacc = 0\nfor i in range(3):\n    acc = add_ints(acc, 1) + add_ints(0, 1)\nassert acc == 6, 'chained ext calls in loop body'\n\n# Nested loops with ext calls\nmatrix_sum = 0\nfor i in range(2):\n    for j in range(2):\n        matrix_sum = add_ints(matrix_sum, add_ints(i, j))\nassert matrix_sum == 4, 'ext calls in nested loops'\n\n# === More nested loop edge cases ===\n\n# Nested loops building a result list\nresults = []\nfor i in range(2):\n    for j in range(2):\n        results.append(concat_strings(return_value(str(i)), return_value(str(j))))\nassert results[0] == '00', 'nested loops result list first'\nassert results[1] == '01', 'nested loops result list second'\nassert results[2] == '10', 'nested loops result list third'\nassert results[3] == '11', 'nested loops result list fourth'\n\n# If inside for loop with external call condition\nfiltered = []\nfor i in range(3):\n    if return_value(i) == i:\n        filtered.append(i)\nassert filtered == [0, 1, 2], 'if inside for with ext condition'\n\n# If inside for loop - some iterations match\nresults2 = []\nfor i in range(4):\n    # Only append even numbers (using modulo check with add_ints)\n    if add_ints(i, 0) % 2 == 0:\n        results2.append(return_value(i))\nassert results2 == [0, 2], 'if inside for filtering with ext'\n\n# Nested for with different ranges\nouter_sum = 0\nfor i in range(2):\n    inner_sum = 0\n    for j in range(3):\n        inner_sum = add_ints(inner_sum, add_ints(i, j))\n    outer_sum = add_ints(outer_sum, inner_sum)\n# i=0: (0+0)+(0+1)+(0+2) = 0+1+2 = 3\n# i=1: (1+0)+(1+1)+(1+2) = 1+2+3 = 6\n# total = 3 + 6 = 9\nassert outer_sum == 9, 'nested for with accumulator'\n\n# Three levels of nested loops\ncount = 0\nfor i in range(2):\n    for j in range(2):\n        for k in range(2):\n            count = add_ints(count, 1)\nassert count == 8, 'triple nested for with ext call'\n\n# multiple ext calls in iterable\n\next_ints = []\nfor i in add_ints(1, 1), add_ints(2, 2), add_ints(3, 3):\n    ext_ints.append(i)\nassert ext_ints == [2, 4, 6], 'multiple ext calls in iterable'\n\n# ext call iterable, get_list() returns [1, 2, 3]\ntotal = 0\nfor x in get_list():\n    total = add_ints(total, x)\nassert total == 6, 'ext call iterable'\n\n# string iteration with ext call in body\nchars = []\nfor c in 'abc':\n    chars.append(return_value(c))\nassert chars == ['a', 'b', 'c'], f'string iteration with ext call: {chars}'\n\n# unicode string iteration with ext call in body\n# Tests decr() handling of multi-byte UTF-8 characters (1-4 bytes each)\nunicode_chars = []\nfor c in 'aé中😀b':  # a (1 byte), e-acute (2), chinese (3), emoji (4), b (1)\n    unicode_chars.append(return_value(c))\nassert unicode_chars == ['a', 'é', '中', '😀', 'b'], f'unicode iteration: {unicode_chars}'\n",
  'ext_call__fstring.py':
      "# call-external\n# External calls in f-strings\n\ns = f'result is {add_ints(10, 20)}'\nassert s == 'result is 30', 'ext call in f-string'\n\ns = f'a={add_ints(1, 2)}, b={add_ints(3, 4)}'\nassert s == 'a=3, b=7', 'multiple ext calls in f-string'\n\n# Nested external call in f-string\ns = f'nested={add_ints(add_ints(1, 2), 3)}'\nassert s == 'nested=6', 'nested ext call in f-string'\n",
  'ext_call__if.py':
      "# call-external\n# === External calls in if/else expressions ===\n\n# Ternary expression with ext call in condition\nresult = 'yes' if add_ints(1, 1) == 2 else 'no'\nassert result == 'yes', 'ext call in ternary condition true'\n\nresult2 = 'yes' if add_ints(1, 1) == 3 else 'no'\nassert result2 == 'no', 'ext call in ternary condition false'\n\n# Ext call in true branch\nval = add_ints(10, 20) if True else 0\nassert val == 30, 'ext call in ternary true branch'\n\n# Ext call in false branch\nval2 = 0 if False else add_ints(5, 5)\nassert val2 == 10, 'ext call in ternary false branch'\n\n# Ext calls in both branches\nval3 = add_ints(1, 2) if True else add_ints(3, 4)\nassert val3 == 3, 'ext call in both branches takes true'\n\nval4 = add_ints(1, 2) if False else add_ints(3, 4)\nassert val4 == 7, 'ext call in both branches takes false'\n\n# === If statements with external calls ===\n\n# Ext call in if condition\nx = 0\nif add_ints(1, 1) == 2:\n    x = 100\nassert x == 100, 'ext call in if statement condition true'\n\ny = 0\nif add_ints(1, 1) == 3:\n    y = 100\nassert y == 0, 'ext call in if statement condition false'\n\n# Ext call in if body\nz = 0\nif True:\n    z = add_ints(50, 50)\nassert z == 100, 'ext call in if body'\n\n# Ext call in else body\nw = 0\nif False:\n    w = 1\nelse:\n    w = add_ints(25, 75)\nassert w == 100, 'ext call in else body'\n\n# Nested ext calls in condition\nnested = 0\nif add_ints(add_ints(1, 2), add_ints(3, 4)) == 10:\n    nested = 1\nassert nested == 1, 'nested ext calls in if condition'\n\n# Chained conditions with ext calls\nresult3 = 0\nif add_ints(1, 1) == 2 and add_ints(2, 2) == 4:\n    result3 = 1\nassert result3 == 1, 'multiple ext calls in and condition'\n\nresult4 = 0\nif add_ints(1, 1) == 3 or add_ints(2, 2) == 4:\n    result4 = 1\nassert result4 == 1, 'multiple ext calls in or condition'\n\n# Comparison with ext call results\ncmp = add_ints(10, 5) > add_ints(5, 5)\nassert cmp == True, 'comparing two ext call results'\n\n# === Nested if statements with external calls ===\n\n# Nested if with ext calls in both conditions (both true)\nresult = 'none'\nif return_value(1) == 1:\n    if return_value(2) == 2:\n        result = 'inner'\n    else:\n        result = 'outer_only'\nelse:\n    result = 'failed'\nassert result == 'inner', 'nested if both conditions true'\n\n# Nested if - outer true, inner false\nresult2 = 'none'\nif return_value(1) == 1:\n    if return_value(2) == 999:\n        result2 = 'inner'\n    else:\n        result2 = 'outer_only'\nelse:\n    result2 = 'failed'\nassert result2 == 'outer_only', 'nested if inner false'\n\n# Nested if - outer false\nresult3 = 'none'\nif return_value(1) == 999:\n    if return_value(2) == 2:\n        result3 = 'inner'\n    else:\n        result3 = 'outer_only'\nelse:\n    result3 = 'xxx'\nassert result3 == 'xxx', 'nested if outer false'\n\n# Triple nested if - all true\nresult4 = 0\nif return_value(1) == 1:\n    if return_value(2) == 2:\n        if return_value(3) == 3:\n            result4 = 123\nassert result4 == 123, 'triple nested if all true'\n\n# If condition with multiple ext calls (addition)\nresult5 = 0\nif add_ints(1, 2) + add_ints(3, 4) == 10:\n    result5 = 1\nassert result5 == 1, 'if condition with multiple ext calls'\n\n# For loop inside if with external condition\ntotal = 0\nif return_value(1) == 1:\n    for i in range(3):\n        total = add_ints(total, return_value(i))\nassert total == 3, 'for loop inside if with ext condition'\n\n# For loop inside if - condition false\ntotal2 = 0\nif return_value(1) == 999:\n    for i in range(3):\n        total2 = add_ints(total2, i)\nassert total2 == 0, 'for loop inside if condition false'\n",
  'ext_call__if_condition.py':
      "# call-external\n# External calls in if conditions\n\n\ndef check_positive():\n    if add_ints(1, 2) > 0:\n        return 'positive'\n    return 'not positive'\n\n\nresult = check_positive()\nassert result == 'positive', 'ext call in if condition'\n\n\ndef check_with_else():\n    if add_ints(-5, 3) > 0:\n        return 'positive'\n    else:\n        return 'negative or zero'\n\n\nresult = check_with_else()\nassert result == 'negative or zero', 'ext call in if condition with else'\n\n\ndef check_elif():\n    val = add_ints(5, 5)\n    if val > 15:\n        return 'big'\n    elif val > 5:\n        return 'medium'\n    else:\n        return 'small'\n\n\nresult = check_elif()\nassert result == 'medium', 'ext call result used in elif chain'\n",
  'ext_call__in_closure.py':
      "# call-external\n# External function calls inside closures (nested functions with captured variables).\n\n\ndef outer_with_nested():\n    x = 10\n\n    def inner():\n        return add_ints(x, 5)\n\n    return inner()\n\n\nassert outer_with_nested() == 15, 'ext call in nested function'\n",
  'ext_call__in_function.py':
      "# call-external\n# === External function calls inside user-defined functions ===\n\n# Basic function calling external function\ndef add_wrapper(a, b):\n    return add_ints(a, b)\n\n\nresult = add_wrapper(10, 20)\nassert result == 30, 'basic ext call in function'\n\n\n# Function with multiple external calls (sequential)\ndef multi_ext():\n    x = add_ints(1, 2)\n    y = add_ints(3, 4)\n    return add_ints(x, y)\n\n\nassert multi_ext() == 10, 'multiple ext calls in function'\n\n\n# External call in function with local variable usage\ndef with_locals():\n    x = 100\n    y = add_ints(x, 50)\n    z = y * 2\n    return z\n\n\nassert with_locals() == 300, 'ext call with locals'\n\n\n# Function returning external call result\ndef get_sum(a, b, c):\n    temp = add_ints(a, b)\n    return add_ints(temp, c)\n\n\nassert get_sum(1, 2, 3) == 6, 'chained ext calls in function'\n",
  'ext_call__in_function_simple.py':
      "# call-external\ndef foo():\n    return add_ints(1, 2)\n\n\nresult = foo()\nassert result == 3, 'basic ext call in function'\n",
  'ext_call__literals.py':
      "# call-external\n# External calls in list and dict literals\n\n# External call in list literal\nlst = [add_ints(1, 2), add_ints(3, 4)]\nassert lst[0] == 3, 'ext call in list literal [0]'\nassert lst[1] == 7, 'ext call in list literal [1]'\n\n# External call in tuple literal\ntup = (add_ints(1, 1), add_ints(2, 2))\nassert tup[0] == 2, 'ext call in tuple literal [0]'\nassert tup[1] == 4, 'ext call in tuple literal [1]'\n\n# External call in dict value\nd = {'a': add_ints(5, 5), 'b': add_ints(10, 10)}\nassert d['a'] == 10, 'ext call in dict value a'\nassert d['b'] == 20, 'ext call in dict value b'\n",
  'ext_call__multi_in_func.py':
      "# call-external\n# Multiple external calls within user-defined functions\n\n\ndef compute_sum():\n    a = add_ints(1, 2)\n    b = add_ints(3, 4)\n    c = add_ints(5, 6)\n    return a + b + c\n\n\nresult = compute_sum()\nassert result == 21, 'multiple sequential ext calls in func'\n\n\ndef compute_nested():\n    return add_ints(add_ints(1, 2), add_ints(3, 4))\n\n\nresult = compute_nested()\nassert result == 10, 'nested ext calls in func'\n\n\ndef outer():\n    def inner():\n        return add_ints(10, 20)\n\n    return inner() + add_ints(1, 2)\n\n\nresult = outer()\nassert result == 33, 'ext call in nested func plus outer ext call'\n",
  'ext_call__name_lookup.py':
      "# call-external\n# Tests for NameLookup resolution with various value types.\n# Verifies that the host can inject non-function values (constants)\n# into the sandbox namespace via the NameLookup mechanism.\n\n# === Integer constant ===\nassert CONST_INT == 42, f'CONST_INT should be 42, got {CONST_INT}'\nassert CONST_INT + 8 == 50, 'CONST_INT arithmetic'\nassert type(CONST_INT) == int, f'CONST_INT type should be int, got {type(CONST_INT)}'\n\n# === String constant ===\nassert CONST_STR == 'hello', f'CONST_STR should be hello, got {CONST_STR}'\nassert CONST_STR + ' world' == 'hello world', 'CONST_STR concatenation'\nassert len(CONST_STR) == 5, f'CONST_STR length should be 5, got {len(CONST_STR)}'\nassert type(CONST_STR) == str, f'CONST_STR type should be str, got {type(CONST_STR)}'\n\n# === Float constant ===\nassert CONST_FLOAT == 3.14, f'CONST_FLOAT should be 3.14, got {CONST_FLOAT}'\nassert CONST_FLOAT + 0.86 == 4.0, 'CONST_FLOAT arithmetic'\nassert type(CONST_FLOAT) == float, f'CONST_FLOAT type should be float, got {type(CONST_FLOAT)}'\n\n# === Boolean constant ===\nassert CONST_BOOL == True, f'CONST_BOOL should be True, got {CONST_BOOL}'\nassert CONST_BOOL and True, 'CONST_BOOL in boolean expression'\nassert type(CONST_BOOL) == bool, f'CONST_BOOL type should be bool, got {type(CONST_BOOL)}'\n\n# === List constant ===\nassert CONST_LIST == [1, 2, 3], f'CONST_LIST should be [1, 2, 3], got {CONST_LIST}'\nassert len(CONST_LIST) == 3, f'CONST_LIST length should be 3, got {len(CONST_LIST)}'\nassert CONST_LIST[0] == 1, 'CONST_LIST first element'\nassert CONST_LIST[-1] == 3, 'CONST_LIST last element'\nassert type(CONST_LIST) == list, f'CONST_LIST type should be list, got {type(CONST_LIST)}'\n\n# === None constant ===\nassert CONST_NONE is None, f'CONST_NONE should be None, got {CONST_NONE}'\nassert type(CONST_NONE) == type(None), f'CONST_NONE type should be NoneType, got {type(CONST_NONE)}'\n\n# === Caching: same constant used twice should work ===\nx = CONST_INT\ny = CONST_INT\nassert x == y == 42, 'cached CONST_INT should be consistent'\n\n# === Mixed: constants and external functions in the same code ===\nresult = add_ints(CONST_INT, 8)\nassert result == 50, f'add_ints(CONST_INT, 8) should be 50, got {result}'\n\nstr_result = concat_strings(CONST_STR, ' world')\nassert str_result == 'hello world', f'concat with CONST_STR should be hello world, got {str_result}'\n\n# === Constants used in control flow ===\nif CONST_BOOL:\n    flag = 'yes'\nelse:\n    flag = 'no'\nassert flag == 'yes', f'CONST_BOOL in if should take true branch, got {flag}'\n\n# === Constants used in loops ===\ntotal = 0\nfor item in CONST_LIST:\n    total = total + item\nassert total == 6, f'sum of CONST_LIST should be 6, got {total}'\n\n\n# === Constants in function scope ===\ndef use_constant():\n    return CONST_INT * 2\n\n\nassert use_constant() == 84, f'CONST_INT in function should be 84, got {use_constant()}'\n",
  'ext_call__name_lookup_fn_01_bare_ref.py':
      "# call-external\n# First-class ext fn reference: bare assignment.\nfn = add_ints\n",
  'ext_call__name_lookup_fn_02_stored_type.py':
