  'ext_call__name_lookup_fn_06_conditional.py':
      "# call-external\n# First-class ext fn reference: in conditional expression.\nop = add_ints if True else add_ints\nresult = op(10, 5)\nassert result == 15, f'expected 15, got {result}'\n",
  'ext_call__name_lookup_fn_07_map_two_args_xfail.py':
      "# call-external\n# KNOWN UPSTREAM LIMITATION (pydantic/monty):\n# map() cannot suspend for external function calls.\n# When upstream adds support, this test will fail — remove Raise= directive.\nlist(map(add_ints, [1, 2, 3], [10, 20, 30]))\n# Raise=RuntimeError\n",
  'ext_call__name_lookup_fn_08_map_one_arg_xfail.py':
      "# call-external\n# KNOWN UPSTREAM LIMITATION (pydantic/monty):\n# map() cannot suspend for external function calls.\n# When upstream adds support, this test will fail — remove Raise= directive.\nlist(map(return_value, [1, 2, 3]))\n# Raise=RuntimeError\n",
  'ext_call__name_lookup_fn_09_user_fn_in_map.py':
      "# call-external\n# Control: map() with user-defined (pure Python) fn works fine.\n# Only external functions trip the upstream limitation.\ndef my_add(a, b):\n    return a + b\nresult = list(map(my_add, [1, 2, 3], [10, 20, 30]))\nassert result == [11, 22, 33], f'expected [11, 22, 33], got {result}'\n",
  'ext_call__name_lookup_fn_10_lambda_in_map_xfail.py':
      "# call-external\n# KNOWN UPSTREAM LIMITATION (pydantic/monty):\n# Wrapping an external function in a lambda does NOT escape the limitation —\n# the suspend point is still inside map()'s stack frame.\n# When upstream adds support, this test will fail — remove Raise= directive.\nlist(map(lambda x: add_ints(x, 100), [1, 2, 3]))\n# Raise=RuntimeError\n",
  'ext_call__name_lookup_undefined.py':
      "# call-external\n# When NameLookup returns Undefined for an unknown name, NameError is raised.\ntotally_unknown_name\n# Raise=NameError(\"name 'totally_unknown_name' is not defined\")\n",
  'ext_call__nested_calls.py':
      "# call-external\n# External calls in nested call expressions\n\n# Nested external calls - inner first\nresult = add_ints(add_ints(1, 2), 3)\nassert result == 6, 'nested ext calls'\n\n# Triple nested\nresult = add_ints(add_ints(add_ints(1, 1), 2), 3)\nassert result == 7, 'triple nested ext calls'\n\n# Two separate nested calls\nresult = add_ints(add_ints(1, 2), add_ints(3, 4))\nassert result == 10, 'two nested ext calls in args'\n",
  'ext_call__recursion_bug.py':
      "# call-external\n# BUG: External calls in recursive functions produce wrong results\n# Recursion with external calls doesn't compute the correct value\n\n\ndef sum_with_ext(n):\n    if n <= 0:\n        return 0\n    return add_ints(n, sum_with_ext(n - 1))\n\n\n# sum_with_ext(3) should compute:\n#   add_ints(3, sum_with_ext(2))\n#   add_ints(3, add_ints(2, sum_with_ext(1)))\n#   add_ints(3, add_ints(2, add_ints(1, sum_with_ext(0))))\n#   add_ints(3, add_ints(2, add_ints(1, 0)))\n#   = 3 + 2 + 1 = 6\nresult = sum_with_ext(3)\nassert result == 6, 'recursive ext call: 1+2+3=6'\n",
  'ext_call__return.py':
      "# call-external\n# External calls in return statements\n\n\ndef direct_return():\n    return add_ints(10, 20)\n\n\nresult = direct_return()\nassert result == 30, 'ext call as direct return value'\n\n\ndef return_with_expression():\n    return add_ints(1, 2) + add_ints(3, 4)\n\n\nresult = return_with_expression()\nassert result == 10, 'ext call expression as return value'\n\n\ndef conditional_return():\n    if return_value(True):\n        return add_ints(100, 200)\n    return add_ints(1, 1)\n\n\nresult = conditional_return()\nassert result == 300, 'ext call in conditional return'\n",
  'ext_call__side_effects.py':
      "# call-external\ndef log(msg):\n    print(msg)\n    return 1\n\n\ndef inner(x):\n    print('Inner called')\n    val = add_ints(x, 1)  # External call\n    print('Inner resumed')\n    return val\n\n\ndef outer():\n    print('Outer calling inner')\n    # If side effects are duplicated, we'll see \"Evaluating arg\" twice\n    res = inner(log('Evaluating arg'))\n    print('Outer returned')\n    return res\n\n\nprint('Starting')\nres = outer()\nprint(f'Result: {res}')\nassert res == 2\n",
  'ext_call__subscript.py':
      "# call-external\n# External calls in subscript operations\n\n# External call as subscript index\nitems = [10, 20, 30]\nresult = items[add_ints(0, 1)]\nassert result == 20, 'ext call as subscript index'\n",
  'ext_call__ternary.py':
      "# call-external\n# External calls in ternary expressions (if/else expressions)\n\n# External call in true branch\nresult = add_ints(1, 2) if True else add_ints(10, 20)\nassert result == 3, 'ext call in ternary true branch'\n\n# External call in false branch\nresult = add_ints(1, 2) if False else add_ints(10, 20)\nassert result == 30, 'ext call in ternary false branch'\n\n# External call in condition\nresult = 'yes' if return_value(True) else 'no'\nassert result == 'yes', 'ext call in ternary condition (true)'\n\nresult = 'yes' if return_value(False) else 'no'\nassert result == 'no', 'ext call in ternary condition (false)'\n\n# External calls in both branches\nresult = add_ints(1, 2) if return_value(True) else add_ints(10, 20)\nassert result == 3, 'ext call in condition and true branch'\n\nresult = add_ints(1, 2) if return_value(False) else add_ints(10, 20)\nassert result == 30, 'ext call in condition and false branch'\n\n# Nested ternary with external calls\nresult = add_ints(1, 1) if return_value(True) else (add_ints(2, 2) if return_value(False) else add_ints(3, 3))\nassert result == 2, 'nested ternary with ext calls'\n",
  'ext_call__try.py':
      "# call-external\n# === External calls in try blocks ===\n\n# Basic external call in try body\nresult = None\ntry:\n    result = add_ints(10, 20)\nexcept:\n    result = -1\nassert result == 30, 'ext call in try body'\n\n# Multiple external calls in try body\ntry:\n    a = add_ints(1, 2)\n    b = add_ints(3, 4)\n    c = add_ints(a, b)\nexcept:\n    c = -1\nassert c == 10, 'multiple ext calls in try body'\n\n# Nested external calls in try body\ntry:\n    nested = add_ints(add_ints(1, 2), add_ints(3, 4))\nexcept:\n    nested = -1\nassert nested == 10, 'nested ext calls in try body'\n\n# === External calls in except blocks ===\n\n# External call in except handler\nhandler_result = None\ntry:\n    raise ValueError('error')\nexcept ValueError:\n    handler_result = add_ints(100, 200)\nassert handler_result == 300, 'ext call in except handler'\n\n# Multiple external calls in except handler\ntry:\n    raise TypeError('error')\nexcept TypeError:\n    x = add_ints(5, 5)\n    y = add_ints(10, 10)\n    handler_sum = add_ints(x, y)\nassert handler_sum == 30, 'multiple ext calls in except handler'\n\n# External call with exception variable\nexc_with_ext = None\ntry:\n    raise ValueError('test')\nexcept ValueError as e:\n    prefix = concat_strings('caught: ', repr(e))\n    exc_with_ext = prefix\nassert exc_with_ext == \"caught: ValueError('test')\", 'ext call with exception variable'\n\n# === External calls in else blocks ===\n\n# External call in else block\nelse_result = None\ntry:\n    x = 1  # No exception\nexcept:\n    else_result = -1\nelse:\n    else_result = add_ints(50, 50)\nassert else_result == 100, 'ext call in else block'\n\n# Multiple external calls in else block\ntry:\n    pass\nexcept:\n    else_multi = -1\nelse:\n    p = add_ints(1, 2)\n    q = add_ints(3, 4)\n    else_multi = add_ints(p, q)\nassert else_multi == 10, 'multiple ext calls in else block'\n\n# === External calls in finally blocks ===\n\n# External call in finally block\nfinally_result = None\ntry:\n    x = 1\nfinally:\n    finally_result = add_ints(25, 75)\nassert finally_result == 100, 'ext call in finally block'\n\n# Finally with external call after exception caught\nfinally_after_exc = None\ntry:\n    raise ValueError('error')\nexcept ValueError:\n    pass\nfinally:\n    finally_after_exc = add_ints(1, 99)\nassert finally_after_exc == 100, 'ext call in finally after caught exception'\n\n# Multiple external calls in finally\ntry:\n    pass\nfinally:\n    f1 = add_ints(10, 20)\n    f2 = add_ints(30, 40)\n    finally_multi = add_ints(f1, f2)\nassert finally_multi == 100, 'multiple ext calls in finally block'\n\n# === External calls across multiple phases ===\n\n# External calls in try, except, and finally\nall_phases = []\ntry:\n    all_phases.append(add_ints(1, 0))  # 1\n    raise ValueError('error')\nexcept ValueError:\n    all_phases.append(add_ints(2, 0))  # 2\nfinally:\n    all_phases.append(add_ints(3, 0))  # 3\nassert all_phases == [1, 2, 3], 'ext calls in try, except, and finally'\n\n# External calls in try, else, and finally (no exception)\nno_exc_phases = []\ntry:\n    no_exc_phases.append(add_ints(10, 0))  # 10\nexcept:\n    no_exc_phases.append(-1)\nelse:\n    no_exc_phases.append(add_ints(20, 0))  # 20\nfinally:\n    no_exc_phases.append(add_ints(30, 0))  # 30\nassert no_exc_phases == [10, 20, 30], 'ext calls in try, else, and finally'\n\n# === External calls in nested try blocks ===\n\n# Nested try with external calls at each level\nouter_val = None\ninner_val = None\ntry:\n    outer_val = add_ints(100, 0)\n    try:\n        inner_val = add_ints(200, 0)\n        raise ValueError('inner')\n    except ValueError:\n        inner_val = add_ints(inner_val, 50)\nexcept:\n    outer_val = -1\nassert outer_val == 100, 'ext call in outer try'\nassert inner_val == 250, 'ext call in inner try and handler'\n\n# === External calls in exception type expression ===\n# (Exception type is evaluated at handler matching time)\n\n# External call producing value used after try\npost_try = None\ntry:\n    pre = add_ints(5, 5)\nexcept:\n    pre = -1\npost_try = add_ints(pre, 10)\nassert post_try == 20, 'ext call result used after try block'\n\n# === External call in finally with unhandled exception ===\n# Finally should still run even when exception propagates\nfinally_with_propagate = None\ntry:\n    try:\n        finally_with_propagate = add_ints(0, 0)  # Initialize\n        raise KeyError('unhandled')\n    except ValueError:\n        pass  # Won't catch KeyError\n    finally:\n        finally_with_propagate = add_ints(42, 0)  # Should still run\nexcept KeyError:\n    pass  # Catch propagated exception\nassert finally_with_propagate == 42, 'ext call in finally should run even with unhandled exception'\n\n# === External call in except handler that then raises ===\nhandler_before_raise = None\ntry:\n    try:\n        raise ValueError('original')\n    except ValueError:\n        handler_before_raise = add_ints(10, 0)  # External call before raising\n        raise TypeError('from handler')\nexcept TypeError:\n    pass\nassert handler_before_raise == 10, 'ext call in handler before raising'\n\n# === External call in else block that then raises ===\nelse_before_raise = None\ntry:\n    try:\n        pass  # No exception\n    except:\n        pass\n    else:\n        else_before_raise = add_ints(20, 0)  # External call before raising\n        raise ValueError('from else')\nexcept ValueError:\n    pass\nassert else_before_raise == 20, 'ext call in else before raising'\n\n# === External call preserves state across try/except ===\nstate_before = add_ints(1000, 0)\nstate_after = None\ntry:\n    state_after = add_ints(state_before, 1)\n    raise ValueError('test')\nexcept ValueError:\n    state_after = add_ints(state_after, 10)\nfinally:\n    state_after = add_ints(state_after, 100)\nassert state_after == 1111, 'state preserved across try/except with ext calls'\n\n# === Multiple except handlers with external calls ===\nwhich_handler = None\ntry:\n    raise TypeError('test')\nexcept ValueError:\n    which_handler = add_ints(1, 0)\nexcept TypeError:\n    which_handler = add_ints(2, 0)\nexcept KeyError:\n    which_handler = add_ints(3, 0)\nassert which_handler == 2, 'ext call in correct handler with multiple handlers'\n\n# === External call in finally with pending exception (after handler raises) ===\nfinally_after_handler_raise = None\ntry:\n    try:\n        raise ValueError('original')\n    except ValueError:\n        finally_after_handler_raise = add_ints(10, 0)  # External call before raising\n        raise TypeError('from handler')\n    finally:\n        # This external call should work even though there's a pending exception\n        finally_after_handler_raise = add_ints(finally_after_handler_raise, 5)\nexcept TypeError:\n    pass\nassert finally_after_handler_raise == 15, 'ext call in finally with pending exception from handler'\n\n# === External call in finally with pending exception (no matching handler) ===\nfinally_with_pending_exc = None\ntry:\n    try:\n        finally_with_pending_exc = add_ints(0, 0)\n        raise KeyError('no handler')\n    except ValueError:\n        pass  # Won't catch KeyError\n    finally:\n        # This external call should work even though KeyError is pending\n        finally_with_pending_exc = add_ints(100, 0)\nexcept KeyError:\n    pass  # Catch it here\nassert finally_with_pending_exc == 100, 'ext call in finally with unhandled exception pending'\n\n# === External call in finally with return (uses simple values) ===\n# Note: External calls in user-defined functions are not supported,\n# so we test pending return with built-in operations only\nfinally_return_result = None\ntry:\n    finally_return_result = 'in_try'\nfinally:\n    pass  # finally runs but doesn't override\nassert finally_return_result == 'in_try', 'finally runs with pending value'\n\n# === Multiple external calls in finally with pending exception ===\nmulti_finally = None\ntry:\n    try:\n        raise ValueError('test')\n    except TypeError:\n        pass  # Won't match\n    finally:\n        a = add_ints(1, 2)\n        b = add_ints(3, 4)\n        multi_finally = add_ints(a, b)\nexcept ValueError:\n    pass\nassert multi_finally == 10, 'multiple ext calls in finally with pending exception'\n",
  'ext_call__try_simple.py':
      "# call-external\n# Test external call with exception variable\n\nexc_with_ext = None\ntry:\n    raise ValueError('test')\nexcept ValueError as e:\n    prefix = concat_strings('caught: ', repr(e))\n    exc_with_ext = prefix\nassert exc_with_ext == \"caught: ValueError('test')\", 'ext call with exception variable'\n",
  'ext_call__unary.py':
      "# call-external\n# External calls in unary expressions\n\n# Negation of external call result\nresult = -add_ints(3, 4)\nassert result == -7, 'negation of ext call'\n\n# Not of external call\nresult = not return_value(False)\nassert result == True, 'not of ext call returning False'\n\nresult = not return_value(True)\nassert result == False, 'not of ext call returning True'\n",
  'frozenset__ops.py':
      "# === Construction ===\nfs = frozenset()\nassert len(fs) == 0, 'empty frozenset len'\nassert fs == frozenset(), 'empty frozenset equality'\n\nfs = frozenset([1, 2, 3])\nassert len(fs) == 3, 'frozenset from list len'\n\n# === Copy ===\nfs = frozenset([1, 2, 3])\nfs2 = fs.copy()\nassert fs == fs2, 'copy equality'\n\n# === Union ===\nfs1 = frozenset([1, 2])\nfs2 = frozenset([2, 3])\nu = fs1.union(fs2)\nassert len(u) == 3, 'union len'\n\n# === Intersection ===\nfs1 = frozenset([1, 2, 3])\nfs2 = frozenset([2, 3, 4])\ni = fs1.intersection(fs2)\nassert len(i) == 2, 'intersection len'\n\n# === Difference ===\nfs1 = frozenset([1, 2, 3])\nfs2 = frozenset([2, 3, 4])\nd = fs1.difference(fs2)\nassert len(d) == 1, 'difference len'\n\n# === Symmetric Difference ===\nfs1 = frozenset([1, 2, 3])\nfs2 = frozenset([2, 3, 4])\nsd = fs1.symmetric_difference(fs2)\nassert len(sd) == 2, 'symmetric_difference len'\n\n# === Binary operators ===\nfs = frozenset([1, 2])\nother_fs = frozenset([2, 3])\ns = {2, 3}\n\nassert fs & other_fs == frozenset([2]), 'frozenset & frozenset works'\nassert fs | other_fs == frozenset([1, 2, 3]), 'frozenset | frozenset works'\nassert fs ^ other_fs == frozenset([1, 3]), 'frozenset ^ frozenset works'\nassert fs - other_fs == frozenset([1]), 'frozenset - frozenset works'\n\nassert fs & s == frozenset([2]), 'frozenset & set works'\nassert fs | s == frozenset([1, 2, 3]), 'frozenset | set works'\nassert fs ^ s == frozenset([1, 3]), 'frozenset ^ set works'\nassert fs - s == frozenset([1]), 'frozenset - set works'\n\nkeys = {'a': 1, 'b': 2}.keys()\nitems = {'a': 1, 'b': 2}.items()\nassert frozenset({'a'}) & keys == frozenset({'a'}), 'frozenset & dict_keys works'\nassert frozenset({'a'}) | keys == frozenset({'a', 'b'}), 'frozenset | dict_keys works'\nassert frozenset({('a', 1)}) ^ items == frozenset({('b', 2)}), 'frozenset ^ dict_items works'\nassert frozenset({('a', 1), ('b', 2)}) - items == frozenset(), 'frozenset - dict_items works'\n\nassert type(fs | s).__name__ == 'frozenset', 'frozenset operators keep the left operand type'\n\ntry:\n    fs & [1, 2]\n    assert False, 'frozenset operators reject non-set rhs'\nexcept TypeError as e:\n    assert str(e) == \"unsupported operand type(s) for &: 'frozenset' and 'list'\", (\n        'frozenset & rhs error matches CPython'\n    )\n\n# === Issubset ===\nfs1 = frozenset([1, 2])\nfs2 = frozenset([1, 2, 3])\nassert fs1.issubset(fs2) == True, 'issubset true'\nassert fs2.issubset(fs1) == False, 'issubset false'\n\n# === Issuperset ===\nfs1 = frozenset([1, 2, 3])\nfs2 = frozenset([1, 2])\nassert fs1.issuperset(fs2) == True, 'issuperset true'\nassert fs2.issuperset(fs1) == False, 'issuperset false'\n\n# === Isdisjoint ===\nfs1 = frozenset([1, 2])\nfs2 = frozenset([3, 4])\nfs3 = frozenset([2, 3])\nassert fs1.isdisjoint(fs2) == True, 'isdisjoint true'\nassert fs1.isdisjoint(fs3) == False, 'isdisjoint false'\n\n# === Bool ===\nassert bool(frozenset()) == False, 'empty frozenset is falsy'\nassert bool(frozenset([1])) == True, 'non-empty frozenset is truthy'\n\n# === repr ===\nassert repr(frozenset()) == 'frozenset()', 'empty frozenset repr'\n\n# === Hashing ===\nfs = frozenset([1, 2, 3])\nh = hash(fs)\nassert isinstance(h, int), 'frozenset hash is int'\n\n# Same elements should have same hash\nfs1 = frozenset([1, 2, 3])\nfs2 = frozenset([3, 2, 1])  # Different order\nassert hash(fs1) == hash(fs2), 'frozenset hash is order-independent'\n\n# === As dict key ===\nd = {}\nfs = frozenset([1, 2])\nd[fs] = 'value'\nassert d[fs] == 'value', 'frozenset as dict key'\nassert d[frozenset([2, 1])] == 'value', 'frozenset key lookup order-independent'\n\n# === Construction from various iterables ===\nfs = frozenset('abc')\nassert len(fs) == 3, 'frozenset from string len'\nassert 'a' in fs and 'b' in fs and 'c' in fs, 'frozenset from string elements'\n\nfs = frozenset((1, 2, 3))\nassert fs == frozenset({1, 2, 3}), 'frozenset from tuple'\n\nfs = frozenset(range(5))\nassert fs == frozenset({0, 1, 2, 3, 4}), 'frozenset from range'\n\nfs = frozenset({1, 2, 3})\nassert len(fs) == 3, 'frozenset from set'\n\n# === Containment (in / not in) ===\nfs = frozenset({1, 2, 3})\nassert 1 in fs, 'in frozenset positive'\nassert 4 not in fs, 'not in frozenset'\nassert 'x' not in frozenset({'a', 'b'}), 'not in frozenset strings'\n\n# === Iteration ===\nresult = []\nfor x in frozenset({1, 2, 3}):\n    result.append(x)\nassert len(result) == 3, 'frozenset iteration length'\nassert set(result) == {1, 2, 3}, 'frozenset iteration elements'\n\nresult = []\nfor x in frozenset():\n    result.append(x)\nassert result == [], 'empty frozenset iteration'\n\n# === Inequality (!=) ===\nassert frozenset({1, 2}) != frozenset({1, 3}), 'frozenset ne different'\nassert not (frozenset({1, 2}) != frozenset({1, 2})), 'frozenset ne same'\n\n# === Methods accepting iterables ===\nassert frozenset({1, 2}).union([3, 4]) == frozenset({1, 2, 3, 4}), 'union with list arg'\nassert frozenset({1, 2, 3}).intersection([2, 3, 4]) == frozenset({2, 3}), 'intersection with list arg'\nassert frozenset({1, 2, 3}).difference([2]) == frozenset({1, 3}), 'difference with list arg'\nassert frozenset({1, 2}).symmetric_difference([2, 3]) == frozenset({1, 3}), 'symmetric_difference with list arg'\nassert frozenset({1}).union(range(3)) == frozenset({0, 1, 2}), 'union with range arg'\nassert frozenset({1}).union((2, 3)) == frozenset({1, 2, 3}), 'union with tuple arg'\n\n# === issubset/issuperset/isdisjoint with non-set iterables ===\nfs = frozenset({1, 2, 3})\nassert fs.issubset(range(10)), 'issubset with range'\nassert fs.issuperset([1, 2]), 'issuperset with list'\nassert fs.isdisjoint([4, 5, 6]), 'isdisjoint with list'\nassert not fs.isdisjoint([3, 4]), 'not isdisjoint with list'\n\n# === Different hashes for different frozensets ===\nfs1 = frozenset({1, 2})\nfs2 = frozenset({3, 4})\n# Not guaranteed to be different, but very likely\n# Instead just verify they're integers and stable\nassert hash(fs1) == hash(frozenset({2, 1})), 'hash stable across order'\nassert hash(frozenset()) == hash(frozenset()), 'empty frozenset hash stable'\n\n# === Frozenset as set element ===\ns = {frozenset({1, 2}), frozenset({3, 4})}\nassert len(s) == 2, 'set of frozensets'\nassert frozenset({1, 2}) in s, 'frozenset element lookup'\n# Duplicate frozenset should dedup\ns2 = {frozenset({1}), frozenset({1})}\nassert len(s2) == 1, 'duplicate frozensets dedup in set'\n",
  'fstring__all.py':
      "# === Basic f-strings ===\nassert f'hello' == 'hello', 'basic f-string'\nassert f'' == '', 'empty f-string'\n\n# === Simple interpolation ===\nx = 'world'\nassert f'hello {x}' == 'hello world', 'simple interpolation'\n\n# multiple interpolations\na = 1\nb = 2\nassert f'{a} + {b} = {a + b}' == '1 + 2 = 3', 'multiple interpolations'\n\n# expression in f-string\nassert f'{1 + 2 + 3}' == '6', 'expression'\n\n# === Value types ===\n# list value\nx = [1, 2, 3]\nassert f'list: {x}' == 'list: [1, 2, 3]', 'list value'\n\n# bool value\nx = True\nassert f'value: {x}' == 'value: True', 'bool value'\n\n# int value\nassert f'{42}' == '42', 'int value'\n\n# float value\nassert f'{3.14}' == '3.14', 'float value'\n\n# None value\nassert f'{None}' == 'None', 'None value'\n\n# === Conversion flags (!s, !r, !a) ===\n# conversion !s (str)\nassert f'{42!s}' == '42', 'conversion !s'\n\n# conversion !r (repr)\nassert f'{\"hello\"!r}' == \"'hello'\", 'conversion !r'\n\n# conversion !r on int (should be same as str for int)\nassert f'{42!r}' == '42', 'conversion !r on int'\n\n# conversion !r on list\nassert f'{[1, 2]!r}' == '[1, 2]', 'conversion !r on list'\n\n# conversion !s on string (no quotes)\nassert f'{\"hello\"!s}' == 'hello', 'conversion !s on string'\n\n# conversion !a (ascii) - escapes non-ASCII characters\nassert f'{\"café\"!a}' == \"'caf\\\\xe9'\", 'conversion !a'\nassert f'{\"hello\"!a}' == \"'hello'\", 'conversion !a ascii only'\nassert f'{\"日本\"!a}' == \"'\\\\u65e5\\\\u672c'\", 'conversion !a unicode'\n\n# === String padding and alignment ===\n# format spec: width (left-aligned by default for strings)\nassert f'{\"hi\":10}' == 'hi        ', 'format width'\n\n# format spec: left align\nassert f'{\"hi\":<10}' == 'hi        ', 'format left align'\n\n# format spec: right align\nassert f'{\"hi\":>10}' == '        hi', 'format right align'\n\n# format spec: center align\nassert f'{\"hi\":^10}' == '    hi    ', 'format center align'\n\n# center align with odd padding\nassert f'{\"zip\":^6}' == ' zip  ', 'format center align odd'\n\n# format spec: fill character\nassert f'{\"hi\":*>10}' == '********hi', 'format fill right'\nassert f'{\"hi\":_<10}' == 'hi________', 'format fill left'\nassert f'{\"hi\":*^10}' == '****hi****', 'format fill center'\n\n# string truncation with precision\nassert f'{\"xylophone\":.5}' == 'xylop', 'string truncation'\nassert f'{\"xylophone\":10.5}' == 'xylop     ', 'string truncation with width'\n\n# === Integer formatting ===\n# basic integer\nassert f'{42}' == '42', 'basic integer'\n\n# integer with :d type\nassert f'{42:d}' == '42', 'integer :d'\n\n# integer padding\nassert f'{42:4d}' == '  42', 'integer padding'\nassert f'{42:04d}' == '0042', 'integer zero padding'\n\n# integer with sign\nassert f'{42:+d}' == '+42', 'integer positive sign'\nassert f'{42: d}' == ' 42', 'integer space for positive'\nassert f'{-42:+d}' == '-42', 'integer negative with sign'\nassert f'{-42: d}' == '-42', 'integer negative space'\n\n# sign-aware padding\nassert f'{-23:=5d}' == '-  23', 'sign-aware padding'\n\n# === Float formatting ===\n# basic float\nassert f'{3.14159}' == '3.14159', 'basic float'\n\n# float with :f type\nassert f'{3.141592653589793:f}' == '3.141593', 'float :f'\n\n# float precision\nassert f'{3.141592653589793:.2f}' == '3.14', 'float precision'\nassert f'{3.141592653589793:.4f}' == '3.1416', 'float precision 4'\n\n# float width and precision\nassert f'{3.141592653589793:06.2f}' == '003.14', 'float zero pad with precision'\nassert f'{3.141592653589793:10.2f}' == '      3.14', 'float width with precision'\n\n# float with sign\nassert f'{3.14:+.2f}' == '+3.14', 'float positive sign'\nassert f'{-3.14:+.2f}' == '-3.14', 'float negative with sign'\nassert f'{3.14:-.2f}' == '3.14', 'float explicit minus sign'\nassert f'{-3.14:-.2f}' == '-3.14', 'float explicit minus sign negative'\n\n# exponential notation\nassert f'{1234.5678:e}' == '1.234568e+03', 'exponential lowercase'\nassert f'{1234.5678:E}' == '1.234568E+03', 'exponential uppercase'\nassert f'{1234.5678:.2e}' == '1.23e+03', 'exponential with precision'\nassert f'{0.00012345:.2e}' == '1.23e-04', 'exponential small number'\n\n# general format (g/G) - uses exponential for very large/small numbers\nassert f'{1.5:g}' == '1.5', 'general format simple'\nassert f'{1.500:g}' == '1.5', 'general format strips trailing zeros'\nassert f'{1234567890:g}' == '1.23457e+09', 'general format large number'\n\n# percentage\nassert f'{0.25:%}' == '25.000000%', 'percentage default precision'\nassert f'{0.25:.1%}' == '25.0%', 'percentage with precision'\nassert f'{0.125:.0%}' == '12%', 'percentage zero precision'\n\n# === Nested format specs ===\nwidth = 10\nassert f'{\"hi\":{width}}' == 'hi        ', 'nested format spec width'\n\n# nested alignment and width\nalign = '^'\nassert f'{\"test\":{align}{width}}' == '   test   ', 'nested align and width'\n\n# nested precision\nprec = 3\nassert f'{\"xylophone\":.{prec}}' == 'xyl', 'nested precision'\n\n\n# === f-string in function ===\ndef greet(name):\n    return f'Hello, {name}!'\n\n\nassert greet('World') == 'Hello, World!', 'f-string in function'\n\n\n# function returning formatted value\ndef format_num(n, w):\n    return f'{n:>{w}}'\n\n\nassert format_num('x', 5) == '    x', 'f-string with params'\n\n# === Escaping ===\n# double braces to escape\nassert f'{{}}' == '{}', 'escaped braces'\nassert f'{{x}}' == '{x}', 'escaped braces with content'\nassert f'{{{42}}}' == '{42}', 'value inside escaped braces'\n\n# === Complex expressions ===\n# TODO: method call on literal - parser doesn't support this yet\n# assert f'{\"hello\".upper()}' == 'HELLO', 'method call on literal'\n\n# TODO: method call on variable - str.upper() not implemented yet\n# s = 'hello'\n# assert f'{s.upper()}' == 'HELLO', 'method call on variable'\n\n# subscript in f-string\nlst = [10, 20, 30]\nassert f'{lst[1]}' == '20', 'subscript'\n\n# dict lookup\nd = {'a': 1, 'b': 2}\nassert f'{d[\"a\"]}' == '1', 'dict lookup'\n\n# TODO: conditional expression - parser doesn't support IfExp yet\n# x = 5\n# assert f'{x if x > 0 else -x}' == '5', 'conditional positive'\n# x = -5\n# assert f'{-x if x < 0 else x}' == '5', 'conditional negative'\n\n# === String concatenation ===\nname = 'world'\n# regular string + f-string (implicit concatenation)\nassert f'hello {name}' == 'hello world', 'str concat with fstring'\n\n# === Empty interpolation expression ===\n# (this should be a syntax error, but test current behavior)\n# assert f'{}' would be syntax error\n\n# === Whitespace in format spec ===\n# no extra whitespace handling needed, width handles it\nassert f'{\"x\":5}' == 'x    ', 'single char width'\n\n# === Unicode character counting in padding ===\nx = 'café'\nassert f'{x:_<10}' == 'café______'\nassert f'{x:_>10}' == '______café'\nassert f'{x:_^10}' == '___café___'\nassert f'{x:_^11}' == '___café____'\nassert f'{x:é<10}' == 'cafééééééé'\nassert f'{x:é>10}' == 'éééééécafé'\nassert f'{x:é^10}' == 'ééécaféééé'\nassert f'{x:é^11}' == 'ééécafééééé'\n\n# === Conversion flag with type spec ===\n# conversion flag produces string, so 's' format should work\nassert f'{42!r:s}' == '42', 'conversion with type spec'\n\n# === Zero-padding with negative numbers ===\n# zero-padding should use sign-aware alignment\nx = -42\nassert f'{x:05d}' == '-0042', 'zero pad negative'\n\n# === Debug/self-documenting expressions (=) ===\na = 42\nassert f'{a=}' == 'a=42', 'basic debug expression'\nassert f'{a = }' == 'a = 42', 'debug with spaces'\nname = 'test'\nassert f'{name=}' == \"name='test'\", 'debug uses repr for strings'\nassert f'{name = }' == \"name = 'test'\", 'debug uses repr for strings'\nassert f'{name=!s}' == 'name=test', 'debug with !s conversion'\nassert f'{name=!r}' == \"name='test'\", 'debug with !r conversion'\nassert f'{1+1=}' == '1+1=2', 'debug with expression'\n",
