  'function__kwargs_unpacking.py':
      "# === Basic **kwargs unpacking ===\ndef greet(name, greeting):\n    return f'{greeting}, {name}!'\n\n\nopts = {'greeting': 'Hi'}\nassert greet('Alice', **opts) == 'Hi, Alice!', 'basic **kwargs unpacking'\n\n# === Dict literal unpacking ===\nassert greet('Charlie', **{'greeting': 'Hey'}) == 'Hey, Charlie!', 'dict literal unpacking'\n\n\n# === Multiple kwargs in unpacked dict ===\ndef format_msg(msg, prefix, suffix):\n    return f'{prefix}{msg}{suffix}'\n\n\nassert format_msg('test', **{'prefix': '[', 'suffix': ']'}) == '[test]', 'multiple kwargs unpacking'\n\n# === Combining regular kwargs with **kwargs ===\nassert format_msg('hello', prefix='> ', **{'suffix': '!'}) == '> hello!', 'regular kwargs with **kwargs'\n\n\n# === **kwargs with positional args ===\ndef add_all(a, b, c):\n    return a + b + c\n\n\nassert add_all(1, 2, **{'c': 3}) == 6, '**kwargs with positional args'\nassert add_all(1, **{'b': 2, 'c': 3}) == 6, '**kwargs providing multiple args'\n\n# === Variable dict unpacking ===\nsettings = {'prefix': '>>> ', 'suffix': ' <<<'}\nassert format_msg('output', **settings) == '>>> output <<<', 'variable dict unpacking'\n\n\n# === Unpacking with keyword-only args ===\ndef kwonly_func(a, *, b, c):\n    return a + b + c\n\n\nassert kwonly_func(1, **{'b': 2, 'c': 3}) == 6, '**kwargs with keyword-only args'\n\n\n# === Empty dict unpacking with all args provided ===\ndef simple(x, y):\n    return x + y\n\n\nassert simple(1, 2, **{}) == 3, 'empty dict unpacking'\n\n\n# === All kwargs from unpacking ===\ndef all_kwargs(a, b, c):\n    return a * 100 + b * 10 + c\n\n\nassert all_kwargs(**{'a': 1, 'b': 2, 'c': 3}) == 123, 'all args from **kwargs'\nassert all_kwargs(**{'c': 7, 'a': 4, 'b': 5}) == 457, 'all args from **kwargs different order'\n\n\n# === Dynamic **kwargs keys ===\ndef kwonly_echo(*, keyword):\n    return keyword\n\n\nkey_name = 'k' + 'e' + 'y' + 'w' + 'o' + 'r' + 'd'\nassert kwonly_echo(**{key_name: 'dynamic'}) == 'dynamic', 'runtime string key matches kw-only param'\n\n\n# ============================================================\n# *args unpacking tests (function calls)\n# ============================================================\n\n\n# === *args with zero args ===\ndef no_args():\n    return 'ok'\n\n\nassert no_args(*[]) == 'ok', '*args with empty list'\nassert no_args(*()) == 'ok', '*args with empty tuple'\n\n\n# === *args with one arg ===\ndef one_arg(x):\n    return x * 2\n\n\nassert one_arg(*[5]) == 10, '*args with one item list'\nassert one_arg(*(7,)) == 14, '*args with one item tuple'\n\n\n# === *args with two args ===\ndef two_args(a, b):\n    return a + b\n\n\nassert two_args(*[1, 2]) == 3, '*args with two item list'\nassert two_args(*(3, 4)) == 7, '*args with two item tuple'\n\n\n# === *args with three+ args ===\ndef many_args(a, b, c, d):\n    return a + b + c + d\n\n\nassert many_args(*[1, 2, 3, 4]) == 10, '*args with four items'\nassert many_args(*(10, 20, 30, 40)) == 100, '*args with tuple four items'\n\n\n# === Mixed positional and *args ===\nassert two_args(1, *[2]) == 3, 'pos + *args'\nassert many_args(1, 2, *[3, 4]) == 10, 'two pos + *args'\n\n\n# === *args with heap-allocated values ===\ndef list_arg(lst):\n    return len(lst)\n\n\nmy_list = [1, 2, 3]\nassert list_arg(*[my_list]) == 3, '*args with list value'\n\n\n# ============================================================\n# Combined *args and **kwargs (function calls)\n# ============================================================\n\n\n# === *args and **kwargs together ===\ndef mixed_func(a, b, c):\n    return f'{a}-{b}-{c}'\n\n\nassert mixed_func(*[1], **{'b': 2, 'c': 3}) == '1-2-3', '*args and **kwargs'\nassert mixed_func(*[1, 2], **{'c': 3}) == '1-2-3', 'two *args and **kwargs'\n\n\n# === *args tuple with **kwargs ===\nargs_tuple = (10, 20)\nkwargs_dict = {'c': 30}\nassert many_args(*args_tuple, **kwargs_dict, d=40) == 100, '*args tuple + **kwargs + regular kwarg'\n\n\n# === Empty *args with **kwargs ===\nassert mixed_func(*[], **{'a': 'x', 'b': 'y', 'c': 'z'}) == 'x-y-z', 'empty *args with **kwargs'\n\n\n# === *args with empty **kwargs ===\nassert two_args(*[5, 6], **{}) == 11, '*args with empty **kwargs'\n\n\n# === All combinations: pos, *args, kwargs, **kwargs ===\ndef full_func(a, b, c, d):\n    return a * 1000 + b * 100 + c * 10 + d\n\n\nassert full_func(1, *[2], c=3, **{'d': 4}) == 1234, 'pos + *args + kwarg + **kwargs'\n\n\n# === *args with heap values and **kwargs ===\ndef heap_func(lst, dct):\n    return len(lst) + len(dct)\n\n\nlist_val = [1, 2, 3]\ndict_val = {'a': 1}\nassert heap_func(*[list_val], **{'dct': dict_val}) == 4, '*args and **kwargs with heap values'\n\n\n# === Both *args and **kwargs empty ===\nassert no_args(*[], **{}) == 'ok', 'empty *args and empty **kwargs'\n",
  'function__ops.py':
      "# === Basic function calls ===\ndef f_no_args():\n    return 1\n\n\nassert f_no_args() == 1, 'no args'\n\n\ndef f_one_arg(x):\n    return x\n\n\nassert f_one_arg(42) == 42, 'one arg'\n\n\ndef add(a, b):\n    return a + b\n\n\nassert add(1, 2) == 3, 'two args'\n\n\ndef sum3(a, b, c):\n    return a + b + c\n\n\nassert sum3(1, 2, 3) == 6, 'three args'\n\n\n# === Local variables ===\ndef f_local():\n    x = 42\n    return x\n\n\nassert f_local() == 42, 'local var'\n\n\ndef f_local_from_arg(x):\n    y = x + 1\n    return y\n\n\nassert f_local_from_arg(10) == 11, 'local var from arg'\n\n\ndef f_local_list():\n    items = [1, 2, 3]\n    return items\n\n\nassert f_local_list() == [1, 2, 3], 'local var list'\n\n\ndef f_local_modify_list():\n    items = [1, 2]\n    items.append(3)\n    return items\n\n\nassert f_local_modify_list() == [1, 2, 3], 'local var modify list'\n\n\ndef f_local_multiple():\n    a = 1\n    b = 2\n    c = 3\n    return a + b + c\n\n\nassert f_local_multiple() == 6, 'local var multiple'\n\n\ndef f_local_reassign():\n    x = 1\n    x = 2\n    x = 3\n    return x\n\n\nassert f_local_reassign() == 3, 'local var reassign'\n\n\n# === Nested functions ===\ndef nested_basic():\n    def bar():\n        return 1\n\n    return bar() + 1\n\n\nassert nested_basic() == 2, 'nested basic'\n\n\ndef nested_deep():\n    def level2():\n        def level3():\n            return 42\n\n        return level3()\n\n    return level2()\n\n\nassert nested_deep() == 42, 'nested deep'\n\n\ndef nested_multiple_calls():\n    def inner():\n        return 10\n\n    return inner() + inner() + inner()\n\n\nassert nested_multiple_calls() == 30, 'nested multiple calls'\n\n\ndef nested_two_inner():\n    def add():\n        return 1\n\n    def sub():\n        return 2\n\n    return add() + sub()\n\n\nassert nested_two_inner() == 3, 'nested two inner'\n\n\ndef nested_with_args(x):\n    def inner(y):\n        return y + y\n\n    return inner(x) + 1\n\n\nassert nested_with_args(5) == 11, 'nested with args'\n\n\n# === Function equality ===\ndef eq_test():\n    return 1\n\n\ndef eq_test2():\n    return 1\n\n\n# Same function is equal to itself\nassert eq_test == eq_test, 'function equals itself'\nassert not (eq_test != eq_test), 'function not-not-equals itself'\n\n# Different functions are not equal (even with same body)\nassert not (eq_test == eq_test2), 'different functions not equal'\nassert eq_test != eq_test2, 'different functions are not equal'\n\n# Function assigned to variable is still equal\nf_alias = eq_test\nassert f_alias == eq_test, 'function alias equals original'\nassert eq_test == f_alias, 'original equals function alias'\n\n\n# === Builtin equality ===\n# Same builtin is equal to itself\nassert len == len, 'builtin equals itself'\nassert print == print, 'print equals itself'\nassert not (len != len), 'builtin not-not-equals itself'\n\n# Builtin identity (is)\nassert print is print, 'print is print'\nassert len is len, 'len is len'\nassert not (len is print), 'len is not print'\n\n# Different builtins are not equal\nassert not (len == print), 'different builtins not equal'\nassert len != print, 'different builtins are not equal'\n\n# Builtin assigned to variable is still equal\nlen_alias = len\nassert len_alias == len, 'builtin alias equals original'\nassert len_alias is len, 'builtin alias is original'\n\n\n# === Exception type equality ===\n# Note: Using == instead of 'is' to explicitly test the __eq__ implementation\nassert ValueError == ValueError, 'exc type equals itself'\nassert TypeError == TypeError, 'exc type equals itself 2'\nassert not (ValueError != ValueError), 'exc type not-not-equals itself'\n\nassert not (ValueError == TypeError), 'different exc types not equal'\nassert ValueError != TypeError, 'different exc types are not equal'\n\nexc_alias = ValueError\nassert exc_alias == ValueError, 'exc type alias equals original'\n\n\n# === Closure equality ===\ndef make_adder(n):\n    def adder(x):\n        return x + n\n\n    return adder\n\n\nadd1 = make_adder(1)\nadd2 = make_adder(2)\nadd1_again = make_adder(1)\n\n# Same closure instance equals itself\nassert add1 == add1, 'closure equals itself'\nassert not (add1 != add1), 'closure not-not-equals itself'\n\n# Different closure instances are not equal (even with same captured value)\nassert not (add1 == add1_again), 'different closure instances not equal'\nassert add1 != add1_again, 'different closure instances are not equal'\n\n# Different closure instances with different captured values\nassert not (add1 == add2), 'closures with diff captured values not equal'\nassert add1 != add2, 'closures with diff captured values are not equal'\n\n\n# === Cross-type inequality ===\ndef cross_test():\n    return 1\n\n\nassert not (cross_test == len), 'function not equal to builtin'\nassert not (len == cross_test), 'builtin not equal to function'\nassert not (cross_test == ValueError), 'function not equal to exc type'\nassert not (ValueError == cross_test), 'exc type not equal to function'\nassert not (len == ValueError), 'builtin not equal to exc type'\nassert not (ValueError == len), 'exc type not equal to builtin'\n\n# Callables not equal to other types\nassert not (len == 1), 'builtin not equal to int'\nassert not (len == 'len'), 'builtin not equal to string'\nassert not (cross_test == None), 'function not equal to None'\nassert not (ValueError == None), 'exc type not equal to None'\n\n\n# === Parameter shadowing global variables ===\n# Function parameters should shadow global variables with the same name\nx = 5\n\n\ndef shadow_single(x):\n    return x + 1\n\n\n# When called with 10, param x=10 should be used, not global x=5\nassert shadow_single(10) == 11, 'param shadows global - single param'\n\ny = 3\n\n\ndef shadow_multiple(x, y):\n    return x + y\n\n\n# When called with (20, 30), params should be used, not globals x=5, y=3\nassert shadow_multiple(20, 30) == 50, 'param shadows global - multiple params'\n\n\ndef shadow_uses_global_too(x):\n    # x is param, y is global\n    return x + y\n\n\n# x=100 (param), y=3 (global), so 100 + 3 = 103\nassert shadow_uses_global_too(100) == 103, 'param shadows but can still access other globals'\n\n\ndef shadow_with_default(x=99):\n    return x + 1\n\n\n# When called with argument, param shadows global\nassert shadow_with_default(10) == 11, 'param with default shadows global'\n# When called without argument, default is used (not global)\nassert shadow_with_default() == 100, 'param default used, not global'\n\n\n# Global is still accessible outside the function\nassert x == 5, 'global still accessible after function that shadows it'\nassert y == 3, 'other global still accessible'\n\n\n# Verify global can still be used as argument\ndef double(x):\n    return x * 2\n\n\nassert double(x) == 10, 'global used as argument, param shadows inside'\n",
  'function__return_none.py':
      "# === Bare return statement ===\n# Test functions with bare return (no value)\n\n\ndef early_exit():\n    return\n\n\nassert early_exit() is None, 'bare return returns None'\n\n\ndef conditional_early_exit(x):\n    if x < 0:\n        return\n    return x * 2\n\n\nassert conditional_early_exit(-5) is None, 'conditional early return'\nassert conditional_early_exit(5) == 10, 'conditional normal return'\n\n\ndef multiple_bare_returns(x):\n    if x == 0:\n        return\n    if x == 1:\n        return\n    return x\n\n\nassert multiple_bare_returns(0) is None, 'first bare return'\nassert multiple_bare_returns(1) is None, 'second bare return'\nassert multiple_bare_returns(2) == 2, 'fall through to value return'\n\n\ndef nested_bare_return():\n    def inner():\n        return\n\n    return inner()\n\n\nassert nested_bare_return() is None, 'nested bare return'\n",
  'function__signatures.py':
      "# === Basic functions ===\ndef simple(a, b, c):\n    return a + b + c\n\n\nassert simple(1, 2, 3) == 6, 'simple function'\nassert simple(10, 20, 30) == 60, 'simple function with larger values'\n\n\n# === Positional-only parameters ===\ndef pos_only(a, b, /, c):\n    return a + b + c\n\n\nassert pos_only(1, 2, 3) == 6, 'positional-only params'\nassert pos_only(5, 5, 5) == 15, 'positional-only all same'\nassert pos_only(5, 5, c=5) == 15, 'positional-only all same'\n\n\n# === All positional-only ===\ndef all_pos_only(a, b, c, /):\n    return a + b + c\n\n\nassert all_pos_only(1, 2, 3) == 6, 'all positional-only'\n\n\n# === Multiple parameter groups ===\ndef multi_group(a, /, b, c):\n    return f'a={a} b={b} c={c}'\n\n\nassert multi_group(1, 2, 3) == 'a=1 b=2 c=3', 'mixed positional-only and regular'\nassert multi_group(1, b=2, c=3) == 'a=1 b=2 c=3', 'mixed positional-only and regular'\nassert multi_group(1, c=3, b=2) == 'a=1 b=2 c=3', 'mixed positional-only and regular'\n\n\n# === Call-site *args unpacking ===\ndef collect_all(*values):\n    return values\n\n\nsource_tuple = (1, 2, 3)\nassert collect_all(*source_tuple) == (1, 2, 3), 'tuple unpacked with *args'\n\nsource_list = [4, 5]\nassert collect_all(0, *source_list) == (0, 4, 5), 'positional args followed by *args'\n",
