  'import__local_scope.py':
      "# Tests that import inside functions binds to local scope, not global\n\n# === Import statement inside function ===\ndef test_import_local():\n    import sys\n\n    return sys.platform\n\n\n# Call to verify import works inside function\nresult = test_import_local()\nassert isinstance(result, str), 'sys.platform should be a string'\n\n# Verify sys is NOT in global scope after function call\ntry:\n    sys\n    assert False, 'sys should not be in global scope'\nexcept NameError:\n    pass  # Expected: sys is local to the function\n\n\n# === From import inside function ===\ndef test_from_import_local():\n    from typing import Any\n\n    return Any\n\n\nany_result = test_from_import_local()\nassert repr(any_result) == 'typing.Any', 'should return typing.Any'\n\n# Verify Any is NOT in global scope after function call\ntry:\n    Any\n    assert False, 'Any should not be in global scope'\nexcept NameError:\n    pass  # Expected: Any is local to the function\n\n\n# === Aliased import inside function ===\ndef test_aliased_import_local():\n    import sys as system\n\n    return system.platform\n\n\nalias_result = test_aliased_import_local()\nassert isinstance(alias_result, str), 'system.platform should be a string'\n\n# Verify system is NOT in global scope\ntry:\n    system\n    assert False, 'system should not be in global scope'\nexcept NameError:\n    pass  # Expected: system is local to the function\n\n# === Global import remains accessible ===\nimport sys as global_sys\n\nassert isinstance(global_sys.platform, str), 'global import should work'\n\n\ndef use_global_import():\n    # This should access the global sys, not create a new local\n    return global_sys.platform\n\n\nassert use_global_import() == global_sys.platform, 'function should access global import'\n",
  'import__multi.py':
      "# Tests for multi-module import statements (import a, b, c)\n\n# === Basic multi-module import ===\nimport sys, math\n\nassert isinstance(sys.version, str), 'sys should be accessible after multi-import'\nassert math.pi > 3.14, 'math should be accessible after multi-import'\n\n# === Multi-module import with alias ===\nimport sys as s, math as m\n\nassert isinstance(s.version, str), 'sys alias should work in multi-import'\nassert m.pi > 3.14, 'math alias should work in multi-import'\n\n# === Mixed alias and non-alias ===\nimport sys, math as m2\n\nassert isinstance(sys.version, str), 'non-aliased module should work in mixed import'\nassert m2.pi > 3.14, 'aliased module should work in mixed import'\n",
  'import__os.py':
      "# call-external\n# Tests for os module import and os.getenv()\n\nimport os\n\n# === os.getenv() with existing variable ===\nassert os.getenv('VIRTUAL_HOME') == '/virtual/home', 'getenv returns existing value'\nassert os.getenv('VIRTUAL_USER') == 'testuser', 'getenv returns user value'\nassert os.getenv('VIRTUAL_EMPTY') == '', 'getenv returns empty string value'\n\n# === os.getenv() with missing variable ===\nassert os.getenv('NONEXISTENT') is None, 'getenv returns None for missing var'\nassert os.getenv('ALSO_MISSING') is None, 'getenv returns None for other missing var'\n\n# === os.getenv() with default value ===\nassert os.getenv('NONEXISTENT', 'fallback') == 'fallback', 'getenv uses default when missing'\nassert os.getenv('ALSO_MISSING', '') == '', 'getenv uses empty string default'\nassert os.getenv('MISSING', None) is None, 'getenv with explicit None default'\n\n# === os.getenv() existing var ignores default ===\nassert os.getenv('VIRTUAL_HOME', 'ignored') == '/virtual/home', 'existing var ignores default'\nassert os.getenv('VIRTUAL_USER', 'other') == 'testuser', 'existing user ignores default'\n\n# === os.getenv() with empty string existing var ===\nassert os.getenv('VIRTUAL_EMPTY', 'not_used') == '', 'empty string var ignores default'\n",
