  'import__sys.py':
      "# Tests for sys module import\n\nimport sys\n\n# === sys.version ===\n# Check that version is a non-empty string (exact value differs between interpreters)\nassert isinstance(sys.version, str), 'version should be a string'\nassert len(sys.version) > 0, 'version should be non-empty'\n\n# === sys.version_info ===\n# Test index access returns integers for first 3 elements\nassert isinstance(sys.version_info[0], int), 'major version should be int'\nassert isinstance(sys.version_info[1], int), 'minor version should be int'\nassert isinstance(sys.version_info[2], int), 'micro version should be int'\nassert isinstance(sys.version_info[3], str), 'releaselevel should be str'\nassert isinstance(sys.version_info[4], int), 'serial should be int'\n\n# Test negative indexing\nassert sys.version_info[-1] == sys.version_info[4], 'negative index -1 should equal index 4'\nassert sys.version_info[-2] == sys.version_info[3], 'negative index -2 should equal index 3'\nassert sys.version_info[-5] == sys.version_info[0], 'negative index -5 should equal index 0'\n\n# Test named attribute access matches index access\nassert sys.version_info.major == sys.version_info[0], 'major attr should equal index 0'\nassert sys.version_info.minor == sys.version_info[1], 'minor attr should equal index 1'\nassert sys.version_info.micro == sys.version_info[2], 'micro attr should equal index 2'\nassert sys.version_info.releaselevel == sys.version_info[3], 'releaselevel attr should equal index 3'\nassert sys.version_info.serial == sys.version_info[4], 'serial attr should equal index 4'\n\n# Test len\nassert len(sys.version_info) == 5, 'version_info should have 5 elements'\n\n# Test tuple equality (works after fixing NamedTuple equality)\nv = sys.version_info\nassert (v[0], v[1]) == (v.major, v.minor), 'tuple of indices should equal tuple of attrs'\nassert v.major == v[0], 'major attr should equal index 0'\nassert v.minor == v[1], 'minor attr should equal index 1'\n\n# === sys.platform ===\n# Check that platform is a non-empty string (exact value differs between interpreters)\nassert isinstance(sys.platform, str), 'platform should be a string'\nassert len(sys.platform) > 0, 'platform should be non-empty'\n\n# === sys.stdout and sys.stderr ===\n# These should exist - we test by accessing them (will fail if not present)\nstdout = sys.stdout\nstderr = sys.stderr\n",
  'import__sys_monty.py':
      "# xfail=cpython\n# Tests for Monty-specific sys module values\n\nimport sys\n\n# === sys.version ===\nassert sys.version == '3.14.0 (Monty)', f'version should be 3.14.0 (Monty), got {sys.version!r}'\n\n# === sys.version_info exact values ===\nassert sys.version_info[0] == 3, 'major version should be 3'\nassert sys.version_info[1] == 14, 'minor version should be 14'\nassert sys.version_info[2] == 0, 'micro version should be 0'\nassert sys.version_info[3] == 'final', 'releaselevel should be final'\nassert sys.version_info[4] == 0, 'serial should be 0'\n\n# === sys.version_info named attributes ===\nassert sys.version_info.major == 3, 'major attr should be 3'\nassert sys.version_info.minor == 14, 'minor attr should be 14'\nassert sys.version_info.micro == 0, 'micro attr should be 0'\nassert sys.version_info.releaselevel == 'final', 'releaselevel attr should be final'\nassert sys.version_info.serial == 0, 'serial attr should be 0'\n\n# === sys.version_info tuple equality ===\n# This works because NamedTuple equality compares only by elements, not type_name\nassert sys.version_info == (3, 14, 0, 'final', 0), 'version_info should equal tuple'\n\n# === sys.platform ===\nassert sys.platform == 'monty', f'platform should be monty, got {sys.platform!r}'\n",
  'import__type_checking_guard.py':
      "# === TYPE_CHECKING guard ===\n# Imports inside TYPE_CHECKING blocks should not raise errors at runtime\n# because TYPE_CHECKING is False at runtime, so the import is never executed.\nfrom typing import TYPE_CHECKING\n\nif TYPE_CHECKING:\n    import also_nonexistent\n    from nonexistent_module import something\n\n# Verify TYPE_CHECKING is False at runtime (as expected)\nassert TYPE_CHECKING is False, 'TYPE_CHECKING should be False at runtime'\n\n\n# === Function using TYPE_CHECKING for conditional import ===\ndef get_type_checking_value():\n    if TYPE_CHECKING:\n        from another_fake_module import FakeType\n    return 'success'\n\n\nresult = get_type_checking_value()\nassert result == 'success', 'function with TYPE_CHECKING guard should execute'\n\n# === Nested TYPE_CHECKING blocks ===\nif TYPE_CHECKING:\n    if True:\n        from deeply_nested_fake import DeepFake\n\n# === TYPE_CHECKING in else branch (should not be executed either) ===\nx = True\nif x:\n    pass\nelse:\n    if TYPE_CHECKING:\n        from unreachable_module import Unreachable\n\nassert True, 'all TYPE_CHECKING guards work correctly'\n",
  'import__typing.py':
      "# === Typing markers via from import ===\nfrom typing import Any, Callable, Dict, List, Optional, Set, Tuple, Union\n\n# These are now assigned to Marker values (not silently ignored)\n# Test repr() to verify they have the correct string representation\nassert repr(Any) == 'typing.Any', f'Any repr should be Any, got {Any!r}'\nassert repr(Optional) == 'typing.Optional', f'Optional repr should be Optional, got {Optional!r}'\nassert repr(Union) == \"<class 'typing.Union'>\", f'Union repr should be <class typing.Union>, got {Union!r}'\nassert repr(List) == 'typing.List', f'List repr should be List, got {List!r}'\nassert repr(Dict) == 'typing.Dict', f'Dict repr should be Dict, got {Dict!r}'\nassert repr(Tuple) == 'typing.Tuple', f'Tuple repr should be Tuple, got {Tuple!r}'\nassert repr(Set) == 'typing.Set', f'Set repr should be Set, got {Set!r}'\nassert repr(Callable) == 'typing.Callable', f'Callable repr should be Callable, got {Callable!r}'\n\n# === Typing markers via module import ===\nimport typing\n\nassert repr(typing.Any) == 'typing.Any'\nassert repr(typing.Optional) == 'typing.Optional'\nassert repr(typing.Union) == \"<class 'typing.Union'>\"\n\n# === Aliased imports ===\nfrom typing import Any as AnyType\n\nassert repr(AnyType) == 'typing.Any'\n",
