      "isinstance(1, 'int')\n# Raise=TypeError('isinstance() arg 2 must be a type, a tuple of types, or a union')\n",
  'iter__dict_mutation.py':
      "d = {'a': 1, 'b': 2}\nfor k in d:\n    d['c'] = 3\n# Raise=RuntimeError('dictionary changed size during iteration')\n",
  'iter__for.py':
      "# === List iteration ===\nresult = []\nfor x in [1, 2, 3]:\n    result.append(x)\nassert result == [1, 2, 3], 'iterate over list'\n\n# list with mixed types\nresult = []\nfor x in [1, 'a', True]:\n    result.append(x)\nassert result == [1, 'a', True], 'iterate over mixed list'\n\n# empty list\nresult = []\nfor x in []:\n    result.append(x)\nassert result == [], 'iterate over empty list'\n\n# nested list items\nresult = []\nfor x in [[1, 2], [3, 4]]:\n    result.append(x)\nassert result == [[1, 2], [3, 4]], 'iterate over nested lists'\n\n# === Tuple iteration ===\nresult = []\nfor x in (1, 2, 3):\n    result.append(x)\nassert result == [1, 2, 3], 'iterate over tuple'\n\n# empty tuple\nresult = []\nfor x in ():\n    result.append(x)\nassert result == [], 'iterate over empty tuple'\n\n# tuple with mixed types\nresult = []\nfor x in (1, 'b', False):\n    result.append(x)\nassert result == [1, 'b', False], 'iterate over mixed tuple'\n\n# === Dict iteration (yields keys) ===\nresult = []\nfor k in {'a': 1, 'b': 2, 'c': 3}:\n    result.append(k)\nassert result == ['a', 'b', 'c'], 'iterate over dict yields keys'\n\n# empty dict\nresult = []\nfor k in {}:\n    result.append(k)\nassert result == [], 'iterate over empty dict'\n\n# dict preserves insertion order\nresult = []\nd = {'z': 1, 'a': 2, 'm': 3}\nfor k in d:\n    result.append(k)\nassert result == ['z', 'a', 'm'], 'dict iteration preserves insertion order'\n\n# === String iteration (yields chars) ===\nresult = []\nfor c in 'abc':\n    result.append(c)\nassert result == ['a', 'b', 'c'], 'iterate over string yields chars'\n\n# empty string\nresult = []\nfor c in '':\n    result.append(c)\nassert result == [], 'iterate over empty string'\n\n# string with punctuation\nresult = []\nfor c in 'hi!':\n    result.append(c)\nassert result == ['h', 'i', '!'], 'iterate over string with punctuation'\n\n# string with unicode (multi-byte UTF-8 characters)\nresult = []\nfor c in 'héllo':\n    result.append(c)\nassert result == ['h', 'é', 'l', 'l', 'o'], 'iterate over string with accented char'\n\n# string with CJK characters\nresult = []\nfor c in '日本':\n    result.append(c)\nassert result == ['日', '本'], 'iterate over string with CJK chars'\n\n# string with emoji\nresult = []\nfor c in 'a🎉b':\n    result.append(c)\nassert result == ['a', '🎉', 'b'], 'iterate over string with emoji'\n\n# heap string\ns = 'xyz'\ns = s + '!'  # Force heap allocation\nresult = []\nfor c in s:\n    result.append(c)\nassert result == ['x', 'y', 'z', '!'], 'iterate over heap string'\n\n# === Bytes iteration (yields ints) ===\nresult = []\nfor b in b'abc':\n    result.append(b)\nassert result == [97, 98, 99], 'iterate over bytes yields ints'\n\n# empty bytes\nresult = []\nfor b in b'':\n    result.append(b)\nassert result == [], 'iterate over empty bytes'\n\n# bytes with various values\nresult = []\nfor b in b'\\x00\\x01\\xff':\n    result.append(b)\nassert result == [0, 1, 255], 'iterate over bytes with special values'\n\n# === Range iteration (existing functionality) ===\nresult = []\nfor i in range(3):\n    result.append(i)\nassert result == [0, 1, 2], 'iterate over range'\n\n# range with step\nresult = []\nfor i in range(0, 6, 2):\n    result.append(i)\nassert result == [0, 2, 4], 'iterate over range with step'\n\n# === Nested iteration ===\nresult = []\nfor outer in [[1, 2], [3, 4]]:\n    for inner in outer:\n        result.append(inner)\nassert result == [1, 2, 3, 4], 'nested for loops'\n\n# iterate over string within list\nresult = []\nfor s in ['ab', 'cd']:\n    for c in s:\n        result.append(c)\nassert result == ['a', 'b', 'c', 'd'], 'nested string iteration'\n\n# === Using loop variable after loop ===\nfor x in [1, 2, 3]:\n    pass\nassert x == 3, 'loop variable persists after loop'\n\nfor y in 'abc':\n    pass\nassert y == 'c', 'string loop variable persists'\n\n# === List mutation during iteration ===\n# Python allows list mutation during iteration (unlike dict).\n# The iterator checks current length on each iteration.\n\n# appending during iteration - new items are seen\nresult = []\nlst = [1, 2, 3]\nfor x in lst:\n    result.append(x)\n    if x == 2:\n        lst.append(4)\nassert result == [1, 2, 3, 4], 'appending to list during iteration sees new items'\nassert lst == [1, 2, 3, 4], 'list was modified'\n\n# appending multiple items\nresult = []\nlst = [1]\nfor x in lst:\n    result.append(x)\n    if x < 5:\n        lst.append(x + 1)\nassert result == [1, 2, 3, 4, 5], 'can grow list dynamically during iteration'\n\n# === Modifying via copy pattern ===\noriginal = [1, 2, 3]\ncopy = list(original)\nfor x in copy:\n    if x == 2:\n        original.append(4)\nassert original == [1, 2, 3, 4], 'modifying list via copy pattern'\n\n# === Sum pattern ===\ntotal = 0\nfor n in [1, 2, 3, 4, 5]:\n    total = total + n\nassert total == 15, 'sum pattern with list'\n\n# === Early break simulation via flag ===\n# (break not implemented, using flag pattern)\nfound = False\nfor x in [1, 2, 3, 4, 5]:\n    if not found and x == 3:\n        found = True\nassert found == True, 'find pattern with flag'\n\n# === Accumulator patterns ===\n# count items\ncount = 0\nfor _ in ['a', 'b', 'c']:\n    count = count + 1\nassert count == 3, 'count items'\n\n# concatenate strings\nresult = ''\nfor s in ['a', 'b', 'c']:\n    result = result + s\nassert result == 'abc', 'concatenate strings'\n\n# === Dict key-value access pattern ===\nd = {'x': 10, 'y': 20}\ntotal = 0\nfor k in d:\n    total = total + d[k]\nassert total == 30, 'dict key-value access in loop'\n\n# === Dict mutation during iteration ===\n# Python allows modifying existing key values during iteration (no size change).\n# It also allows pop + add that keeps size the same (iterator sees new keys).\n\n# modifying existing values is allowed\nd = {'a': 1, 'b': 2, 'c': 3}\nfor k in d:\n    d[k] = d[k] * 10\nassert d == {'a': 10, 'b': 20, 'c': 30}, 'modify dict values during iteration'\n\n# pop + add keeping same size is allowed, iterator sees new keys\nd = {'a': 1, 'b': 2, 'c': 3}\nresult = []\nfor k in d:\n    result.append(k)\n    if k == 'a':\n        d.pop('b')\n        d['x'] = 4  # size unchanged\nassert result == ['a', 'c', 'x'], 'dict pop+add same size sees new keys'\nassert d == {'a': 1, 'c': 3, 'x': 4}, 'dict was modified correctly'\n",
  'iter__for_loop_unpacking.py':
      "# === Basic for loop ===\nresult = []\nfor i in range(5):\n    result.append(i)\nassert result == [0, 1, 2, 3, 4], 'basic for loop'\n\n# === Tuple unpacking in for loop ===\npairs = [(1, 2), (3, 4), (5, 6)]\nsums = []\nfor a, b in pairs:\n    sums.append(a + b)\nassert sums == [3, 7, 11], 'for loop with pair unpacking'\n\n# === Triple unpacking ===\ntriples = [(1, 2, 3), (4, 5, 6)]\nproducts = []\nfor a, b, c in triples:\n    products.append(a * b * c)\nassert products == [6, 120], 'for loop with triple unpacking'\n\n# === Nested tuple unpacking ===\nnested = [((1, 2), 3), ((4, 5), 6)]\nresults = []\nfor (a, b), c in nested:\n    results.append(a + b + c)\nassert results == [6, 15], 'for loop with nested unpacking'\n\n# === Deep nested unpacking ===\ndeep = [((1, 2), (3, 4)), ((5, 6), (7, 8))]\nsums = []\nfor (a, b), (c, d) in deep:\n    sums.append(a + b + c + d)\nassert sums == [10, 26], 'for loop with deep nested unpacking'\n\n# === Mixed depth unpacking ===\nmixed = [(1, (2, 3)), (4, (5, 6))]\nresults = []\nfor a, (b, c) in mixed:\n    results.append(a + b + c)\nassert results == [6, 15], 'for loop with mixed depth unpacking'\n\n# === Unpacking with else clause ===\npairs = [(1, 2), (3, 4)]\ntotal = 0\nfor a, b in pairs:\n    total += a + b\nelse:\n    total += 100\nassert total == 110, 'for loop unpacking with else clause'\n\n# === Enumerate with unpacking ===\nitems = ['a', 'b', 'c']\nresult = []\nfor i, val in enumerate(items):\n    result.append((i, val))\nassert result == [(0, 'a'), (1, 'b'), (2, 'c')], 'enumerate with unpacking'\n\n# === Dict items unpacking ===\nd = {'x': 1, 'y': 2}\nkeys = []\nvals = []\nfor k, v in d.items():\n    keys.append(k)\n    vals.append(v)\nassert sorted(keys) == ['x', 'y'], 'dict items unpacking keys'\nassert sorted(vals) == [1, 2], 'dict items unpacking values'\n",
  'iter__generator_expr.py':
      "# === Basic generator expression ===\nresult = list(x * 2 for x in range(5))\nassert result == [0, 2, 4, 6, 8], 'basic generator expression'\n\n# === With condition ===\nresult = list(x for x in range(10) if x % 2 == 0)\nassert result == [0, 2, 4, 6, 8], 'generator with condition'\n\n# === Nested generators ===\nresult = list(x + y for x in range(3) for y in range(2))\nassert result == [0, 1, 1, 2, 2, 3], 'nested generator'\n\n# === Generator in function call ===\nresult = sum(x for x in range(5))\nassert result == 10, 'generator in sum()'\n\n# === Generator with unpacking ===\npairs = [(1, 2), (3, 4)]\nresult = list(a + b for a, b in pairs)\nassert result == [3, 7], 'generator with unpacking'\n",
  'iter__generator_expr_type.py':
      "# xfail=cpython\n# TODO: When proper generators are implemented, this test should be removed.\n# Currently generator expressions return lists in Monty, not generator objects.\n# This test verifies the temporary behavior until generators are properly implemented.\ngen_result = (x * 2 for x in range(5))\nassert type(gen_result) == list, 'generator expr currently returns list'\nassert gen_result == [0, 2, 4, 6, 8], 'generator expr value'\n",
  'iter__not_iterable.py':
      "for x in 42:\n    pass\n# Raise=TypeError(\"'int' object is not iterable\")\n",
  'json__dumps_errors.py':
      "import json\n\n# === allow_nan=False errors ===\ntry:\n    json.dumps(float('inf'), allow_nan=False)\n    assert False, 'should raise ValueError for inf'\nexcept ValueError as exc:\n    assert str(exc) == 'Out of range float values are not JSON compliant: inf', 'inf error message'\n\ntry:\n    json.dumps(float('-inf'), allow_nan=False)\n    assert False, 'should raise ValueError for -inf'\nexcept ValueError as exc:\n    assert str(exc) == 'Out of range float values are not JSON compliant: -inf', '-inf error message'\n\n# === not JSON serializable errors ===\ntry:\n    json.dumps({1})\n    assert False, 'set should not be serializable'\nexcept TypeError as exc:\n    assert str(exc) == 'Object of type set is not JSON serializable', 'set error message'\n\n# === separators errors ===\ntry:\n    json.dumps(1, separators=[',', ':', 'x'])\n    assert False, 'list of 3 separators should raise ValueError'\nexcept ValueError as exc:\n    assert str(exc) == 'too many values to unpack (expected 2, got 3)', 'sep list of 3 error message'\n\ntry:\n    json.dumps(1, separators=[','])\n    assert False, 'list of 1 separator should raise ValueError'\nexcept ValueError as exc:\n    assert str(exc) == 'not enough values to unpack (expected 2, got 1)', 'sep list of 1 error message'\n\ntry:\n    json.dumps(1, separators=42)\n    assert False, 'int separators should raise TypeError'\nexcept TypeError as exc:\n    assert str(exc) == 'cannot unpack non-iterable int object', 'int separators error message'\n\ntry:\n    json.dumps(1, separators=[1, ':'])\n    assert False, 'non-string first separator should raise TypeError'\nexcept TypeError as exc:\n    assert str(exc) == 'make_encoder() argument 6 must be str, not int', 'non-string item_separator error'\n\ntry:\n    json.dumps(1, separators=[',', 2])\n    assert False, 'non-string second separator should raise TypeError'\nexcept TypeError as exc:\n    assert str(exc) == 'make_encoder() argument 5 must be str, not int', 'non-string key_separator error'\n\n# === unexpected keyword argument ===\ntry:\n    json.dumps(None, foobar_not_static=True)\n    assert False, 'unexpected kwarg should raise TypeError'\nexcept TypeError as exc:\n    assert str(exc) == \"JSONEncoder.__init__() got an unexpected keyword argument 'foobar_not_static'\", (\n        'unexpected kwarg error message'\n    )\n\ntry:\n    json.dumps(1, 2)\nexcept TypeError as exc:\n    assert str(exc) == 'dumps() takes 1 positional argument but 2 were given'\n\n# === circular reference errors ===\ncircular_list = []\ncircular_list.append(circular_list)\ntry:\n    json.dumps(circular_list)\n    assert False, 'circular list should raise ValueError'\nexcept ValueError as exc:\n    assert str(exc) == 'Circular reference detected', 'circular list error'\n\ncircular_dict = {}\ncircular_dict['self'] = circular_dict\ntry:\n    json.dumps(circular_dict)\n    assert False, 'circular dict should raise ValueError'\nexcept ValueError as exc:\n    assert str(exc) == 'Circular reference detected', 'circular dict error'\n\n# === nested circular reference ===\nouter = []\ninner = [outer]\nouter.append(inner)\ntry:\n    json.dumps(outer)\n    assert False, 'nested circular should raise ValueError'\nexcept ValueError as exc:\n    assert str(exc) == 'Circular reference detected', 'nested circular error'\n\n# === circular reference in dict value ===\nd = {}\nd['a'] = [d]\ntry:\n    json.dumps(d)\n    assert False, 'circular dict in list should raise ValueError'\nexcept ValueError as exc:\n    assert str(exc) == 'Circular reference detected', 'circular dict-in-list error'\n\n# === allow_nan=False with float dict keys ===\ntry:\n    json.dumps({float('nan'): 1}, allow_nan=False)\n    assert False, 'should raise ValueError for NaN key'\nexcept ValueError as exc:\n    assert str(exc) == 'Out of range float values are not JSON compliant: nan', 'NaN key error message'\n\ntry:\n    json.dumps({float('inf'): 1}, allow_nan=False)\n    assert False, 'should raise ValueError for inf key'\nexcept ValueError as exc:\n    assert str(exc) == 'Out of range float values are not JSON compliant: inf', 'inf key error message'\n\ntry:\n    json.dumps({float('-inf'): 1}, allow_nan=False)\n    assert False, 'should raise ValueError for -inf key'\nexcept ValueError as exc:\n    assert str(exc) == 'Out of range float values are not JSON compliant: -inf', '-inf key error message'\n",
  'json__dumps_formatting.py':
      "import json\n\n# === indent edge cases ===\nassert json.dumps([1, 2], indent=False) == '[\\n1,\\n2\\n]', 'indent=False behaves like indent=0'\nassert json.dumps({'a': 1}, indent=False) == '{\\n\"a\": 1\\n}', 'indent=False on dict uses newline-only'\n\n# === empty containers with indent ===\nassert json.dumps([], indent=2) == '[]', 'empty list with indent stays compact'\nassert json.dumps({}, indent=2) == '{}', 'empty dict with indent stays compact'\nassert json.dumps((), indent=2) == '[]', 'empty tuple with indent stays compact'\n\n# === separators=None preserves indent-aware defaults ===\nassert json.dumps({'a': [1, 2]}, indent=2, separators=None) == json.dumps({'a': [1, 2]}, indent=2), (\n    'separators=None with indent uses same defaults as omitting separators'\n)\n\n# === separators as tuple ===\nassert json.dumps({'a': 1}, separators=(',', ':')) == '{\"a\":1}', 'tuple separators work'\nassert json.dumps([1, 2], separators=(' , ', ' : ')) == '[1 , 2]', 'custom separators with spaces'\n\n# === separators as list ===\nassert json.dumps({'a': 1}, separators=[',', ':']) == '{\"a\":1}', 'list separators work'\n\n# === indent with explicit separators ===\nassert json.dumps({'a': 1}, indent=2, separators=(',', ': ')) == '{\\n  \"a\": 1\\n}', (\n    'indent with explicit separators does not override to defaults'\n)\n\n# === nested structures with indent ===\nassert json.dumps({'a': {'b': 1}}, indent=2) == '{\\n  \"a\": {\\n    \"b\": 1\\n  }\\n}', (\n    'nested dict pretty prints with proper nesting'\n)\nassert json.dumps({'a': [1, 2], 'b': {'c': 3}}, indent=2) == (\n    '{\\n  \"a\": [\\n    1,\\n    2\\n  ],\\n  \"b\": {\\n    \"c\": 3\\n  }\\n}'\n), 'mixed nested containers with indent'\n\n# === empty inner containers with indent ===\nassert json.dumps({'a': [], 'b': {}}, indent=2) == '{\\n  \"a\": [],\\n  \"b\": {}\\n}', (\n    'empty inner containers stay compact even with indent'\n)\n\n# === deeply nested structures ===\nassert json.dumps([[[[1]]]]) == '[[[[1]]]]', 'deeply nested lists serialize'\nassert json.dumps({'a': {'b': {'c': {'d': 1}}}}) == '{\"a\": {\"b\": {\"c\": {\"d\": 1}}}}', 'deeply nested dicts serialize'\n\n# === sort_keys with multiple keys ===\nassert json.dumps({'c': 3, 'a': 1, 'b': 2}, sort_keys=True) == '{\"a\": 1, \"b\": 2, \"c\": 3}', (\n    'sort_keys sorts string keys alphabetically'\n)\nassert json.dumps({}, sort_keys=True) == '{}', 'sort_keys on empty dict'\nassert json.dumps({'z': 1}, sort_keys=True) == '{\"z\": 1}', 'sort_keys on single key'\n\n# === sort_keys with indent ===\nassert json.dumps({'b': 1, 'a': 2}, sort_keys=True, indent=2) == ('{\\n  \"a\": 2,\\n  \"b\": 1\\n}'), (\n    'sort_keys combined with indent'\n)\n\n# === multiple refs to same object (not circular) ===\nshared = [1, 2]\nassert json.dumps([shared, shared]) == '[[1, 2], [1, 2]]', (\n    'multiple references to same list are not flagged as circular'\n)\n\n# === long integers beyond i64 range ===\nbig = 2**63 + 1\nassert json.dumps(big) == '9223372036854775809', 'long int above i64::MAX serializes'\nassert json.dumps(-big) == '-9223372036854775809', 'negative long int below i64::MIN serializes'\n\n# === string escaping ===\nassert json.dumps('a\\\\b') == '\"a\\\\\\\\b\"', 'backslash is escaped'\nassert json.dumps('a\"b') == '\"a\\\\\"b\"', 'double quote is escaped'\nassert json.dumps('\\x00') == '\"\\\\u0000\"', 'null byte is escaped'\nassert json.dumps('\\x01') == '\"\\\\u0001\"', 'control char 0x01 is escaped'\nassert json.dumps('\\x1f') == '\"\\\\u001f\"', 'control char 0x1f is escaped'\nassert json.dumps('\\x7f') == '\"\\\\u007f\"', 'DEL char 0x7f is escaped with ensure_ascii'\nassert json.dumps('\\x7f', ensure_ascii=False) == '\"\\x7f\"', 'DEL char 0x7f is literal with ensure_ascii=False'\nassert json.dumps('😀') == '\"\\\\ud83d\\\\ude00\"', 'non-BMP unicode escapes as surrogate pair with ensure_ascii'\nassert json.dumps('😀', ensure_ascii=False) == '\"😀\"', 'non-BMP unicode stays literal with ensure_ascii=False'\nassert json.dumps('ascii😀\"\\\\\\x01z') == '\"ascii\\\\ud83d\\\\ude00\\\\\"\\\\\\\\\\\\u0001z\"', (\n    'mixed string escapes flush correctly across ascii, unicode, quotes, backslashes, and control chars'\n)\n",
  'json__dumps_keys.py':
      "import json\n\n# === float special value keys ===\nassert json.dumps({float('nan'): 1}) == '{\"NaN\": 1}', 'NaN float key is coerced to \"NaN\"'\nassert json.dumps({float('inf'): 1}) == '{\"Infinity\": 1}', 'inf float key is coerced to \"Infinity\"'\nassert json.dumps({float('-inf'): 1}) == '{\"-Infinity\": 1}', '-inf float key is coerced to \"-Infinity\"'\n\n# === bigint key ===\nbig = 10**40\nassert json.dumps({big: 1}) == '{\"10000000000000000000000000000000000000000\": 1}', (\n    'big integer keys are coerced to decimal strings'\n)\n\n# === skipkeys with various unsupported key types ===\nassert json.dumps({(1, 2): 'a', 'b': 'c'}, skipkeys=True) == '{\"b\": \"c\"}', (\n    'skipkeys drops tuple keys and keeps string keys'\n)\nassert json.dumps({(1,): 1, (2,): 2}, skipkeys=True) == '{}', 'skipkeys drops all unsupported keys leaving empty dict'\n\n# === skipkeys=False (default) error ===\ntry:\n    json.dumps({(1, 2): 3})\n    assert False, 'should raise TypeError for tuple key'\nexcept TypeError as exc:\n    assert str(exc) == 'keys must be str, int, float, bool or None, not tuple', (\n        'invalid key type error message for tuple'\n    )\n\n# === sort_keys error with mixed types ===\ntry:\n    json.dumps({1: 'a', 'b': 'c'}, sort_keys=True)\n    assert False, 'sort_keys with mixed key types should raise TypeError'\nexcept TypeError as exc:\n    assert \"'<' not supported between instances of 'str' and 'int'\" == str(exc), (\n        'sort_keys mixed types error matches CPython'\n    )\n\n# === all allowed key types together ===\nresult = json.dumps({True: 1, False: 2, None: 3, 4: 5, 1.5: 6, 'a': 7})\nassert result == '{\"true\": 1, \"false\": 2, \"null\": 3, \"4\": 5, \"1.5\": 6, \"a\": 7}', (\n    'all allowed key types serialize correctly'\n)\n\n# === skipkeys preserves insertion order ===\nd = {}\nd['a'] = 1\nd[(1,)] = 'skip'\nd['b'] = 2\nd[(2,)] = 'skip'\nd['c'] = 3\nassert json.dumps(d, skipkeys=True) == '{\"a\": 1, \"b\": 2, \"c\": 3}', 'skipkeys preserves order of remaining keys'\n\n# === skipkeys drops keys at the start ===\nd2 = {}\nd2[(1,)] = 'skip'\nd2['a'] = 1\nd2['b'] = 2\nassert json.dumps(d2, skipkeys=True) == '{\"a\": 1, \"b\": 2}', 'skipkeys drops disallowed keys at the start'\n\n# === skipkeys drops keys at the end ===\nd3 = {}\nd3['a'] = 1\nd3['b'] = 2\nd3[(1,)] = 'skip'\nassert json.dumps(d3, skipkeys=True) == '{\"a\": 1, \"b\": 2}', 'skipkeys drops disallowed keys at the end'\n\n# === skipkeys drops consecutive disallowed keys ===\nd4 = {}\nd4['a'] = 1\nd4[(1,)] = 'skip'\nd4[(2,)] = 'skip'\nd4[(3,)] = 'skip'\nd4['b'] = 2\nassert json.dumps(d4, skipkeys=True) == '{\"a\": 1, \"b\": 2}', 'skipkeys drops consecutive disallowed keys'\n\n# === skipkeys with single allowed key ===\nassert json.dumps({(1,): 'skip', 'a': 1, (2,): 'skip'}, skipkeys=True) == '{\"a\": 1}', (\n    'skipkeys with only one allowed key'\n)\n\n# === skipkeys with single disallowed key ===\nassert json.dumps({(1,): 1}, skipkeys=True) == '{}', 'skipkeys with single disallowed key produces empty object'\n\n# === skipkeys with only allowed keys is a no-op ===\nassert json.dumps({'a': 1, 'b': 2}, skipkeys=True) == '{\"a\": 1, \"b\": 2}', (\n    'skipkeys with all allowed keys changes nothing'\n)\n\n# === skipkeys in nested dicts ===\nassert json.dumps({'a': {(1,): 'skip', 'b': 2}}, skipkeys=True) == '{\"a\": {\"b\": 2}}', (\n    'skipkeys applies recursively to nested dicts'\n)\nassert json.dumps({'a': {(1,): 'skip', (2,): 'skip'}}, skipkeys=True) == '{\"a\": {}}', (\n    'skipkeys recursively produces empty nested dict'\n)\n\n# === skipkeys with complex values on skipped entries ===\nassert (\n    json.dumps(\n        {\n            (1,): [1, 2, 3],\n            'a': {'nested': True},\n            (2,): {'also': 'skipped'},\n            'b': [4, 5],\n        },\n        skipkeys=True,\n    )\n    == '{\"a\": {\"nested\": true}, \"b\": [4, 5]}'\n), 'skipkeys drops entries with complex values without errors'\n\n# === skipkeys combined with indent ===\nresult = json.dumps({'a': 1, (1,): 'skip', 'b': 2}, skipkeys=True, indent=2)\nassert result == '{\\n  \"a\": 1,\\n  \"b\": 2\\n}', 'skipkeys works with indent'\n\n# === skipkeys with mixed allowed key types ===\nassert (\n    json.dumps(\n        {\n            'str': 1,\n            42: 2,\n            True: 3,\n            None: 4,\n            3.14: 5,\n            (1,): 'skip',\n        },\n        skipkeys=True,\n    )\n    == '{\"str\": 1, \"42\": 2, \"true\": 3, \"null\": 4, \"3.14\": 5}'\n), 'skipkeys drops tuple but keeps str, int, bool, None, float keys'\n\n# === skipkeys with bytes key ===\nassert json.dumps({b'hello': 1, 'a': 2}, skipkeys=True) == '{\"a\": 2}', 'skipkeys drops bytes keys'\n\n# === skipkeys with empty dict ===\nassert json.dumps({}, skipkeys=True) == '{}', 'skipkeys with empty dict'\n\n# === skipkeys=False TypeError for various disallowed types ===\ntry:\n    json.dumps({(1, 2): 3})\n    assert False, 'should raise TypeError for tuple key without skipkeys'\nexcept TypeError as exc:\n    assert str(exc) == 'keys must be str, int, float, bool or None, not tuple', 'TypeError message for tuple key'\n\ntry:\n    json.dumps({b'hello': 1})\n    assert False, 'should raise TypeError for bytes key without skipkeys'\nexcept TypeError as exc:\n    assert str(exc) == 'keys must be str, int, float, bool or None, not bytes', 'TypeError message for bytes key'\n\n# === skipkeys + sort_keys (only allowed keys) ===\nd5 = {}\nd5['c'] = 3\nd5['a'] = 1\nd5['b'] = 2\nassert json.dumps(d5, skipkeys=True, sort_keys=True) == '{\"a\": 1, \"b\": 2, \"c\": 3}', (\n    'skipkeys + sort_keys: allowed keys are sorted correctly'\n)\n\n# === string key with ensure_ascii ===\nassert json.dumps({'hello': 1}) == '{\"hello\": 1}', 'simple string key'\n",
  'json__int_max_str_digits.py':
      "import json\n\n# === loads accepts integers at the digit limit ===\nload_ok = '1' * 4300\nassert json.loads(load_ok) == int(load_ok), 'loads should accept 4300-digit integers'\n\n# === loads rejects oversized decimal integers ===\ntry:\n    json.loads('1' * 4301)\n    assert False, 'loads should reject integers that exceed INT_MAX_STR_DIGITS'\nexcept ValueError as exc:\n    msg = str(exc)\n    assert msg.startswith('Exceeds the limit (4300 digits) for integer string conversion: value has 4301 digits'), (\n        f'loads digit-limit error message mismatch: {msg}'\n    )\n\n# === dumps accepts integers at the digit limit ===\ndump_ok = 10**4299\nassert json.dumps(dump_ok) == str(dump_ok), 'dumps should accept 4300-digit integers'\n\n# === dumps rejects oversized decimal integers ===\ntry:\n    json.dumps(10**4300)\n    assert False, 'dumps should reject integers that exceed INT_MAX_STR_DIGITS'\nexcept ValueError as exc:\n    msg = str(exc)\n    assert msg.startswith('Exceeds the limit (4300 digits) for integer string conversion'), (\n        f'dumps digit-limit error message mismatch: {msg}'\n    )\n",
  'json__literals.py':
      "import json\n\n# === dumps unicode and escaping ===\nassert json.dumps('😀') == '\"\\\\ud83d\\\\ude00\"', 'ensure_ascii escapes supplementary-plane characters as surrogate pairs'\nassert json.dumps('😀', ensure_ascii=False) == '\"😀\"', 'ensure_ascii=False keeps supplementary-plane characters'\nassert json.dumps('A☃😀') == '\"A\\\\u2603\\\\ud83d\\\\ude00\"', (\n    'mixed non-ASCII string escapes all non-ASCII code points by default'\n)\nassert json.dumps('A☃😀', ensure_ascii=False) == '\"A☃😀\"', (\n    'mixed non-ASCII string stays literal with ensure_ascii=False'\n)\nassert json.dumps('\\b\\f\\n\\r\\t') == '\"\\\\b\\\\f\\\\n\\\\r\\\\t\"', 'control characters use the short JSON escapes'\nassert json.dumps({'☃': '😀'}) == '{\"\\\\u2603\": \"\\\\ud83d\\\\ude00\"}', 'non-ASCII dict keys and values escape by default'\nassert json.dumps({'☃': '😀'}, ensure_ascii=False) == '{\"☃\": \"😀\"}', (\n    'non-ASCII dict keys and values stay literal with ensure_ascii=False'\n)\n\n# === dumps indentation and separators ===\nassert json.dumps({'a': [1, 2]}, indent=0) == '{\\n\"a\": [\\n1,\\n2\\n]\\n}', 'indent=0 uses newline-only pretty printing'\nassert json.dumps({'a': [1, 2]}, indent=-1) == '{\\n\"a\": [\\n1,\\n2\\n]\\n}', (\n    'negative indent matches indent=0 newline-only formatting'\n)\nassert json.dumps({'a': [1, 2]}, indent=True) == '{\\n \"a\": [\\n  1,\\n  2\\n ]\\n}', 'indent=True behaves like indent=1'\nassert json.dumps({'a': 1}, separators=None) == '{\"a\": 1}', 'separators=None keeps the default separators'\n\n# === dumps exact numeric literals ===\nbig = 1234567890123456789012345678901234567890\nassert json.dumps(big) == '1234567890123456789012345678901234567890', 'big integers dump without scientific notation'\nassert json.dumps({big: 1}) == '{\"1234567890123456789012345678901234567890\": 1}', (\n    'big integer dict keys are coerced to decimal strings'\n)\nassert json.dumps(1e20) == '1e+20', 'large finite floats keep exponent notation'\nassert json.dumps(1e-6) == '1e-06', 'small finite floats keep exponent notation'\nassert json.dumps(-0.0) == '-0.0', 'negative zero preserves its sign when dumped'\nassert json.dumps(9999999999999998.0) == '9999999999999998.0', (\n    'float just below 1e16 stays in fixed notation despite log10 rounding'\n)\nassert json.dumps(1.0000000000000002e16) == '1.0000000000000002e+16', 'float just above 1e16 uses exponent notation'\nassert json.dumps(0.0001) == '0.0001', 'float at 1e-4 boundary stays in fixed notation'\nassert json.dumps(9.999999999999999e-05) == '9.999999999999999e-05', 'float just below 1e-4 uses exponent notation'\nassert json.dumps(5e-324) == '5e-324', 'smallest subnormal float uses exponent notation'\nassert json.dumps(1e300) == '1e+300', 'very large float uses exponent notation'\n\n# === loads unicode literals ===\nassert json.loads('\"☃😀\"') == '☃😀', 'loads raw non-ASCII JSON strings'\nassert json.loads('{\"☃\": \"😀\"}') == {'☃': '😀'}, 'loads raw non-ASCII object keys and values'\nassert json.loads('\"\\\\ud83d\\\\ude00\"') == '😀', 'loads surrogate-pair escapes into a supplementary-plane character'\nassert json.loads('\"☃😀\"'.encode('utf-8')) == '☃😀', 'loads UTF-8 bytes containing raw non-ASCII characters'\n\n# === loads numeric literals ===\nassert json.loads(str(big)) == big, 'loads large integers without losing precision'\nassert json.loads('1e20') == 1e20, 'loads large exponent floats'\nassert json.loads('1e-6') == 1e-6, 'loads small exponent floats'\nassert json.loads('-0.0') == -0.0, 'loads negative zero as a float'\n\n# === loads NaN and Infinity (CPython accepts these by default) ===\nimport math\n\nnan_result = json.loads('NaN')\nassert math.isnan(nan_result), 'loads NaN as float nan'\nassert json.loads('Infinity') == float('inf'), 'loads Infinity as float inf'\nassert json.loads('-Infinity') == float('-inf'), 'loads -Infinity as float -inf'\nassert json.loads('[NaN, Infinity, -Infinity]')[1] == float('inf'), 'loads NaN/Infinity in arrays'\n",
  'json__loads_invalid_messages.py':
      "import json\n\n# === invalid JSON messages ===\ninvalid_cases = [\n    (\n        \"{'a': 1}\",\n        'Expecting property name enclosed in double quotes: line 1 column 2 (char 1)',\n    ),\n    (\n        '{\"a\": 1,}',\n        'Illegal trailing comma before end of object: line 1 column 8 (char 7)',\n    ),\n    (\n        '[1,]',\n        'Illegal trailing comma before end of array: line 1 column 3 (char 2)',\n    ),\n    (\n        '\"abc',\n        'Unterminated string starting at: line 1 column 1 (char 0)',\n    ),\n    (\n        '',\n        'Expecting value: line 1 column 1 (char 0)',\n    ),\n    (\n        'true false',\n        'Extra data: line 1 column 6 (char 5)',\n    ),\n    (\n        '1\\n2',\n        'Extra data: line 2 column 1 (char 2)',\n    ),\n    (\n        '[1]\\n{\"a\": 2}',\n        'Extra data: line 2 column 1 (char 4)',\n    ),\n    (\n        '[,1]',\n        'Expecting value: line 1 column 2 (char 1)',\n    ),\n    (\n        '{\"a\" 1}',\n        \"Expecting ':' delimiter: line 1 column 6 (char 5)\",\n    ),\n    (\n        '\"\\\\x\"',\n        'Invalid \\\\escape: line 1 column 2 (char 1)',\n    ),\n    (\n        '\"\\\\u12X4\"',\n        'Invalid \\\\uXXXX escape: line 1 column 3 (char 2)',\n    ),\n    (\n        '[1',\n        \"Expecting ',' delimiter: line 1 column 3 (char 2)\",\n    ),\n    (\n        '{\"a\": 1',\n        \"Expecting ',' delimiter: line 1 column 8 (char 7)\",\n    ),\n    (\n        '{\"a\": [1, 2,]}',\n        'Illegal trailing comma before end of array: line 1 column 12 (char 11)',\n    ),\n    (\n        '{\"a\": {\"b\": 1,}}',\n        'Illegal trailing comma before end of object: line 1 column 14 (char 13)',\n    ),\n    (\n        '[\\n  1,\\n]',\n        'Illegal trailing comma before end of array: line 2 column 4 (char 5)',\n    ),\n    (\n        '{\\n  \"a\": 1,\\n}',\n        'Illegal trailing comma before end of object: line 2 column 9 (char 10)',\n    ),\n    (\n        'True',\n        'Expecting value: line 1 column 1 (char 0)',\n    ),\n]\n\nfor source, expected in invalid_cases:\n    try:\n        json.loads(source)\n        assert False, f'invalid JSON should raise JSONDecodeError: {source!r}'\n    except json.JSONDecodeError as exc:\n        assert str(exc) == expected, f'invalid JSON message mismatch for {source!r}'\n",
  'json__module.py':
      "import json\n\n# === loads basics ===\nassert json.loads('null') is None, 'loads null -> None'\nassert json.loads('true') is True, 'loads true -> True'\nassert json.loads('false') is False, 'loads false -> False'\nassert json.loads('123') == 123, 'loads int'\nassert json.loads('1.5') == 1.5, 'loads float'\nassert json.loads('\"hello\"') == 'hello', 'loads string'\nassert json.loads('[1, 2, 3]') == [1, 2, 3], 'loads array'\nassert json.loads('{\"a\": 1, \"b\": [true, null]}') == {\n    'a': 1,\n    'b': [True, None],\n}, 'loads nested object'\n\n# === loads bytes and unicode ===\nassert json.loads(b'{\"a\":[1,true,null]}') == {'a': [1, True, None]}, 'loads bytes object input'\nassert json.loads(b'123') == 123, 'loads bytes integer'\nassert json.loads(b'1.5') == 1.5, 'loads bytes float'\nassert json.loads(b'\"hello\"') == 'hello', 'loads bytes string'\nassert json.loads(b'[1, 2, 3]') == [1, 2, 3], 'loads bytes array'\nassert json.loads(b'true') is True, 'loads bytes true'\nassert json.loads(b'false') is False, 'loads bytes false'\nassert json.loads(b'null') is None, 'loads bytes null'\nassert json.loads('\"\\\\u2603\"') == '☃', 'loads unicode escape'\nassert json.loads('{\"a\": 1, \"a\": 2}') == {'a': 2}, 'loads duplicate object keys with last value winning'\n\n# === loads big integers ===\nbig = 1234567890123456789012345678901234567890\nassert json.loads(str(big)) == big, 'loads big integer as Python int'\n\n# === dumps basics ===\nassert json.dumps(None) == 'null', 'dumps None'\nassert json.dumps(True) == 'true', 'dumps True'\nassert json.dumps(False) == 'false', 'dumps False'\nassert json.dumps(123) == '123', 'dumps int'\nassert json.dumps(1.0) == '1.0', 'dumps whole float keeps decimal'\nassert json.dumps(1.5) == '1.5', 'dumps float'\nassert json.dumps('hello') == '\"hello\"', 'dumps string'\nassert json.dumps([1, 2, 3]) == '[1, 2, 3]', 'dumps list'\nassert json.dumps({'a': 1}) == '{\"a\": 1}', 'dumps dict'\nassert json.dumps((1, 2, 3)) == '[1, 2, 3]', 'dumps tuple as array'\n\n# === dumps formatting ===\nassert json.dumps({'b': 1, 'a': 2}, sort_keys=True) == ('{\"a\": 2, \"b\": 1}'), 'sort_keys sorts string keys'\nassert json.dumps({'a': [1, 2]}, indent=2) == ('{\\n  \"a\": [\\n    1,\\n    2\\n  ]\\n}'), 'indent=2 pretty prints'\nassert json.dumps({'a': [1, 2]}, indent='--') == ('{\\n--\"a\": [\\n----1,\\n----2\\n--]\\n}'), (\n    'string indent repeats per depth'\n)\nassert json.dumps({'a': 1}, separators=(',', ':')) == '{\"a\":1}', 'custom separators applied'\n\n# === dumps unicode and floats ===\nassert json.dumps('☃') == '\"\\\\u2603\"', 'ensure_ascii defaults to true'\nassert json.dumps('☃', ensure_ascii=False) == ('\"☃\"'), 'ensure_ascii=False keeps unicode characters'\nassert json.dumps(float('nan')) == 'NaN', 'allow_nan defaults to true'\nassert json.dumps(float('inf')) == ('Infinity'), 'positive infinity serializes when allow_nan is true'\nassert json.dumps(float('-inf')) == ('-Infinity'), 'negative infinity serializes when allow_nan is true'\n\n# === dumps key coercion ===\nassert (\n    json.dumps({True: 1, False: 2, None: 3, 4: 5, 1.5: 6}) == '{\"true\": 1, \"false\": 2, \"null\": 3, \"4\": 5, \"1.5\": 6}'\n), 'non-string JSON keys are coerced to strings like CPython'\n\n# === dumps skipkeys ===\nassert json.dumps({(1, 2): 3}, skipkeys=True) == '{}', 'skipkeys drops unsupported keys'\n\n# === empty containers ===\nassert json.dumps([]) == '[]', 'dumps empty list'\nassert json.dumps({}) == '{}', 'dumps empty dict'\nassert json.loads('[]') == [], 'loads empty list'\nassert json.loads('{}') == {}, 'loads empty dict'\n\n# === roundtrip ===\ndata = {'a': [1, 2.5, True, None, 'x', {'b': [3]}]}\nassert json.loads(json.dumps(data)) == data, 'loads(dumps(x)) roundtrips nested JSON values'\n\n# === JSONDecodeError subclassing ===\ntry:\n    json.loads('{]')\n    assert False, 'invalid JSON should raise JSONDecodeError'\nexcept json.JSONDecodeError as exc:\n    assert str(exc) == 'Expecting property name enclosed in double quotes: line 1 column 2 (char 1)', (\n        'JSONDecodeError message matches CPython format'\n    )\n\ncaught_value_error = False\ntry:\n    json.loads('{]')\nexcept ValueError:\n    caught_value_error = True\nassert caught_value_error, 'JSONDecodeError is catchable as ValueError'\n\n# === dumps error handling ===\ntry:\n    json.dumps(float('nan'), allow_nan=False)\n    assert False, 'allow_nan=False should reject NaN'\nexcept ValueError as exc:\n    assert str(exc) == 'Out of range float values are not JSON compliant: nan', 'allow_nan=False error message'\n\ntry:\n    json.dumps({(1, 2): 3})\n    assert False, 'unsupported dict key type should raise TypeError'\nexcept TypeError as exc:\n    assert str(exc) == 'keys must be str, int, float, bool or None, not tuple', 'invalid key type error message'\n\ntry:\n    json.dumps({1})\n    assert False, 'set should not be JSON serializable'\nexcept TypeError as exc:\n    assert str(exc) == 'Object of type set is not JSON serializable', 'set serialization error message'\n\ntry:\n    json.loads(1)\n    assert False, 'loads(int) should raise TypeError'\nexcept TypeError as exc:\n    assert str(exc) == 'the JSON object must be str, bytes or bytearray, not int', 'loads type error message'\n\n# === circular reference detection ===\ncircular = []\ncircular.append(circular)\ntry:\n    json.dumps(circular)\n    assert False, 'circular reference should raise ValueError'\nexcept ValueError as exc:\n    assert str(exc) == 'Circular reference detected', 'circular reference error message'\n",
  'lambda__all.py':
      "# === Basic lambda ===\n# no-arg lambda\nf = lambda: 42\nassert f() == 42, 'no-arg lambda'\n\n# single arg lambda\nf = lambda x: x + 1\nassert f(5) == 6, 'single arg lambda'\n\n# === Multiple arguments ===\nf = lambda x, y: x + y\nassert f(2, 3) == 5, 'multi-arg lambda'\n\nf = lambda x, y, z: x * y + z\nassert f(2, 3, 4) == 10, 'three-arg lambda'\n\n# === Default arguments ===\nf = lambda x, y=10: x + y\nassert f(5) == 15, 'lambda with default'\nassert f(5, 3) == 8, 'lambda override default'\n\nf = lambda x=1, y=2: x * y\nassert f() == 2, 'lambda all defaults'\nassert f(3) == 6, 'lambda override first default'\nassert f(3, 4) == 12, 'lambda override all defaults'\n\n# === Lambda as expression (immediate call) ===\nassert (lambda x: x * 2)(5) == 10, 'immediate call'\nassert (lambda: 'hello')() == 'hello', 'immediate call no args'\nassert (lambda x, y: x - y)(10, 3) == 7, 'immediate call multi args'\n\n# === Lambda in data structures ===\nfuncs = [lambda x: x + 1, lambda x: x * 2, lambda x: x**2]\nassert funcs[0](3) == 4, 'lambda in list - add'\nassert funcs[1](3) == 6, 'lambda in list - mul'\nassert funcs[2](3) == 9, 'lambda in list - pow'\n\n# === Lambda assigned and called later ===\nsquare = lambda x: x * x\ndouble = lambda x: x + x\nassert square(4) == 16, 'lambda assigned square'\nassert double(4) == 8, 'lambda assigned double'\n\n# === Lambda with operations ===\nf = lambda x: x > 5\nassert f(6) is True, 'lambda comparison gt'\nassert f(4) is False, 'lambda comparison not gt'\n\nf = lambda x: x if x > 0 else -x\nassert f(5) == 5, 'lambda ternary positive'\nassert f(-5) == 5, 'lambda ternary negative'\n\n\n# === Closures ===\ndef make_adder(n):\n    return lambda x: x + n\n\n\nadd5 = make_adder(5)\nadd10 = make_adder(10)\nassert add5(3) == 8, 'closure capture add5'\nassert add10(3) == 13, 'closure capture add10'\n\n\ndef make_multiplier(factor):\n    return lambda x: x * factor\n\n\ntimes3 = make_multiplier(3)\nassert times3(4) == 12, 'closure capture multiplier'\n\n# === Nested lambdas ===\nf = lambda x: lambda y: x + y\nadd_to_5 = f(5)\nassert add_to_5(3) == 8, 'nested lambda'\n\nf = lambda x: lambda y: lambda z: x + y + z\nassert f(1)(2)(3) == 6, 'triple nested lambda'\n\n# === Lambda in list comprehension ===\nsquared = [f(x) for x in [1, 2, 3, 4] for f in [lambda n: n * n]]\n# Note: this tests lambda in comprehension context, though due to late binding\n# all items use the same lambda\n\n# === Lambda returns another lambda ===\ncompose = lambda f: lambda g: lambda x: f(g(x))\ninc = lambda x: x + 1\ndouble = lambda x: x * 2\ninc_then_double = compose(double)(inc)\nassert inc_then_double(3) == 8, 'lambda composition'  # double(inc(3)) = double(4) = 8\n\n# === Lambda repr ===\nf = lambda: None\nr = repr(f)\nassert '<lambda>' in r, 'lambda repr contains <lambda>'\nassert 'function' in r, 'lambda repr contains function'\n\n# === Lambda with *args ===\nf = lambda *args: sum(args)\nassert f() == 0, 'lambda varargs empty'\nassert f(1) == 1, 'lambda varargs one'\nassert f(1, 2, 3) == 6, 'lambda varargs multiple'\n\n# === Lambda with keyword arguments ===\nf = lambda x, *, y: x + y\nassert f(1, y=2) == 3, 'lambda keyword only'\n\nf = lambda **kwargs: len(kwargs)\nassert f() == 0, 'lambda kwargs empty'\nassert f(a=1, b=2) == 2, 'lambda kwargs multiple'\n\n# === Mixed parameters ===\nf = lambda a, b=2, *args, c, d=4, **kwargs: (a, b, args, c, d, len(kwargs))\nresult = f(1, 2, 3, 4, c=10, d=20, e=30, f=40)\nassert result == (1, 2, (3, 4), 10, 20, 2), 'lambda mixed params'\n\n# === Unpacking in immediate lambda calls ===\nxs = [1, 2, 3]\nassert (lambda *a: a)(*xs) == (1, 2, 3), 'lambda with *args unpacking'\nassert (lambda **k: k)(**{'a': 1}) == {'a': 1}, 'lambda with **kwargs unpacking'\nassert (lambda *a, **k: (a, k))(1, 2, x=3) == ((1, 2), {'x': 3}), 'lambda mixed unpack'\n\n# === Lambda parameter shadowing ===\n# Inner lambda shadows outer variable - outer should not capture it\n\n\ndef make_shadowing_lambda():\n    x = 10\n    # inner lambda has param x, so outer lambda should NOT capture x from make_shadowing_lambda\n    return lambda: (lambda x: x + 1)\n\n\nouter_fn = make_shadowing_lambda()\ninner_fn = outer_fn()\nassert inner_fn(5) == 6, 'inner lambda takes x as param'\n\n\ndef test_inner_lambda_capture():\n    y = 5\n    # outer lambda binds y as param, inner lambda captures from outer lambda, not test_inner_lambda_capture\n    g = lambda y: (lambda: y)\n    return g(7)()\n\n\nassert test_inner_lambda_capture() == 7, 'inner lambda captures outer lambda param'\n",
  'list__eq_self_referential.py':
      "# Two different self-referential lists compared for equality.\n# CPython raises RecursionError; Monty must not panic.\na = [1, 2, 3]\nb = [1, 2, 3]\na.append(a)\nb.append(b)\ntry:\n    a == b\n    assert False, 'should have raised RecursionError'\nexcept RecursionError:\n    pass\n",
  'list__extend_not_iterable.py':
      "# Regression test: list.extend() with a non-iterable should still raise TypeError\n# with the correct message. This verifies that the list_extend opcode helper in\n# collections.rs (for [*expr] literals) and the list.extend() method in\n# types/list.rs are separate code paths that do not interfere with each other.\na = []\na.extend(1)\n# Raise=TypeError(\"'int' object is not iterable\")\n",
  'list__extend_self.py':
      "# list.extend(self) - CPython checks size of input sequence before copying elements,\n# so it can handle the case where the input sequence is the list itself.\n# Monty must not panic when the iterable is the list itself.\nx = [1, 2, 3]\nx.extend(x)\nassert x == [1, 2, 3, 1, 2, 3], 'extend self should duplicate elements'\n",
