      "# === Basic break ===\nresult = []\nfor x in [1, 2, 3, 4, 5]:\n    if x == 3:\n        break\n    result.append(x)\nassert result == [1, 2], 'break exits loop early'\n\n# === Break skips else ===\nflag = 0\nfor x in [1, 2, 3]:\n    if x == 2:\n        break\nelse:\n    flag = 1\nassert flag == 0, 'break skips else clause'\n\n# === No break runs else ===\nflag = 0\nfor x in [1, 2, 3]:\n    pass\nelse:\n    flag = 1\nassert flag == 1, 'completing loop runs else clause'\n\n# === Basic continue ===\nresult = []\nfor x in [1, 2, 3, 4, 5]:\n    if x % 2 == 0:\n        continue\n    result.append(x)\nassert result == [1, 3, 5], 'continue skips iteration'\n\n# === Continue with else ===\nflag = 0\nfor x in [1, 2, 3]:\n    if x == 2:\n        continue\nelse:\n    flag = 1\nassert flag == 1, 'continue does not skip else clause'\n\n# === Nested loops - break inner ===\nresult = []\nfor i in [1, 2, 3]:\n    for j in ['a', 'b', 'c']:\n        if j == 'b':\n            break\n        result.append((i, j))\nassert result == [(1, 'a'), (2, 'a'), (3, 'a')], 'break only affects inner loop'\n\n# === Nested loops - continue inner ===\nresult = []\nfor i in [1, 2]:\n    for j in ['a', 'b', 'c']:\n        if j == 'b':\n            continue\n        result.append((i, j))\nassert result == [(1, 'a'), (1, 'c'), (2, 'a'), (2, 'c')], 'continue only affects inner loop'\n\n# === Break in nested with else on inner ===\nresult = []\nfor i in [1, 2]:\n    for j in [10, 20, 30]:\n        if j == 20:\n            break\n        result.append(j)\n    else:\n        result.append('inner-else')\nassert result == [10, 10], 'break skips inner else'\n\n# === No break in inner runs inner else ===\nresult = []\nfor i in [1, 2]:\n    for j in [10, 20]:\n        result.append(j)\n    else:\n        result.append('inner-else')\nassert result == [10, 20, 'inner-else', 10, 20, 'inner-else'], 'no break runs inner else'\n\n# === Continue does not affect else ===\nresult = []\nfor x in [1, 2, 3]:\n    if x == 2:\n        continue\n    result.append(x)\nelse:\n    result.append('else')\nassert result == [1, 3, 'else'], 'continue does not prevent else'\n\n# === Empty loop with else ===\nflag = 0\nfor x in []:\n    flag = 1\nelse:\n    flag = 2\nassert flag == 2, 'empty loop runs else'\n\n# === Break on first iteration ===\nresult = []\nfor x in [1, 2, 3]:\n    result.append('before')\n    break\n    result.append('after')  # unreachable\nassert result == ['before'], 'break on first iteration'\n\n\n# === Double break (unreachable second break) ===\ndef double_break(value):\n    for i in range(0, 1):\n        break\n        break\n    return value\n\n\nassert double_break('hello') == 'hello', 'double break returns value correctly'\nassert double_break(42) == 42, 'double break works with int'\n\n\n# === Two breaks in different branches (both reachable) ===\ndef two_breaks(items):\n    result = []\n    for x in items:\n        if x < 0:\n            result.append('negative')\n            break\n        if x > 100:\n            result.append('too big')\n            break\n        result.append(x)\n    return result\n\n\nassert two_breaks([1, 2, 3]) == [1, 2, 3], 'no break taken'\nassert two_breaks([1, -1, 3]) == [1, 'negative'], 'first break taken'\nassert two_breaks([1, 200, 3]) == [1, 'too big'], 'second break taken'\nassert two_breaks([-5]) == ['negative'], 'negative on first item'\nassert two_breaks([999]) == ['too big'], 'too big on first item'\n\n\n# === Double continue (unreachable second continue) ===\ndef double_continue(items):\n    out = []\n    for x in items:\n        out.append(x)\n        continue\n        continue\n    return out\n\n\nassert double_continue([1, 2, 3]) == [1, 2, 3], 'double continue keeps normal loop output'\nassert double_continue([]) == [], 'double continue handles empty input'\n\n# === Continue on every iteration ===\nresult = []\nfor x in [1, 2, 3]:\n    result.append(x)\n    continue\n    result.append('after')  # unreachable\nassert result == [1, 2, 3], 'continue on every iteration'\n",
  'loop__break_finally.py':
      "# === Break in try/finally must run finally ===\nresult = []\nfor x in [1, 2, 3]:\n    try:\n        result.append('before')\n        break\n        result.append('after')  # unreachable\n    finally:\n        result.append('finally')\nassert result == ['before', 'finally'], f'break in try/finally should run finally: {result}'\n\n# === Break in nested try/finally runs both finally blocks ===\nresult = []\nfor x in [1, 2, 3]:\n    try:\n        try:\n            result.append('inner-try')\n            break\n        finally:\n            result.append('inner-finally')\n    finally:\n        result.append('outer-finally')\nassert result == ['inner-try', 'inner-finally', 'outer-finally'], f'nested finally blocks: {result}'\n\n# === Break in try/except/finally runs finally ===\nresult = []\nfor x in [1, 2, 3]:\n    try:\n        result.append('try')\n        break\n    except ValueError:\n        result.append('except')\n    finally:\n        result.append('finally')\nassert result == ['try', 'finally'], f'break in try/except/finally: {result}'\n\n# === Break inside except handler with finally ===\nresult = []\nfor x in [1, 2, 3]:\n    try:\n        raise ValueError('test')\n    except ValueError:\n        result.append('except')\n        break\n    finally:\n        result.append('finally')\nassert result == ['except', 'finally'], f'break in except with finally: {result}'\n\n# === Break does not run finally if not in try ===\nresult = []\nfor x in [1, 2, 3]:\n    result.append('body')\n    break\nassert result == ['body'], f'break without finally: {result}'\n\n# === Break with multiple loops and finally ===\nresult = []\nfor i in [1, 2]:\n    try:\n        for j in [10, 20, 30]:\n            if j == 20:\n                break  # This break should not trigger outer finally\n            result.append(j)\n        result.append('after-inner')\n    finally:\n        result.append('outer-finally')\nassert result == [10, 'after-inner', 'outer-finally', 10, 'after-inner', 'outer-finally'], (\n    f'inner break with outer finally: {result}'\n)\n",
