  'method__args_kwargs_unpacking.py':
      "# Tests for method calls with *args unpacking\n\n# === Basic *args unpacking ===\nitems = ['a', 'b', 'c']\nresult = '-'.join(*[items])\nassert result == 'a-b-c', f'join with *args: {result}'\n\nparts = ['hello', 'world']\nresult = ' '.join(*[parts])\nassert result == 'hello world', f'join with *args list: {result}'\n\n# === Empty *args unpacking ===\nresult = '-'.join(*[[]])\nassert result == '', f'join with empty *args: {result}'\n\nempty = []\nresult = '-'.join(*[empty])\nassert result == '', f'join with empty list via *args: {result}'\n\n# === *args with tuple unpacking ===\nvalues = ('x', 'y', 'z')\nresult = '|'.join(*[list(values)])\nassert result == 'x|y|z', f'join with tuple *args: {result}'\n\n# === String methods with *args ===\ns = 'hello world'\nargs = ('o', 'O')\nresult = s.replace(*args)\nassert result == 'hellO wOrld', f'replace with *args: {result}'\n\n# Count with *args\ncount_args = ('l',)\nresult = s.count(*count_args)\nassert result == 3, f'count with *args: {result}'\n\n# === List methods with *args ===\nmy_list = [1, 2, 3]\nappend_args = [4]\nmy_list.append(*append_args)\nassert my_list == [1, 2, 3, 4], f'append with *args: {my_list}'\n\nmy_list = [1, 2, 3]\nextend_args = [[4, 5]]\nmy_list.extend(*extend_args)\nassert my_list == [1, 2, 3, 4, 5], f'extend with *args: {my_list}'\n\nmy_list = [1, 2, 3]\ninsert_args = (1, 'x')\nmy_list.insert(*insert_args)\nassert my_list == [1, 'x', 2, 3], f'insert with *args: {my_list}'\n\n# === Dict methods with *args ===\nd = {'a': 1, 'b': 2}\nget_args = ('a',)\nresult = d.get(*get_args)\nassert result == 1, f'dict.get with *args: {result}'\n\nget_args_default = ('missing', 'default')\nresult = d.get(*get_args_default)\nassert result == 'default', f'dict.get with *args and default: {result}'\n\n# === Mixed positional and *args ===\nmy_list = [1, 2, 3]\nextra_args = ('y',)\nmy_list.insert(0, *extra_args)\nassert my_list == ['y', 1, 2, 3], f'insert with pos and *args: {my_list}'\n\n# === setdefault with *args ===\nd = {'a': 1}\nargs = ('b', 2)\nresult = d.setdefault(*args)\nassert result == 2, f'setdefault with *args: {result}'\nassert d == {'a': 1, 'b': 2}, f'dict after setdefault: {d}'\n\n# === pop with *args ===\nd = {'a': 1, 'b': 2}\npop_args = ('a',)\nresult = d.pop(*pop_args)\nassert result == 1, f'pop with *args: {result}'\nassert d == {'b': 2}, f'dict after pop: {d}'\n\npop_args_default = ('missing', 'default')\nresult = d.pop(*pop_args_default)\nassert result == 'default', f'pop with *args and default: {result}'\n\n# === String split with *args ===\ns = 'a,b,c,d'\nsplit_args = (',',)\nresult = s.split(*split_args)\nassert result == ['a', 'b', 'c', 'd'], f'split with *args: {result}'\n\nsplit_args_maxsplit = (',', 2)\nresult = s.split(*split_args_maxsplit)\nassert result == ['a', 'b', 'c,d'], f'split with *args maxsplit: {result}'\n\n# === String startswith/endswith with *args ===\ns = 'hello'\nstartswith_args = (('hel', 'hey'),)\nresult = s.startswith(*startswith_args)\nassert result == True, f'startswith with *args tuple: {result}'\n\nendswith_args = ('lo',)\nresult = s.endswith(*endswith_args)\nassert result == True, f'endswith with *args: {result}'\n\n# === List index with *args ===\nmy_list = [1, 2, 3, 2, 4]\nindex_args = (2,)\nresult = my_list.index(*index_args)\nassert result == 1, f'index with *args: {result}'\n\nindex_args_start = (2, 2)\nresult = my_list.index(*index_args_start)\nassert result == 3, f'index with *args and start: {result}'\n\n# === String find with *args ===\ns = 'hello hello'\nfind_args = ('hello',)\nresult = s.find(*find_args)\nassert result == 0, f'find with *args: {result}'\n\nfind_args_start = ('hello', 1)\nresult = s.find(*find_args_start)\nassert result == 6, f'find with *args and start: {result}'\n\n# ============================================================\n# **kwargs unpacking tests\n# ============================================================\n\n# === Basic **kwargs unpacking with dict.update ===\nd = {'a': 1}\nopts = {'b': 2, 'c': 3}\nd.update(**opts)\nassert d == {'a': 1, 'b': 2, 'c': 3}, f'update with **kwargs: {d}'\n\n# === Empty **kwargs unpacking ===\nd = {'a': 1}\nempty_opts = {}\nd.update(**empty_opts)\nassert d == {'a': 1}, f'update with empty **kwargs: {d}'\n\n# === **kwargs with string keys ===\nd = {}\nstr_opts = {'key1': 'value1', 'key2': 'value2'}\nd.update(**str_opts)\nassert d == {'key1': 'value1', 'key2': 'value2'}, f'update with string **kwargs: {d}'\n\n# === **kwargs with heap-allocated values ===\nd = {}\nlist_val = [1, 2, 3]\ndict_val = {'nested': True}\nheap_opts = {'list': list_val, 'dict': dict_val}\nd.update(**heap_opts)\nassert d['list'] == [1, 2, 3], f'update with list value: {d}'\nassert d['dict'] == {'nested': True}, f'update with dict value: {d}'\n\n# === Multiple **kwargs updates ===\nd = {'a': 1}\nopts1 = {'b': 2}\nopts2 = {'c': 3}\nd.update(**opts1)\nd.update(**opts2)\nassert d == {'a': 1, 'b': 2, 'c': 3}, f'multiple updates with **kwargs: {d}'\n\n# === **kwargs overwriting existing keys ===\nd = {'a': 1, 'b': 2}\noverride_opts = {'b': 'new', 'c': 3}\nd.update(**override_opts)\nassert d == {'a': 1, 'b': 'new', 'c': 3}, f'update overwriting with **kwargs: {d}'\n\n# === Mixed *args and **kwargs with dict.update ===\n# dict.update can take a dict positionally AND **kwargs\nd = {'a': 1}\npos_update = {'b': 2}\nkw_update = {'c': 3}\nd.update(pos_update, **kw_update)\nassert d == {'a': 1, 'b': 2, 'c': 3}, f'update with pos and **kwargs: {d}'\n\n# === *args tuple unpacking combined with method ===\nd = {'a': 1}\nargs_tuple = ({'x': 10},)\nd.update(*args_tuple)\nassert d == {'a': 1, 'x': 10}, f'update with *args tuple: {d}'\n\n# === Combined *args and **kwargs ===\nd = {}\npos_dict = {'a': 1}\nkw_opts = {'b': 2}\nd.update(*[pos_dict], **kw_opts)\nassert d == {'a': 1, 'b': 2}, f'update with *args and **kwargs: {d}'\n\n# === Regular kwargs combined with **kwargs ===\n# This tests the code path where we have both explicit keyword args and **kwargs unpacking\nd = {}\nextra_opts = {'c': 3}\nd.update(a=1, b=2, **extra_opts)\nassert d == {'a': 1, 'b': 2, 'c': 3}, f'update with regular kwargs and **kwargs: {d}'\n\n# === Regular kwargs only (no **kwargs) with method call ===\nd = {}\nd.update(x=10, y=20)\nassert d == {'x': 10, 'y': 20}, f'update with regular kwargs only: {d}'\n\n# === Mixed positional, regular kwargs, and **kwargs ===\nd = {'existing': 0}\npos_update = {'a': 1}\nextra = {'d': 4}\nd.update(pos_update, b=2, c=3, **extra)\nassert d == {'existing': 0, 'a': 1, 'b': 2, 'c': 3, 'd': 4}, f'update with pos, kwargs, **kwargs: {d}'\n\n# === Empty **kwargs with regular kwargs ===\nd = {}\nempty_extra = {}\nd.update(x=1, **empty_extra)\nassert d == {'x': 1}, f'update with kwargs and empty **kwargs: {d}'\n\n# === **kwargs with different keys from regular kwargs ===\nd = {}\nextra = {'b': 'from_dict'}\nd.update(a='original', **extra)\nassert d == {'a': 'original', 'b': 'from_dict'}, f'update with different kwargs: {d}'\n\n# ============================================================\n# PEP 448 generalized method calls (multiple * or **)\n# ============================================================\n\n# === Multiple **kwargs in method call ===\nd = {}\nd.update(**{'a': 1}, **{'b': 2})\nassert d == {'a': 1, 'b': 2}, f'update with multiple **kwargs: {d}'\n\nd = {'x': 0}\nd.update(**{'a': 1}, **{'b': 2}, **{'c': 3})\nassert d == {'x': 0, 'a': 1, 'b': 2, 'c': 3}, f'update with three **kwargs: {d}'\n\n# Mixed named kwargs and multiple **kwargs\nd = {}\nd.update(a=1, **{'b': 2}, **{'c': 3})\nassert d == {'a': 1, 'b': 2, 'c': 3}, f'update named + multiple **kwargs: {d}'\n\n# === Positional args mixed with *unpack in method GeneralizedCall ===\n# insert(*[0], 1): positional 1 comes AFTER the *unpack → GeneralizedCall.\n# This exercises CallArg::Unpack (the *[0]) and CallArg::Value (the 1)\n# in the compile_method_call GeneralizedCall branch.\nmy_list = [2, 3]\nmy_list.insert(*[0], 1)\nassert my_list == [1, 2, 3], 'insert: star index then positional value'\n\nmy_list2 = ['a', 'b', 'c', 'd']\nmy_list2.insert(*[1], 'x')\nassert my_list2 == ['a', 'x', 'b', 'c', 'd'], 'insert: star index then positional string'\n\n# === *args + multiple **kwargs in method GeneralizedCall ===\n# d.update(*[...], **{...}, **{...}): two **unpacks → GeneralizedCall (not ArgsKargs).\n# The *unpack in args covers CallArg::Unpack; the two **unpacks mean has_kwargs=True,\n# covering the kwargs dict-builder block in the compile_method_call GeneralizedCall branch.\nd = {}\nd.update(*[{}], **{'a': 1}, **{'b': 2})\nassert d == {'a': 1, 'b': 2}, 'update: star args + two star-star kwargs'\n",
  'mount_fs__errors.py':
      "# mount-fs\nimport sys\nfrom pathlib import Path\n\n# root is injected by the test runner:\n# - Monty: Path('/mnt') with OverlayMemory mount over a real temp directory\n# - CPython: Path('<real_tmpdir>') pointing to a real temp directory\n\nis_monty = sys.platform == 'monty'\nis_windows = sys.platform == 'win32'\n\n# ============================================================================\n# FileNotFoundError — read/write/stat/unlink/rmdir on nonexistent paths\n# ============================================================================\n\n# === FileNotFoundError on read_text of nonexistent ===\ntry:\n    (root / 'nonexistent.txt').read_text()\n    assert False, 'expected FileNotFoundError on read_text'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/nonexistent.txt'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === FileNotFoundError on read_bytes of nonexistent ===\ntry:\n    (root / 'nonexistent.bin').read_bytes()\n    assert False, 'expected FileNotFoundError on read_bytes'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/nonexistent.bin'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === FileNotFoundError on unlink of nonexistent ===\ntry:\n    (root / 'nonexistent.txt').unlink()\n    assert False, 'expected FileNotFoundError on unlink'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/nonexistent.txt'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === FileNotFoundError on stat of nonexistent ===\ntry:\n    (root / 'nonexistent.txt').stat()\n    assert False, 'expected FileNotFoundError on stat'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/nonexistent.txt'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === FileNotFoundError on stat of deeply nonexistent ===\ntry:\n    (root / 'nonexistent' / 'child.txt').stat()\n    assert False, 'expected FileNotFoundError on stat'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/nonexistent/child.txt'\", (\n            f'unexpected message: {exc}'\n        )\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === FileNotFoundError on rmdir of nonexistent ===\ntry:\n    (root / 'nonexistent_dir').rmdir()\n    assert False, 'expected FileNotFoundError on rmdir nonexistent'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/nonexistent_dir'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === FileNotFoundError on rename nonexistent ===\ntry:\n    (root / 'nonexistent.txt').rename(root / 'new.txt')\n    assert False, 'expected FileNotFoundError on rename nonexistent'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/nonexistent.txt'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === Error on mkdir without parents when parent missing ===\ntry:\n    (root / 'missing_parent' / 'child').mkdir()\n    assert False, 'expected error on mkdir without parents'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/missing_parent/child'\", (\n            f'unexpected message: {exc}'\n        )\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === FileNotFoundError on write_text with missing parent ===\ntry:\n    (root / 'no_such_parent' / 'child.txt').write_text('should fail')\n    assert False, 'expected FileNotFoundError on write_text with missing parent'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/no_such_parent/child.txt'\", (\n            f'unexpected message: {exc}'\n        )\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === FileNotFoundError on write_bytes with missing parent ===\ntry:\n    (root / 'no_such_parent' / 'child.bin').write_bytes(b'should fail')\n    assert False, 'expected FileNotFoundError on write_bytes with missing parent'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/no_such_parent/child.bin'\", (\n            f'unexpected message: {exc}'\n        )\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# === FileNotFoundError on iterdir of nonexistent ===\ntry:\n    list((root / 'nonexistent').iterdir())\n    assert False, 'expected FileNotFoundError on iterdir nonexistent'\nexcept FileNotFoundError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 2] No such file or directory: '/mnt/nonexistent'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 2] No such file or directory: '\"), f'exc message: {exc}'\n\n# ============================================================================\n# FileExistsError — mkdir on existing\n# ============================================================================\n\n# === FileExistsError on mkdir of existing dir without exist_ok ===\ntry:\n    (root / 'subdir').mkdir()\n    assert False, 'expected FileExistsError on mkdir existing'\nexcept FileExistsError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 17] File exists: '/mnt/subdir'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 17] File exists: '\"), f'exc message: {exc}'\n\n# === FileExistsError on mkdir(parents=True, exist_ok=False) of existing dir ===\ntry:\n    (root / 'subdir').mkdir(parents=True, exist_ok=False)\n    assert False, 'expected FileExistsError on mkdir parents=True exist_ok=False'\nexcept FileExistsError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 17] File exists: '/mnt/subdir'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 17] File exists: '\"), f'exc message: {exc}'\n\n# === FileExistsError on mkdir(exist_ok=True) when path is a file ===\ntry:\n    (root / 'hello.txt').mkdir(exist_ok=True)\n    assert False, 'expected FileExistsError on mkdir exist_ok=True on a file'\nexcept FileExistsError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 17] File exists: '/mnt/hello.txt'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 17] File exists: '\"), f'exc message: {exc}'\n\n# === OSError on rename directory onto non-empty directory ===\n(root / 'rename_src_dir').mkdir()\n(root / 'rename_src_dir' / 'moved.txt').write_text('moved')\n(root / 'rename_dst_dir').mkdir()\n(root / 'rename_dst_dir' / 'existing.txt').write_text('existing')\ntry:\n    (root / 'rename_src_dir').rename(root / 'rename_dst_dir')\n    assert False, 'expected OSError on rename dir onto non-empty dir'\nexcept OSError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 39] Directory not empty: '/mnt/rename_dst_dir'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(('[Errno 66] Directory not empty:', '[Errno 39] Directory not empty:')), (\n            f'exc message: {exc}'\n        )\n\n# Rename onto empty directory should succeed (POSIX only — Windows rejects\n# any rename where the destination already exists, even an empty directory).\nif not is_windows:\n    (root / 'rename_dst_empty').mkdir()\n    (root / 'rename_src_dir').rename(root / 'rename_dst_empty')\n    assert (root / 'rename_dst_empty' / 'moved.txt').read_text() == 'moved', 'rename dir onto empty dir succeeds'\n    assert not (root / 'rename_src_dir').exists(), 'source dir gone after rename'\n\n# ============================================================================\n# IsADirectoryError — read/write/unlink on directories\n# ============================================================================\n\n# === IsADirectoryError on read_text of directory ===\n# CPython on Windows raises PermissionError instead of IsADirectoryError\ntry:\n    (root / 'subdir').read_text()\n    assert False, 'expected IsADirectoryError on read_text of dir'\nexcept (IsADirectoryError, PermissionError) as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 21] Is a directory: '/mnt/subdir'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 21] Is a directory: '\"), f'exc message: {exc}'\n\n# === IsADirectoryError on read_bytes of directory ===\ntry:\n    (root / 'subdir').read_bytes()\n    assert False, 'expected IsADirectoryError on read_bytes of dir'\nexcept (IsADirectoryError, PermissionError) as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 21] Is a directory: '/mnt/subdir'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 21] Is a directory: '\"), f'exc message: {exc}'\n\n# === IsADirectoryError on write_text to directory ===\ntry:\n    (root / 'subdir').write_text('test')\n    assert False, 'expected IsADirectoryError on write_text to dir'\nexcept (IsADirectoryError, PermissionError) as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 21] Is a directory: '/mnt/subdir'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 21] Is a directory: '\"), f'exc message: {exc}'\n\n# === IsADirectoryError on write_bytes to directory ===\ntry:\n    (root / 'subdir').write_bytes(b'test')\n    assert False, 'expected IsADirectoryError on write_bytes to dir'\nexcept (IsADirectoryError, PermissionError) as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 21] Is a directory: '/mnt/subdir'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 21] Is a directory: '\"), f'exc message: {exc}'\n\n# === IsADirectoryError/PermissionError on unlink of directory ===\n# macOS returns PermissionError (EPERM), Linux returns IsADirectoryError (EISDIR)\ntry:\n    (root / 'subdir').unlink()\n    assert False, 'expected error on unlink of dir'\nexcept (IsADirectoryError, PermissionError):\n    pass\n\n# ============================================================================\n# NotADirectoryError — iterdir/rmdir on files\n# ============================================================================\n\n# === NotADirectoryError on iterdir of file ===\ntry:\n    list((root / 'hello.txt').iterdir())\n    assert False, 'expected NotADirectoryError on iterdir of file'\nexcept NotADirectoryError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 20] Not a directory: '/mnt/hello.txt'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 20] Not a directory: '\"), f'exc message: {exc}'\n\n# === NotADirectoryError on rmdir of file ===\ntry:\n    (root / 'hello.txt').rmdir()\n    assert False, 'expected NotADirectoryError on rmdir of file'\nexcept NotADirectoryError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 20] Not a directory: '/mnt/hello.txt'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith(\"[Errno 20] Not a directory: '\"), f'exc message: {exc}'\n\n# ============================================================================\n# DirectoryNotEmpty — rmdir of non-empty directory\n# ============================================================================\n\n# === Error on rmdir of non-empty directory ===\ntry:\n    (root / 'subdir').rmdir()\n    assert False, 'expected error on rmdir non-empty'\nexcept OSError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 39] Directory not empty: '/mnt/subdir'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        # macOS uses errno 66, Linux uses errno 39\n        assert str(exc).startswith(('[Errno 66] Directory not empty:', '[Errno 39] Directory not empty:')), (\n            f'exc message: {exc}'\n        )\n\n# ============================================================================\n# UnicodeDecodeError — read_text of non-UTF-8 file\n# ============================================================================\n\n(root / 'bad_utf8.bin').write_bytes(b'\\x80\\x81\\x82')\ntry:\n    (root / 'bad_utf8.bin').read_text()\n    assert False, 'expected UnicodeDecodeError on read_text of non-UTF-8'\nexcept UnicodeDecodeError as exc:\n    if is_monty:\n        assert str(exc) == \"'utf-8' codec can't decode byte 0x80 in position 0: invalid start byte\", (\n            f'unexpected message: {exc}'\n        )\n    elif not is_windows:\n        assert 'utf-8' in str(exc), f'exc message: {exc}'\n\n# ============================================================================\n# OSError — path length limits\n# ============================================================================\n\n# === OSError on path component too long (> 255 bytes) ===\nlong_name = 'a' * 256\nlong_component_path = Path(str(root) + '/' + long_name)\ntry:\n    long_component_path.write_text('test')\n    assert False, 'expected OSError on long component'\nexcept OSError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 36] File name too long: '/mnt/\" + long_name + \"'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith((\"[Errno 36] File name too long: '\", \"[Errno 63] File name too long: '\")), (\n            f'exc message: {exc}'\n        )\n\n# === Component at exactly 255 bytes is accepted ===\nok_name = 'b' * 255\nassert Path(str(root) + '/' + ok_name).exists() == False, '255-byte component should be accepted'\n\n# === OSError on total path too long (> 4096 bytes) ===\nlong_path_str = str(root) + '/' + '/'.join(['x' * 200] * 21)\ntry:\n    Path(long_path_str).write_text('test')\n    assert False, 'expected OSError on long total path'\nexcept OSError as exc:\n    if is_monty:\n        assert str(exc).startswith(\"[Errno 36] File name too long: '\"), f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith((\"[Errno 36] File name too long: '\", \"[Errno 63] File name too long: '\")), (\n            f'exc message: {exc}'\n        )\n\n# === OSError on long component in read operations too ===\ntry:\n    long_component_path.read_text()\n    assert False, 'expected OSError on read_text with long component'\nexcept OSError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 36] File name too long: '/mnt/\" + long_name + \"'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith((\"[Errno 36] File name too long: '\", \"[Errno 63] File name too long: '\")), (\n            f'exc message: {exc}'\n        )\n\n# === OSError on long component in stat ===\ntry:\n    long_component_path.stat()\n    assert False, 'expected OSError on stat with long component'\nexcept OSError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 36] File name too long: '/mnt/\" + long_name + \"'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith((\"[Errno 36] File name too long: '\", \"[Errno 63] File name too long: '\")), (\n            f'exc message: {exc}'\n        )\n\n# === OSError on long component in mkdir ===\ntry:\n    long_component_path.mkdir()\n    assert False, 'expected OSError on mkdir with long component'\nexcept OSError as exc:\n    if is_monty:\n        assert str(exc) == \"[Errno 36] File name too long: '/mnt/\" + long_name + \"'\", f'unexpected message: {exc}'\n    elif not is_windows:\n        assert str(exc).startswith((\"[Errno 36] File name too long: '\", \"[Errno 63] File name too long: '\")), (\n            f'exc message: {exc}'\n        )\n\n# ============================================================================\n# TypeError — wrong argument types\n# ============================================================================\n\ntry:\n    (root / 'hello.txt').write_text(123)\n    assert False, 'expected TypeError on write_text with int'\nexcept TypeError as exc:\n    assert str(exc) == 'data must be str, not int', f'unexpected message: {exc}'\n\ntry:\n    (root / 'hello.txt').write_text()\n    assert False, 'expected TypeError on write_text with no args'\nexcept TypeError as exc:\n    assert str(exc) == \"Path.write_text() missing 1 required positional argument: 'data'\", f'unexpected message: {exc}'\n\ntry:\n    (root / 'hello.txt').write_bytes(123)\n    assert False, 'expected TypeError on write_bytes with int'\nexcept TypeError as exc:\n    assert str(exc) == \"memoryview: a bytes-like object is required, not 'int'\", f'unexpected message: {exc}'\n\ntry:\n    (root / 'hello.txt').write_bytes()\n    assert False, 'expected TypeError on write_bytes with no args'\nexcept TypeError as exc:\n    assert str(exc) == \"Path.write_bytes() missing 1 required positional argument: 'data'\", f'unexpected message: {exc}'\n",
  'mount_fs__ops.py':
      "# mount-fs\nimport sys\nfrom pathlib import Path\n\n# root is injected by the test runner:\n# - Monty: Path('/mnt') with OverlayMemory mount over a real temp directory\n# - CPython: Path('<real_tmpdir>') pointing to a real temp directory\n\n# === exists() ===\nassert (root / 'hello.txt').exists() == True, 'file exists'\nassert (root / 'subdir').exists() == True, 'dir exists'\nassert (root / 'subdir' / 'deep').exists() == True, 'nested dir exists'\nassert (root / 'nonexistent').exists() == False, 'nonexistent path'\nassert (root / 'nonexistent' / 'file.txt').exists() == False, 'nonexistent nested'\n\n# === is_file() ===\nassert (root / 'hello.txt').is_file() == True, 'is_file on file'\nassert (root / 'subdir').is_file() == False, 'is_file on dir'\nassert (root / 'nonexistent').is_file() == False, 'is_file on nonexistent'\n\n# === is_dir() ===\nassert (root / 'subdir').is_dir() == True, 'is_dir on dir'\nassert (root / 'hello.txt').is_dir() == False, 'is_dir on file'\nassert (root / 'subdir' / 'deep').is_dir() == True, 'is_dir nested'\nassert (root / 'nonexistent').is_dir() == False, 'is_dir on nonexistent'\n\n# === read_text() ===\nassert (root / 'hello.txt').read_text() == 'hello world\\n', 'read_text basic'\nassert (root / 'empty.txt').read_text() == '', 'read_text empty'\nassert (root / 'subdir' / 'nested.txt').read_text() == 'nested content', 'read_text nested'\nassert (root / 'subdir' / 'deep' / 'file.txt').read_text() == 'deep file', 'read_text deep'\n\n# === read_bytes() ===\nassert (root / 'data.bin').read_bytes() == b'\\x00\\x01\\x02\\x03', 'read_bytes binary'\nassert (root / 'empty.txt').read_bytes() == b'', 'read_bytes empty'\nassert (root / 'hello.txt').read_bytes() == b'hello world\\n', 'read_bytes text file'\n\n# === write_text() and read back ===\n(root / 'new_file.txt').write_text('created by test')\nassert (root / 'new_file.txt').read_text() == 'created by test', 'write_text creates file'\n\n# Overwrite existing file\n(root / 'hello.txt').write_text('overwritten')\nassert (root / 'hello.txt').read_text() == 'overwritten', 'write_text overwrites'\n\n# === write_bytes() and read back ===\n(root / 'binary.dat').write_bytes(b'\\xff\\xfe\\xfd')\nassert (root / 'binary.dat').read_bytes() == b'\\xff\\xfe\\xfd', 'write_bytes creates file'\n\n# === stat() ===\nst = (root / 'readonly.txt').stat()\nassert st.st_size == 16, 'stat size (len of \"readonly content\")'\n\n# === iterdir() ===\nentries = sorted([e.name for e in root.iterdir()])\nassert 'hello.txt' in entries, 'iterdir has hello.txt'\nassert 'subdir' in entries, 'iterdir has subdir'\nassert 'data.bin' in entries, 'iterdir has data.bin'\nassert 'empty.txt' in entries, 'iterdir has empty.txt'\n\n# iterdir nested\nnested_entries = sorted([e.name for e in (root / 'subdir').iterdir()])\nassert 'nested.txt' in nested_entries, 'iterdir nested has nested.txt'\nassert 'deep' in nested_entries, 'iterdir nested has deep'\n\n# iterdir entries can be used for further operations\nfor entry in (root / 'subdir').iterdir():\n    if entry.name == 'nested.txt':\n        assert entry.read_text() == 'nested content', 'iterdir entry readable'\n\n# === mkdir() ===\n(root / 'new_dir').mkdir()\nassert (root / 'new_dir').is_dir() == True, 'mkdir creates dir'\n\n# mkdir with parents\n(root / 'a' / 'b' / 'c').mkdir(parents=True)\nassert (root / 'a' / 'b' / 'c').is_dir() == True, 'mkdir parents'\n\n# mkdir with exist_ok on existing directory\n(root / 'new_dir').mkdir(exist_ok=True)\n\n# mkdir(parents=True) on fresh nested path\n(root / 'd' / 'e' / 'f').mkdir(parents=True)\nassert (root / 'd' / 'e' / 'f').is_dir() == True, 'mkdir parents=True creates nested dirs'\n\n# mkdir(parents=True, exist_ok=True) on existing directory\n(root / 'new_dir').mkdir(parents=True, exist_ok=True)\nassert (root / 'new_dir').is_dir() == True, 'mkdir parents=True exist_ok=True on existing dir'\n\n# mkdir(parents=True, exist_ok=True) on existing nested directory\n(root / 'a' / 'b' / 'c').mkdir(parents=True, exist_ok=True)\nassert (root / 'a' / 'b' / 'c').is_dir() == True, 'mkdir parents=True exist_ok=True on existing nested'\n\n# mkdir(parents=True) where some parents already exist\n(root / 'a' / 'b' / 'new_child').mkdir(parents=True)\nassert (root / 'a' / 'b' / 'new_child').is_dir() == True, 'mkdir parents=True with partial existing parents'\n\n# === unlink() ===\n(root / 'to_delete.txt').write_text('delete me')\nassert (root / 'to_delete.txt').exists() == True, 'file before unlink'\n(root / 'to_delete.txt').unlink()\nassert (root / 'to_delete.txt').exists() == False, 'file after unlink'\n\n# === rmdir() ===\n(root / 'empty_dir').mkdir()\nassert (root / 'empty_dir').is_dir() == True, 'dir before rmdir'\n(root / 'empty_dir').rmdir()\nassert (root / 'empty_dir').exists() == False, 'dir after rmdir'\n\n# === rename() ===\n(root / 'old_name.txt').write_text('rename test')\n(root / 'old_name.txt').rename(root / 'new_name.txt')\nassert (root / 'old_name.txt').exists() == False, 'old name gone after rename'\nassert (root / 'new_name.txt').read_text() == 'rename test', 'new name readable'\n\n# === write_text() return value is character count, not byte count ===\nn = (root / 'unicode.txt').write_text('hello')\nassert n == 5, f'write_text ASCII returns char count: {n}'\n\nif sys.platform != 'win32':\n    n = (root / 'unicode.txt').write_text('\\U0001f600')  # single emoji = 1 char, 4 UTF-8 bytes\n    assert n == 1, f'write_text emoji returns char count not byte count: {n}'\n    n = (root / 'unicode.txt').write_text('\\u00e9')  # é = 1 char, 2 UTF-8 bytes\n    assert n == 1, f'write_text accented char returns char count: {n}'\n    n = (root / 'unicode.txt').write_text('\\u4e16\\u754c')  # 世界 = 2 chars, 6 UTF-8 bytes\n    assert n == 2, f'write_text CJK returns char count: {n}'\n\n# === mkdir(parents=True) over deleted parent ===\n(root / 'mkp_test').mkdir()\n(root / 'mkp_test' / 'child.txt').write_text('data')\n(root / 'mkp_test' / 'child.txt').unlink()\n(root / 'mkp_test').rmdir()\nassert not (root / 'mkp_test').exists(), 'deleted dir should not exist'\n# Re-create with parents=True over the tombstoned path\n(root / 'mkp_test' / 'sub' / 'deep').mkdir(parents=True)\nassert (root / 'mkp_test' / 'sub' / 'deep').is_dir(), 'mkdir parents recreates over tombstone'\n\n# === mkdir(parents=True) blocked by real file ===\ntry:\n    (root / 'hello.txt' / 'sub').mkdir(parents=True)\n    assert False, 'expected error when mkdir parents through a file'\nexcept (OSError, NotADirectoryError):\n    pass  # correct — a file blocks mkdir -p\n\n# === resolve() and absolute() ===\np = (root / 'hello.txt').resolve()\nassert p.name == 'hello.txt', 'resolve preserves name'\n\np2 = (root / 'subdir').absolute()\nassert p2.name == 'subdir', 'absolute preserves name'\n\n# === path operations with mounted paths ===\nfull = root / 'subdir' / 'nested.txt'\nassert full.name == 'nested.txt', 'path / .name'\nassert full.suffix == '.txt', 'path / .suffix'\nassert full.stem == 'nested', 'path / .stem'\n",
