  'namedtuple__ops.py':
      "import sys\n\nvi = sys.version_info\n\n# === Equality: same object ===\nassert vi == vi, 'namedtuple equals itself'\n\n# === Equality: two references ===\nvi2 = sys.version_info\nassert vi == vi2, 'two refs to same namedtuple are equal'\n\n# === Equality: namedtuple == equivalent tuple ===\nt = (vi.major, vi.minor, vi.micro, vi.releaselevel, vi.serial)\nassert vi == t, 'namedtuple equals equivalent tuple'\nassert t == vi, 'equivalent tuple equals namedtuple'\n\n# === Inequality: wrong length ===\nassert vi != (3,), 'namedtuple not equal to wrong-length tuple'\nassert (3,) != vi, 'wrong-length tuple not equal to namedtuple'\n\n# === Inequality: different values ===\nassert vi != (0, 0, 0, 'final', 0), 'namedtuple not equal to different values'\n\n# === Inequality: non-tuple types ===\nassert vi != 42, 'namedtuple not equal to int'\nassert vi != 'hello', 'namedtuple not equal to str'\nassert vi != None, 'namedtuple not equal to None'\nassert vi != [3, 14], 'namedtuple not equal to list'\n\n# === repr ===\nr = repr(vi)\nassert r.startswith('sys.version_info(major='), f'namedtuple repr starts with type name, {r!r}'\nassert ', minor=' in r, f'namedtuple repr has minor field, {r!r}'\nassert r.endswith(')'), f'namedtuple repr ends with paren, {r!r}'\n",
  'nonlocal__error_module_level.py':
      "# nonlocal at module level is a syntax error\nnonlocal x  # type: ignore\n# Raise=SyntaxError('nonlocal declaration not allowed at module level')\n",
  'nonlocal__ops.py':
      "# === Basic nonlocal read/write ===\ndef read_outer():\n    x = 10\n\n    def inner():\n        return x  # reads from outer scope\n\n    return inner()\n\n\nassert read_outer() == 10, 'nonlocal read'\n\n\ndef write_outer():\n    x = 10\n\n    def inner():\n        nonlocal x\n        x = 20\n\n    inner()\n    return x\n\n\nassert write_outer() == 20, 'nonlocal write'\n\n\n# === Classic counter pattern ===\ndef make_counter():\n    count = 0\n\n    def increment():\n        nonlocal count\n        count = count + 1\n        return count\n\n    return increment\n\n\ncounter2 = make_counter()\nassert counter2() == 1, 'counter first call'\nassert counter2() == 2, 'counter second call'\nassert counter2() == 3, 'counter third call'\n\n\n# === Implicit capture (read without nonlocal) ===\ndef implicit_capture():\n    a = 10\n    b = 20\n\n    def inner():\n        return a + b  # reads both from outer\n\n    return inner()\n\n\nassert implicit_capture() == 30, 'implicit capture multiple vars'\n\n\n# === Pass-through nesting ===\ndef pass_through():\n    x = 1\n\n    def middle():\n        nonlocal x\n        x = x + 10\n\n        def inner():\n            nonlocal x\n            x = x + 100\n            return x\n\n        r1 = inner()  # returns 111\n        r2 = x  # x is now 111\n        return r1 + r2  # 222\n\n    return middle()\n\n\nassert pass_through() == 222, 'nonlocal pass through'\n\n\n# === Deep nesting (3 levels) ===\ndef deep_nesting():\n    x = 1\n\n    def level2():\n        nonlocal x\n        x = x + 10\n\n        def level3():\n            nonlocal x\n            x = x + 100\n            return x\n\n        return level3()\n\n    return level2()\n\n\nassert deep_nesting() == 111, 'deep nesting'\n\n\n# === Deep nesting (4 levels) ===\ndef deep_pass_through():\n    val = 1\n\n    def level1():\n        nonlocal val\n        val = val + 1\n\n        def level2():\n            nonlocal val\n            val = val + 10\n\n            def level3():\n                nonlocal val\n                val = val + 100\n                return val\n\n            return level3()\n\n        return level2()\n\n    result = level1()  # val: 1 -> 2 -> 12 -> 112\n    return (result, val)\n\n\nassert deep_pass_through() == (112, 112), 'deep pass through 4 levels'\n\n\n# === Multiple independent cells ===\ndef multiple_cells():\n    a = 1\n    b = 10\n    c = 100\n\n    def modify_a():\n        nonlocal a\n        a = a + 1\n        return a\n\n    def modify_b():\n        nonlocal b\n        b = b + 10\n        return b\n\n    def modify_c():\n        nonlocal c\n        c = c + 100\n        return c\n\n    def read_all():\n        return a + b + c\n\n    r1 = modify_b()  # b = 20\n    r2 = modify_a()  # a = 2\n    r3 = modify_c()  # c = 200\n    r4 = read_all()  # 2 + 20 + 200 = 222\n    return (r1, r2, r3, r4)\n\n\nassert multiple_cells() == (20, 2, 200, 222), 'multiple independent cells'\n\n\n# === Shared cell (getter/setter pattern) ===\ndef shared_cell():\n    x = 0\n\n    def getter():\n        return x\n\n    def setter(v):\n        nonlocal x\n        x = v\n\n    return (getter, setter)\n\n\npair = shared_cell()\ngetter = pair[0]\nsetter = pair[1]\nassert getter() == 0, 'shared cell initial'\nsetter(42)\nassert getter() == 42, 'shared cell after setter'\n\n\n# === Shared multiple vars ===\ndef shared_multiple_vars():\n    x = 0\n    y = 0\n\n    def add_to_x(n):\n        nonlocal x\n        x = x + n\n        return x\n\n    def add_to_y(n):\n        nonlocal y\n        y = y + n\n        return y\n\n    def swap():\n        nonlocal x, y\n        tmp = x\n        x = y\n        y = tmp\n        return (x, y)\n\n    def get_both():\n        return (x, y)\n\n    return (add_to_x, add_to_y, swap, get_both)\n\n\nops = shared_multiple_vars()\nadd_x = ops[0]\nadd_y = ops[1]\nswap = ops[2]\nget = ops[3]\nadd_x(5)  # x=5\nadd_y(10)  # y=10\nadd_x(3)  # x=8\nswap()  # x=10, y=8\nassert get() == (10, 8), 'shared multiple vars with swap'\n\n\n# === Local and captured ===\ndef local_and_captured():\n    x = 1\n\n    def inner():\n        nonlocal x\n        x = x + x\n        return x\n\n    before = x  # 1\n    middle = inner()  # 2\n    after = x  # 2\n    final = inner()  # 4\n    return (before, middle, after, final, x)\n\n\nassert local_and_captured() == (1, 2, 2, 4, 4), 'local and captured'\n\n\n# === Mixing global and nonlocal ===\ng1 = 100\n\n\ndef global_and_nonlocal():\n    x = 1\n\n    def inner():\n        global g1\n        nonlocal x\n        g1 = g1 + 1\n        x = x + 10\n        return g1 + x\n\n    return inner()\n\n\nassert global_and_nonlocal() == 112, 'global and nonlocal together'\n\n\n# === Closure with global and nonlocal ===\ng2 = 1000\n\n\ndef make_closure_global():\n    x = 1\n\n    def closure():\n        global g2\n        nonlocal x\n        result = g2 + x\n        g2 = g2 + 1\n        x = x + 10\n        return result\n\n    return closure\n\n\nc = make_closure_global()\nr1 = c()  # returns 1001\nr2 = c()  # returns 1012\nr3 = c()  # returns 1023\nassert (r1, r2, r3, g2) == (1001, 1012, 1023, 1003), 'closure with global and nonlocal'\n\n\n# === Closure creates closure ===\ndef outer_factory():\n    outer_val = 10\n\n    def inner_factory():\n        nonlocal outer_val\n        inner_val = outer_val\n\n        def innermost():\n            nonlocal inner_val\n            inner_val = inner_val + 1\n            return inner_val\n\n        outer_val = outer_val + 100\n        return innermost\n\n    return inner_factory\n\n\nfactory = outer_factory()\nclosure1 = factory()  # inner_val=10, outer_val->110\nclosure2 = factory()  # inner_val=110, outer_val->210\nr1 = closure1()  # 11\nr2 = closure1()  # 12\nr3 = closure2()  # 111\nr4 = closure1()  # 13\nassert (r1, r2, r3, r4) == (11, 12, 111, 13), 'closure creates closure'\n\n\n# === Augmented assignment with nonlocal ===\ndef augmented_assign():\n    x = 10\n\n    def inner():\n        nonlocal x\n        x += 5\n\n    inner()\n    return x\n\n\nassert augmented_assign() == 15, 'augmented assign nonlocal'\n\n\n# === Cell contains closure ===\ndef cell_contains_closure():\n    y = 100\n\n    def inner():\n        return y\n\n    x = inner  # x holds closure, x is also a cell var\n\n    def get_x():\n        nonlocal x\n        return x\n\n    f = get_x()\n    return f()\n\n\nassert cell_contains_closure() == 100, 'cell contains closure'\n",
  'os__environ.py':
      "# call-external\n# Tests for os.environ property\n\nimport os\n\n# === os.environ property ===\n# os.environ returns a dict-like object\nenv = os.environ\n\n# === os.environ key access ===\nassert env['VIRTUAL_HOME'] == '/virtual/home', 'environ key access VIRTUAL_HOME'\nassert os.environ['VIRTUAL_HOME'] == '/virtual/home', 'environ key access VIRTUAL_HOME'\nassert os.environ['VIRTUAL_USER'] == 'testuser', 'environ key access VIRTUAL_USER'\nassert os.environ['VIRTUAL_EMPTY'] == '', 'environ key access VIRTUAL_EMPTY'\n\n# === os.environ get method ===\nassert env.get('VIRTUAL_HOME') == '/virtual/home', 'environ.get existing key'\nassert os.environ.get('VIRTUAL_HOME') == '/virtual/home', 'environ.get existing key'\nassert os.environ.get('VIRTUAL_USER') == 'testuser', 'environ.get existing user'\nassert os.environ.get('NONEXISTENT_VAR_12345') is None, 'environ.get missing returns None'\nassert os.environ.get('NONEXISTENT_VAR_12345', 'default') == 'default', 'environ.get with default'\n\n# === os.environ length ===\nassert len(env) == 3, 'environ has 3 virtual entries'\n\n# === os.environ membership test ===\nassert 'VIRTUAL_HOME' in env, 'VIRTUAL_HOME in environ'\nassert 'VIRTUAL_HOME' in os.environ, 'VIRTUAL_HOME in environ'\nassert 'VIRTUAL_USER' in env, 'VIRTUAL_USER in environ'\nassert 'NONEXISTENT_VAR_12345' not in env, 'nonexistent not in environ'\nassert 'NONEXISTENT_VAR_12345' not in os.environ, 'nonexistent not in environ'\n\n# === os.environ keys/values/items ===\nkeys = list(os.environ.keys())\nassert 'VIRTUAL_HOME' in keys, 'VIRTUAL_HOME in keys'\nassert 'VIRTUAL_USER' in keys, 'VIRTUAL_USER in keys'\n\nvalues = list(os.environ.values())\nassert '/virtual/home' in values, '/virtual/home in values'\nassert 'testuser' in values, 'testuser in values'\n",
