  'typing__types.py':
      "# Tests for typing module type() behavior\n#\n# CPython's typing module uses various internal types for different constructs.\n# Monty simplifies this by using typing._SpecialForm for all typing markers.\n# Where CPython also uses _SpecialForm, we use == for exact match.\n# Where CPython uses different internal types, we accept both representations.\n\nimport typing\n\n# === Types that match between CPython and Monty ===\nassert repr(type(typing.Optional)) == \"<class 'typing._SpecialForm'>\", 'type(Optional)'\nassert repr(type(typing.ClassVar)) == \"<class 'typing._SpecialForm'>\", 'type(ClassVar)'\nassert repr(type(typing.Final)) == \"<class 'typing._SpecialForm'>\", 'type(Final)'\nassert repr(type(typing.Union)) == \"<class 'type'>\", 'type(Union)'\n\n# === Types that differ between CPython and Monty ===\n# CPython uses specialized internal types; Monty uses _SpecialForm for all\nassert repr(type(typing.Any)) in (\"<class 'typing._SpecialForm'>\", \"<class 'typing._AnyMeta'>\"), 'type(Any)'\nassert repr(type(typing.Callable)) in (\"<class 'typing._SpecialForm'>\", \"<class 'typing._CallableType'>\"), (\n    'type(Callable)'\n)\n\n# === Verify TYPE_CHECKING is False ===\nassert typing.TYPE_CHECKING is False, 'TYPE_CHECKING should be False at runtime'\n",
  'unpack__nested.py':
      "# Test nested tuple unpacking\n\n# === Basic nested unpacking ===\ndata = ((1, 2), 'x')\n(a, b), c = data\nassert a == 1, 'nested unpack first inner'\nassert b == 2, 'nested unpack second inner'\nassert c == 'x', 'nested unpack outer'\n\n# === Deeply nested ===\n((a, b), (c, d)) = ((1, 2), (3, 4))\nassert a == 1, 'deep nested first'\nassert b == 2, 'deep nested second'\nassert c == 3, 'deep nested third'\nassert d == 4, 'deep nested fourth'\n\n# === Mixed depths ===\n(a, (b, c)) = (1, (2, 3))\nassert a == 1, 'mixed depth outer'\nassert b == 2, 'mixed depth inner first'\nassert c == 3, 'mixed depth inner second'\n\n# === Three levels deep ===\n(a, (b, (c, d))) = (1, (2, (3, 4)))\nassert a == 1, 'three level outer'\nassert b == 2, 'three level mid'\nassert c == 3, 'three level inner first'\nassert d == 4, 'three level inner second'\n\n# === In for loops ===\nitems = [((1, 2), 'a'), ((3, 4), 'b')]\nsums = []\nletters = []\nfor (a, b), c in items:\n    sums.append(a + b)\n    letters.append(c)\nassert sums == [3, 7], 'for loop nested unpack sums'\nassert letters == ['a', 'b'], 'for loop nested unpack letters'\n\n# === In comprehensions ===\nitems = [((1, 2), 'a'), ((3, 4), 'b')]\nresult = [a + b for (a, b), c in items]\nassert result == [3, 7], 'comprehension nested unpack'\n\n# === Deep nested in comprehension ===\nitems = [((1, 2), (3, 4)), ((5, 6), (7, 8))]\nresult = [a + b + c + d for (a, b), (c, d) in items]\nassert result == [10, 26], 'comprehension deep nested unpack'\n",
